def average_density_matrices(measurements: List[str]) -> Optional[str]:
    """Average multiple 16³ density matrices (hex encoded) into consensus state."""
    try:
        import numpy as _np_avg

        if not measurements or not all(measurements):
            return None

        matrices = []
        for dm_hex in measurements:
            if not dm_hex:
                continue
            # Accept both 16³ (32,768 bytes = 65,536 hex) and 64³ (2,097,152 bytes = 4,194,304 hex)
            hex_len = len(dm_hex)
            if hex_len < 65536:  # Too small even for 16³
                continue
            try:
                dm_bytes = bytes.fromhex(dm_hex)
                dm_array = _np_avg.frombuffer(
                    dm_bytes, dtype=_np_avg.complex64
                ).reshape((16, 16, 16))
                matrices.append(dm_array)
            except Exception:
                continue

        if not matrices:
            return None

        # Average: mean_dm = (1/N) * sum(dm_i)
        avg_dm = _np_avg.zeros((16, 16, 16), dtype=_np_avg.complex64)
        for dm in matrices:
            avg_dm += dm
        avg_dm = avg_dm / len(matrices)

        # Normalize: trace = 1
        trace = _np_avg.sum(_np_avg.abs(avg_dm) ** 2)
        if trace > 1e-12:
            avg_dm = avg_dm / _np_avg.sqrt(trace)

        return _np_avg.asarray(avg_dm, dtype=_np_avg.complex64).tobytes().hex()
    except Exception as e:
        _EXP_LOG.debug(f"[PEER-DM] Average failed: {e}")
    return None


def discover_and_average_peer_measurements(
    db,
    block_height: int,
    server_dm_hex: str,
    local_dm_hex: str = None,
    timeout_per_peer: float = 2.0,
) -> Optional[str]:
    """
    Discover known peers, fetch their measurements, average with server/local DM to create consensus.

    Returns averaged consensus DM hex, or None if averaging fails.
    """
    try:
        _EXP_LOG.debug(f"[CONSENSUS] Starting peer discovery for block {block_height}")

        # Collect all measurements: server + local + peers
        measurements = []
        if server_dm_hex:
            measurements.append(server_dm_hex)
        if local_dm_hex:
            measurements.append(local_dm_hex)

        # Discover active peers from database
        try:
            peers = db.get_active_p2p_peers(max_age_s=300)  # Last 5 minutes
            _EXP_LOG.debug(f"[CONSENSUS] Discovered {len(peers)} active peers")
        except Exception:
            peers = []

        # Fetch measurements from each peer
        peer_count = 0
        for peer in peers[:8]:  # Limit to 8 peers to avoid network bloat
            try:
                peer_host = peer.get("host") or peer.get("address")
                peer_port = peer.get("port") or 9091
                if not peer_host:
                    continue

                peer_dm = fetch_peer_measurement(
                    peer_host, peer_port, timeout_s=timeout_per_peer
                )
                if peer_dm:
                    measurements.append(peer_dm)
                    peer_count += 1
                    _EXP_LOG.debug(
                        f"[CONSENSUS] ✅ Fetched measurement from {peer_host}:{peer_port}"
                    )
                    # Store peer measurement in database
                    try:
                        db.store_dm_measurement(
                            block_height,
                            f"peer:{peer_host}:{peer_port}",
                            peer_dm,
                            {"timestamp": time.time()},
                        )
                    except Exception:
                        pass
            except Exception as _peer_e:
                _EXP_LOG.debug(f"[CONSENSUS] Peer measurement fetch failed: {_peer_e}")
                continue

        _EXP_LOG.info(
            f"[CONSENSUS] 📊 Collected measurements: 1 server + {1 if local_dm_hex else 0} local + {peer_count} peers = {len(measurements)} total"
        )

        if len(measurements) < 2:
            _EXP_LOG.warning(
                f"[CONSENSUS] ⚠️  Insufficient measurements ({len(measurements)}) for consensus"
            )
            return None

        # Average all measurements
        avg_dm = average_density_matrices(measurements)
        if avg_dm:
            _EXP_LOG.info(
                f"[CONSENSUS] ✅ Quantum consensus achieved: {len(measurements)} measurements averaged"
            )
            return avg_dm
        else:
            _EXP_LOG.warning(
                f"[CONSENSUS] ❌ Averaging failed for {len(measurements)} measurements"
            )
            return None

    except Exception as e:
        _EXP_LOG.debug(f"[CONSENSUS] Peer discovery/averaging failed: {e}")
        return None


class HyperbolicEntropyPool:
    """
    Client-side quantum entropy pipeline.
    Source priority:
      1. XOR of up to 3 QRNG APIs  (if QRNG_API_KEY_1/2/3 are set)
      2. Server /api/entropy/stream (already hyperbolic-processed once server-side)
      3. os.urandom(32)             — liveness hedge, always mixed in
    Final step: C qtcl_hyp_entropy_mul() applies the {8,3} Möbius walk (depth=64).
    os.urandom(8) is hashed in alongside every call so that a fully-compromised
    QRNG cannot eliminate local entropy.
    """

    _QRNG_SPECS: dict = {
        1: {  # random.org — same key as RANDOM_ORG_KEY in qrng_ensemble.py
            "url": "https://api.random.org/json-rpc/4/invoke",
            "parse": lambda r: base64.b64decode(
                r.get("result", {}).get("random", {}).get("data", [""])[0]
            ),
        },
        2: {  # ANU quantum vacuum — same key as ANU_API_KEY in qrng_ensemble.py
            "url": "https://api.quantumnumbers.anu.edu.au",
            "parse": lambda r: bytes.fromhex("".join(r.get("data", [])[:8])),
        },
        3: {  # QBICK / ID Quantique — same key as QRNG_API_KEY in qrng_ensemble.py
            "url": "https://qrng.qbck.io/{key}/qbck/block/hex",
            "parse": lambda r: bytes.fromhex(
                (r.get("result") or r.get("data", ""))[:64]
            ),
        },
    }

    def __init__(self) -> None:
        self._lock = threading.Lock()
        self._cache: Optional[bytes] = None
        self._cache_ts: float = 0.0
        self._ttl: float = 20.0

    # ── QRNG fetchers ─────────────────────────────────────────────────────────
    def _fetch_random_org(self, key: str) -> Optional[bytes]:
        try:
            body = json.dumps(
                {
                    "jsonrpc": "2.0",
                    "method": "generateBytes",
                    "params": {"apiKey": key, "n": 32, "format": "base64"},
                    "id": 1,
                }
            ).encode()
            req = Request(
                "https://api.random.org/json-rpc/4/invoke", data=body, method="POST"
            )
            req.add_header("Content-Type", "application/json")
            req.add_header("User-Agent", "QTCL-Client/3.0")
            with urlopen(req, timeout=6) as resp:
                return self._QRNG_SPECS[1]["parse"](json.loads(resp.read()))[:32]
        except Exception as e:
            logger.debug(f"[HypEnt] random.org: {e}")
            return None

    def _fetch_anu(self, key: str) -> Optional[bytes]:
        try:
            ep = f"https://api.quantumnumbers.anu.edu.au?{urlencode({'length': 32, 'type': 'hex16'})}"
            req = Request(ep, method="GET")
            req.add_header("x-api-key", key)
            req.add_header("User-Agent", "QTCL-Client/3.0")
            with urlopen(req, timeout=6) as resp:
                return self._QRNG_SPECS[2]["parse"](json.loads(resp.read()))[:32]
        except Exception as e:
            logger.debug(f"[HypEnt] ANU QRNG: {e}")
            return None

    def _fetch_qbick(self, key: str) -> Optional[bytes]:
        try:
            url = self._QRNG_SPECS[3]["url"].format(key=key)
            req = Request(url, method="GET")
            req.add_header("User-Agent", "QTCL-Client/3.0")
            with urlopen(req, timeout=6) as resp:
                return self._QRNG_SPECS[3]["parse"](json.loads(resp.read()))[:32]
        except Exception as e:
            logger.debug(f"[HypEnt] QBICK: {e}")
            return None

    def _fetch_server(self, height: int = 0, pq_curr: str = "") -> Optional[bytes]:
        """Fetch entropy from server via RPC (not streaming)."""
        try:
            from urllib.parse import urlencode

            params_json = json.dumps([])
            query = urlencode(
                {"method": "qtcl_getEntropy", "params": params_json, "id": 1}
            )
            full_url = f"{ENTROPY_SERVER_URL}/rpc?{query}"
            req = Request(full_url)
            req.add_header("User-Agent", "QTCL-Client/3.0")
            if ENTROPY_API_KEY:
                req.add_header("X-Entropy-Key", ENTROPY_API_KEY)
            with urlopen(req, timeout=5) as resp:
                result = json.loads(resp.read())
                if "result" in result and isinstance(result["result"], str):
                    return bytes.fromhex(result["result"])[:32]
                return None
        except Exception as e:
            logger.debug(f"[HypEnt] Server RPC entropy: {e}")
            return None

    # ── C-accelerated combiners ────────────────────────────────────────────────
    def _xor3(
        self, s1: Optional[bytes], s2: Optional[bytes], s3: Optional[bytes]
    ) -> bytes:

        import hashlib as _hl

        xored = bytearray(32)
        for src in (s1, s2, s3):
            if src:
                for i, b in enumerate((src + b"\x00" * 32)[:32]):
                    xored[i] ^= b
        h = _hl.sha3_256()
        h.update(b"QTCL_XOR3_POOL_v1:")
        h.update(bytes(xored))
        return h.digest()

    def _hyp_mix(self, raw: bytes, depth: int = 64) -> bytes:
        seed = (raw + os.urandom(8))[:32]  # 8-byte local liveness hedge

        import hashlib as _hl

        h = _hl.shake_256()
        h.update(b"QTCL_HYP_ENT_v1:")
        h.update(seed)
        return h.digest(32)

    # ── Public API ─────────────────────────────────────────────────────────────
    def _acquire(self, height: int, pq_curr: str) -> bytes:
        s1 = self._fetch_random_org(QRNG_API_KEY_1) if QRNG_API_KEY_1 else None
        s2 = self._fetch_anu(QRNG_API_KEY_2) if QRNG_API_KEY_2 else None
        s3 = self._fetch_qbick(QRNG_API_KEY_3) if QRNG_API_KEY_3 else None
        if any(x is not None for x in (s1, s2, s3)):
            names = " + ".join(
                n for n, x in [("random.org", s1), ("ANU", s2), ("QBICK", s3)] if x
            )
            logger.debug(f"[HypEnt] QRNG pool: {names}")
            return self._xor3(s1, s2, s3)
        srv = self._fetch_server(height=height, pq_curr=pq_curr)
        if srv:
            logger.debug("[HypEnt] source: server (pass-1 hyperbolic already applied)")
            return srv
        logger.debug("[HypEnt] source: os.urandom")
        return os.urandom(32)

    def get(self, size: int = 32, height: int = 0, pq_curr: str = "") -> bytes:
        """Return hyperbolic-mixed entropy bytes. Cached; safe to call per-nonce."""
        with self._lock:
            now = time.time()
            if self._cache and (now - self._cache_ts) < self._ttl:
                raw = self._cache
            else:
                raw = self._acquire(height, pq_curr)
                self._cache = raw
                self._cache_ts = now
        out32 = self._hyp_mix(raw)
        if size <= 32:
            return out32[:size]
        import hashlib as _hl

        h = _hl.shake_256()
        h.update(b"QTCL_HYP_EXPAND:")
        h.update(out32)
        return h.digest(size)


_ENTROPY_POOL: Optional[HyperbolicEntropyPool] = None
_ENTROPY_POOL_LOCK = threading.Lock()


def _get_pool() -> HyperbolicEntropyPool:
    global _ENTROPY_POOL
    if _ENTROPY_POOL is None:
        with _ENTROPY_POOL_LOCK:
            if _ENTROPY_POOL is None:
                _ENTROPY_POOL = HyperbolicEntropyPool()
    return _ENTROPY_POOL


def get_mining_entropy(size: int = 32) -> bytes:
    """Mining entropy — two-pass hyperbolic quantum pool, never blocks."""
    return _get_pool().get(size=size)


def get_system_entropy(height: int = 0, pq_curr: str = "") -> bytes:
    """System entropy for HypΓ keygen / mnemonics — same pool, height-aware."""
    with ENTROPY_LOCK:
        now = time.time()
        if (
            SYSTEM_ENTROPY_CACHE["data"]
            and (now - SYSTEM_ENTROPY_CACHE["timestamp"])
            < SYSTEM_ENTROPY_CACHE["ttl_seconds"]
        ):
            return SYSTEM_ENTROPY_CACHE["data"]
        result = _get_pool().get(size=32, height=height, pq_curr=pq_curr)
        SYSTEM_ENTROPY_CACHE["data"] = result
        SYSTEM_ENTROPY_CACHE["timestamp"] = now
        return result


_qrng_active = (
    " + ".join(
        n
        for n, k in [
            ("random.org", QRNG_API_KEY_1),
            ("ANU", QRNG_API_KEY_2),
            ("QBICK", QRNG_API_KEY_3),
        ]
        if k
    )
    or "none"
)
logger.info(
    f"[HypEnt] Pipeline: QRNG[{_qrng_active}] "
    f"→ XOR₃ → {{8,3}} Möbius(d=64) "
    f"→ server({ENTROPY_SERVER_URL}) → os.urandom hedge"
)


def init_p2p_bootstrap() -> None:
    """Initialize P2P peer discovery from hardcoded seed nodes (no localhost)."""
    import sqlite3 as _sq3
    from pathlib import Path as _P

    # Use the canonical DB path detected at module load — NOT a hardcoded fallback
    db_file = _P(_DB_PATH)
    if not db_file.exists():
        return

    try:
        conn = _sq3.connect(str(db_file), timeout=2.0)
        cur = conn.cursor()

        cur.execute("""CREATE TABLE IF NOT EXISTS known_peers(
            host TEXT, port INTEGER, last_seen TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            PRIMARY KEY(host, port))""")

        try:
            _cols = {
                r[1] for r in cur.execute("PRAGMA table_info(known_peers)").fetchall()
            }
            for _col, _defn in [
                ("mac_address", "TEXT DEFAULT ''"),
                ("device_id", "TEXT DEFAULT ''"),
            ]:
                if _col not in _cols:
                    cur.execute(f"ALTER TABLE known_peers ADD COLUMN {_col} {_defn}")
        except Exception:
            pass

        for (host, port), seed_info in P2P_HARDCODED_SEEDS.items():
            try:
                cur.execute(
                    "INSERT OR REPLACE INTO known_peers(host,port) VALUES(?,?)",
                    (host.split(":")[0], int(port)),
                )
            except Exception as e:
                logger.debug(f"[P2P] Seed insert {host}:{port}: {e}")

        # Seed live peers pulled from server during _bootstrap_client_env()
        # These are real active miners registered with Koyeb — far more useful
        # than the hardcoded seed hostnames which just point to the Koyeb app.
        import json as _bj

        _live_peers_json = os.environ.get("QTCL_BOOTSTRAP_PEERS_JSON", "")
        _live_seeded = 0
        if _live_peers_json:
            try:
                _live_peers = _bj.loads(_live_peers_json)
                for _p in _live_peers:
                    _ea = str(_p.get("external_addr") or "")
                    if ":" in _ea:
                        _h, _port_s = _ea.rsplit(":", 1)
                        try:
                            _port_i = int(_port_s)
                        except ValueError:
                            continue
                    else:
                        _h = _ea
                        _port_i = 9091
                    _h = _h.strip()
                    if not _h or _h in ("", "localhost", "127.0.0.1"):
                        continue
                    try:
                        cur.execute(
                            "INSERT OR REPLACE INTO known_peers(host,port) VALUES(?,?)",
                            (_h, _port_i),
                        )
                        _live_seeded += 1
                    except Exception:
                        pass
            except Exception as _je:
                logger.debug(f"[P2P] live peer seed parse: {_je}")

        conn.commit()
        conn.close()
        _total = len(P2P_HARDCODED_SEEDS) + _live_seeded
        logger.info(
            f"[P2P] Bootstrap complete: {_total} peers to DB "
            f"({len(P2P_HARDCODED_SEEDS)} seeds + {_live_seeded} live from server)"
        )
    except Exception as e:
        logger.debug(f"[P2P] Bootstrap DB init failed (non-fatal): {e}")


