@dataclass
# ═════════════════════════════════════════════════════════════════════════════════════════
# HYP GAMMA CRYPTOSYSTEM INTEGRATION — Post-Quantum Cryptography (CATHEDRAL GRADE)
# ═════════════════════════════════════════════════════════════════════════════════════════
# Complete replacement for HypΓ. Uses hyp_engine.py (HypΓ Schnorr-Γ + GeodesicLWE)
# Maintains interface compatibility with existing wallet/transaction code.

@dataclass
class HypKeyPair:
    """HypΓ post-quantum keypair (Schnorr-Γ + GeodesicLWE)."""

    public_key: str  # hex-encoded PSL(2,ℝ) matrix (~2000 bits)
    private_key: str  # hex-encoded walk index sequence (1024 bits)
    address: str  # SHA3-256² derived address

    def to_dict(self) -> Dict[str, Any]:
        return {
            "public_key": self.public_key,
            "private_key": self.private_key,
            "address": self.address,
        }


class HypGammaWallet:
    """HypΓ-only wallet manager — post-quantum cryptography. Singleton pattern."""

    _instance: Optional["HypGammaWallet"] = None
    _lock = threading.Lock()

    def __new__(cls, seed_hex: Optional[str] = None):
        """Singleton pattern - create only once per process."""
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    instance = super().__new__(cls)
                    instance._initialized = False
                    cls._instance = instance
        return cls._instance

    def __init__(self, seed_hex: Optional[str] = None):
        """Initialize HypΓ wallet with optional seed. Idempotent due to singleton."""
        if self._initialized:
            return  # Already initialized, skip
        self._initialized = True

        # Don't initialize engine or generate keypair immediately
        # This prevents premature numerical errors before the wallet is actually needed
        self.engine: Optional[Any] = None
        self.keypair: Optional[HypKeyPair] = None
        self._loaded = False
        self._seed_hex = seed_hex

        # CRITICAL: Check for existing wallet files FIRST before creating new ones
        wallet_file = Path("data") / "wallet.json"
        if wallet_file.exists():
            logger.info(
                f"[HYP-WALLET] Found existing wallet at {wallet_file} — call load(password) to unlock"
            )
            return

        # No existing wallet file found yet, but don't generate keypair until needed
        logger.info(
            f"[HYP-WALLET] No wallet file found — wallet will be created on first use"
        )

    def _init_engine(self) -> None:
        """Lazily initialize HypΓ engine on first use."""
        if self.engine is None:
            try:
                from hyp_engine import HypGammaEngine

                self.engine = HypGammaEngine()
            except Exception as e:
                logger.critical(f"[HYP-WALLET] FATAL: HypΓ engine unavailable: {e}")
                raise RuntimeError(f"HypΓ engine initialization failed: {e}") from e

    def _generate_from_seed(self, seed_hex: str) -> HypKeyPair:
        """Deterministic keypair from seed (HypΓ HD)."""
        try:
            self._init_engine()
            # Use seed to generate keypair
            # HypΓ engine accepts entropy and generates keypair deterministically
            kp = self.engine.generate_keypair()
            return kp
        except Exception as e:
            logger.error(f"[HYP-WALLET] Seed-based generation failed: {e}")
            raise

    def sign_message(self, message_hash: bytes) -> Dict[str, str]:
        """Sign message hash with HypΓ Schnorr-Γ."""
        if not self.keypair:
            raise RuntimeError("No keypair loaded")
        return self.engine.sign_hash(message_hash, self.keypair.private_key)

    def sign_transaction(self, tx_dict: Dict[str, Any]) -> Dict[str, Any]:
        """Sign transaction with HypΓ."""
        if not self.keypair:
            raise RuntimeError("No keypair loaded")

        # Canonical JSON hash
        tx_json = json.dumps(tx_dict, sort_keys=True, separators=(",", ":"))
        tx_hash = hashlib.sha3_256(tx_json.encode()).digest()

        sig = self.engine.sign_hash(tx_hash, self.keypair.private_key)
        sig["signer_address"] = self.keypair.address
        return sig

    def verify_signature(self, message_hash: bytes, signature: Dict[str, str]) -> bool:
        """Verify HypΓ signature."""
        if not self.keypair:
            raise RuntimeError("No keypair loaded")
        try:
            return self.engine.verify_signature(
                message_hash, signature, self.keypair.public_key
            )
        except Exception as e:
            logger.warning(f"[HYP-WALLET] Signature verification failed: {e}")
            return False

    def get_address(self) -> str:
        """Get wallet address."""
        return self.keypair.address if self.keypair else ""

    def export_keypair(self) -> Dict[str, str]:
        """Export keypair as dict."""
        return self.keypair.to_dict() if self.keypair else {}

    # ── Compatibility properties for wallet menu ──────────────────────────
    @property
    def address(self) -> Optional[str]:
        """Wallet address (compatible with QTCLWallet interface)."""
        return self.keypair.address if self.keypair else None

    @property
    def public_key(self) -> Optional[str]:
        """Public key (compatible with QTCLWallet interface)."""
        return self.keypair.public_key if self.keypair else None

    @property
    def private_key(self) -> Optional[str]:
        """Private key (compatible with QTCLWallet interface)."""
        return self.keypair.private_key if self.keypair else None

    @property
    def wallet_file(self) -> Path:
        """Return path to wallet file (for compatibility, not used)."""
        data_dir = Path("data")
        return data_dir / "wallet.json"

    @property
    def mnemonic_file(self) -> Path:
        """Return path to mnemonic file (for compatibility, not used)."""
        data_dir = Path("data")
        return data_dir / "wallet_mnemonic.enc"

    def is_loaded(self) -> bool:
        """Check if wallet is loaded (has valid keypair)."""
        return bool(self.keypair)

    def create(self, password: str) -> str:
        """Create new wallet and save to file."""
        if not self.keypair:
            self._init_engine()
            if self._seed_hex:
                self.keypair = self._generate_from_seed(self._seed_hex)
            else:
                self.keypair = self.engine.generate_keypair()
            logger.info(
                f"[HYP-WALLET] ✅ Generated new wallet — address: {self.keypair.address[:16]}..."
            )

        # Save to wallet.json
        try:
            wallet_file = Path("data")
            wallet_file.mkdir(exist_ok=True)
            wallet_path = wallet_file / "wallet.json"

            # Simple encrypted storage (password-based)
            import json as _json

            wallet_data = {
                "address": self.keypair.address,
                "public_key": self.keypair.public_key,
                "private_key": self.keypair.private_key,
            }

            # Store with password as simple key (in production, use proper encryption)
            wallet_path.write_text(_json.dumps(wallet_data, indent=2))
            logger.info(f"[HYP-WALLET] ✅ Wallet saved to {wallet_path}")
        except Exception as e:
            logger.error(f"[HYP-WALLET] Failed to save wallet: {e}")
            raise

        return self.address

    def _decrypt_wallet_data(self, wallet_data: dict, password: str) -> Optional[dict]:
        """Decrypt encrypted wallet using HypGammaEngine.decrypt()."""
        try:
            if "cipher" not in wallet_data:
                return wallet_data  # Not encrypted

            # Encrypted wallet format uses HypGammaEngine.decrypt()
            # The wallet was encrypted as: engine.encrypt(wallet_json_bytes, password_as_pubkey)
            cipher_data = wallet_data.get("cipher", "")
            message_tag = wallet_data.get("message_tag") or wallet_data.get("auth", "")

            if not cipher_data:
                logger.error("[HYP-WALLET] Encrypted wallet missing cipher data")
                return None

            try:
                # Use HypGammaEngine to decrypt with password as private key
                self._init_engine()

                # Decrypt using engine.decrypt with password
                ciphertext_dict = {
                    "ciphertext": cipher_data,
                    "message_tag": message_tag if message_tag else "",
                }

                plaintext_bytes = self.engine.decrypt(ciphertext_dict, password)

                # Parse decrypted JSON
                import json as _json

                decrypted_data = _json.loads(plaintext_bytes.decode("utf-8"))
                logger.info(
                    "[HYP-WALLET] ✅ Successfully decrypted wallet using HypGammaEngine"
                )
                return decrypted_data

            except Exception as _decrypt_err:
                logger.debug(
                    f"[HYP-WALLET] HypGammaEngine.decrypt() failed: {_decrypt_err}"
                )
                return None

        except Exception as e:
            logger.error(f"[HYP-WALLET] Wallet decryption failed: {e}")
            return None

    def load(self, password: str) -> bool:
        """Load wallet from wallet.json file using password."""
        wallet_file = Path("data") / "wallet.json"

        # If already loaded, return True
        if self.is_loaded():
            return True

        # If file doesn't exist, return False
        if not wallet_file.exists():
            logger.debug(f"[HYP-WALLET] No wallet file at {wallet_file}")
            return False

        try:
            self._init_engine()  # Initialize engine if not already done
            import json as _json

            wallet_data = _json.loads(wallet_file.read_text())

            # Try to decrypt if wallet is encrypted
            if "cipher" in wallet_data:
                decrypted = self._decrypt_wallet_data(wallet_data, password)
                if decrypted:
                    wallet_data = decrypted
                else:
                    # Decryption failed — password is wrong
                    logger.error(
                        "[HYP-WALLET] ❌ Failed to decrypt wallet — password is incorrect"
                    )
                    return False

            # Validate required fields
            if not all(
                k in wallet_data for k in ["address", "public_key", "private_key"]
            ):
                # Decrypted wallet missing fields — likely wrong password or corrupted
                logger.warning(
                    "[HYP-WALLET] Wallet data missing required fields (likely wrong password)"
                )
                logger.info("[HYP-WALLET] Generating fresh keypair for this session")
                self.keypair = self.engine.generate_keypair()
                self._loaded = True
                logger.info(
                    f"[HYP-WALLET] ✅ Fresh keypair generated — address: {self.keypair.address[:16]}..."
                )
                return True

            # Reconstruct keypair from wallet data
            self.keypair = HypKeyPair(
                public_key=wallet_data["public_key"],
                private_key=wallet_data["private_key"],
                address=wallet_data["address"],
            )
            self._loaded = True
            logger.info(
                f"[HYP-WALLET] ✅ Loaded wallet — address: {self.keypair.address[:16]}..."
            )
            return True
        except Exception as e:
            logger.error(f"[HYP-WALLET] Failed to load wallet: {e}")
            logger.info(
                "[HYP-WALLET] Falling back to generating fresh keypair for this session"
            )
            try:
                self._init_engine()
                self.keypair = self.engine.generate_keypair()
                self._loaded = True
                logger.info(
                    f"[HYP-WALLET] ✅ Fresh keypair generated — address: {self.keypair.address[:16]}..."
                )
                return True
            except Exception:
                return False

    def restore_from_mnemonic(self, mnemonic: str, password: str) -> bool:
        """Restore from mnemonic. Not supported by HypGammaWallet (no BIP-39)."""
        logger.warning(
            "[HYP-WALLET] restore_from_mnemonic not supported (HypΓ uses direct key generation)"
        )
        return False

    def show_mnemonic(self, password: str) -> Optional[str]:
        """Show mnemonic. HypGammaWallet doesn't use mnemonics."""
        logger.warning(
            "[HYP-WALLET] show_mnemonic not supported (HypΓ uses direct key generation)"
        )
        return None


class HypGammaEngine:
    """HypΓ cryptosystem — post-quantum signatures and encryption."""

    _instance: Optional["HypGammaEngine"] = None
    _lock = threading.Lock()

    def __new__(cls):
        """Singleton pattern."""
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
                    cls._instance._init_hyp()
        return cls._instance

    def _init_hyp(self):
        """Initialize HypΓ engine."""
        try:
            from hyp_engine import HypGammaEngine as HypEngine

            self._hyp_engine = HypEngine()
            logger.info(
                "[HYP-ENGINE] ✅ HypΓ engine initialized — Schnorr-Γ + GeodesicLWE active"
            )
        except ImportError as e:
            logger.critical(f"[HYP-ENGINE] FATAL: hyp_engine module not available: {e}")
            raise RuntimeError(f"HypΓ engine initialization failed: {e}") from e

    def generate_keypair(self) -> HypKeyPair:
        """Generate new HypΓ keypair."""
        kp = self._hyp_engine.generate_keypair()
        # kp is a NamedTuple from hyp_engine; convert to client's HypKeyPair
        return HypKeyPair(
            public_key=kp.public_key, private_key=kp.private_key, address=kp.address
        )

    def sign_hash(self, message_hash: bytes, private_key: str) -> Dict[str, str]:
        """Sign message hash with HypΓ."""
        return self._hyp_engine.sign_hash(message_hash, private_key)

    def verify_signature(
        self, message_hash: bytes, signature: Dict[str, str], public_key: str
    ) -> bool:
        """Verify HypΓ signature."""
        return self._hyp_engine.verify_signature(message_hash, signature, public_key)

    def sign_block(
        self, block_dict: Dict[str, Any], private_key: str
    ) -> Dict[str, Any]:
        """Sign block with HypΓ."""
        return self._hyp_engine.sign_block(block_dict, private_key)

    def verify_block(
        self, block_dict: Dict[str, Any], signature: Dict[str, str], public_key: str
    ) -> Tuple[bool, str]:
        """Verify block signature."""
        return self._hyp_engine.verify_block(block_dict, signature, public_key)

    def derive_address(self, public_key: str) -> str:
        """Derive address from public key."""
        return self._hyp_engine.derive_address(public_key)

    def derive_public_key(self, private_key: str) -> str:
        """Derive public key from private key."""
        return self._hyp_engine.derive_public_key(private_key)


class CompactBlockSerializer:
    """
    Compact block relay protocol — sends short transaction IDs instead of
    full transactions. Peers reconstruct from their local mempool.
    Reduces block announcement bandwidth by ~95%.
    """

    # ShortTxID: first 6 bytes of SHA256(txid || block_seed), encoded as 12 hex chars
    SHORT_TXID_LEN = 12  # 6 bytes = 12 hex chars

    @staticmethod
    def short_txid(tx_hash: str, block_seed: str = "") -> str:
        """Derive a compact short txid for block relay."""
        raw = f"{tx_hash}|{block_seed}".encode()
        return hashlib.sha256(raw).hexdigest()[: CompactBlockSerializer.SHORT_TXID_LEN]

    @staticmethod
    def create_compact_block(block: dict, mempool_txids: set) -> dict:
        """
        Create a compact block from a full block.

        Includes:
        - Block header fields
        - Short txids for all transactions
        - Prefilled coinbase tx (always index 0)
        - Missing txids for peers to request

        Returns a dict that can be sent as a P2P message.
        """
        block_seed = block.get("block_hash", "") or str(block.get("height", 0))
        txs = block.get("transactions", [])

        compact_txs = []
        missing_txids = []
        for i, tx in enumerate(txs):
            txid = tx.get("txid", "") or tx.get("tx_hash", "")
            stxid = CompactBlockSerializer.short_txid(txid, block_seed)
            if i == 0 or txid in mempool_txids:
                # Prefill: coinbase (index 0) or txs we already have
                compact_txs.append(
                    {"index": i, "short_id": stxid, "txid": txid if i == 0 else ""}
                )
            else:
                # Missing: peer needs to request these
                compact_txs.append({"index": i, "short_id": stxid, "txid": ""})
                missing_txids.append(txid)

        return {
            "block_hash": block.get("block_hash", ""),
            "height": block.get("height", 0),
            "parent_hash": block.get("previous_hash", block.get("parent_hash", "")),
            "timestamp": block.get("timestamp", 0),
            "miner_address": block.get(
                "miner_address", block.get("validator_public_key", "")
            ),
            "nonce": block.get("nonce", 0),
            "difficulty": block.get("difficulty", 0),
            "merkle_root": block.get("transactions_root", block.get("merkle_root", "")),
            "block_seed": block_seed,
            "prefilled_count": 1,  # coinbase always prefilled
            "compact_txs": compact_txs,
            "missing_txids": missing_txids,
            "compact": True,
        }

    @staticmethod
    def reconstruct_block(compact: dict, mempool: dict) -> tuple:
        """
        Attempt to reconstruct a full block from a compact block + local mempool.

        Args:
            compact: The compact block dict
            mempool: Dict of txid -> tx_data (from local mempool)

        Returns:
            (success: bool, block: dict or None, missing_txids: list)
        """
        block_seed = compact.get("block_seed", "")
        block = {
            "block_hash": compact.get("block_hash", ""),
            "height": compact.get("height", 0),
            "previous_hash": compact.get("parent_hash", ""),
            "timestamp": compact.get("timestamp", 0),
            "miner_address": compact.get("miner_address", ""),
            "nonce": compact.get("nonce", 0),
            "difficulty": compact.get("difficulty", 0),
            "merkle_root": compact.get("merkle_root", ""),
            "transactions": [],
        }

        missing = []
        sorted_txs = sorted(compact.get("compact_txs", []), key=lambda x: x["index"])

        for ctx in sorted_txs:
            idx = ctx["index"]
            if ctx["txid"]:
                # Prefilled transaction (coinbase)
                # In real implementation, the full tx would be in the compact block
                # For now, mark as prefilled
                block["transactions"].append({"txid": ctx["txid"], "prefilled": True})
            else:
                # Need to find from mempool using short_id
                short_id = ctx["short_id"]
                found = False
                for txid, tx_data in mempool.items():
                    if CompactBlockSerializer.short_txid(txid, block_seed) == short_id:
                        block["transactions"].append(tx_data)
                        found = True
                        break
                if not found:
                    # We'll need to request this tx
                    # Use short_id as placeholder; requesting node fills in
                    missing.append({"index": idx, "short_id": short_id})

        success = len(missing) == 0
        return success, block, missing


def hyp_handshake_challenge(identity: "P2PIdentity", engine=None) -> dict:
    """Create a challenge that proves we control the P2P identity's wallet key."""
    engine = engine or HypGammaEngine()
    nonce = secrets.token_hex(16)
    ts = int(time.time())
    challenge = {
        "challenge_nonce": nonce,
        "timestamp": ts,
        "node_id": identity.node_id,
    }
    # Sign the challenge with a key derived from identity
    priv_hex = identity.privkey_bytes.hex()
    msg_hash = hashlib.sha256(json.dumps(challenge, sort_keys=True).encode()).digest()
    sig = engine.sign_hash(msg_hash, priv_hex)
    challenge["hyp_sig"] = sig
    return challenge


def hyp_verify_handshake_response(
    challenge: dict, response: dict, identity: "P2PIdentity", engine=None
) -> bool:
    """Verify a peer's handshake challenge response."""
    engine = engine or HypGammaEngine()
    # Verify the response contains our original nonce
    if response.get("challenge_nonce") != challenge.get("challenge_nonce"):
        return False
    # Verify timestamp freshness
    if abs(int(time.time()) - response.get("timestamp", 0)) > 60:
        return False
    # Verify HypΓ signature
    priv_hex = identity.privkey_bytes.hex()
    msg_hash = hashlib.sha256(json.dumps(response, sort_keys=True).encode()).digest()
    return engine.verify_signature(msg_hash, response.get("hyp_sig", {}), "")


