# ════════════════════════════════════════════════════════════════════════════════════════
# UTXO SET MANAGEMENT — Cathedral-grade production implementation for thousands of miners
# ════════════════════════════════════════════════════════════════════════════════════════

_UTXO_TABLE_INITIALIZED: threading.Event = threading.Event()
_UTXO_INIT_LOCK: threading.Lock = threading.Lock()


def _lazy_ensure_utxo_set(db_path: Path) -> bool:
    """
    Lazily initialize the UTXO set table with proper indexes.
    Thread-safe singleton initialization for production mining operations.

    UTXO Schema:
        utxo_id:        TEXT PRIMARY KEY — format: tx_hash:output_index
        owner_address:  TEXT NOT NULL — recipient of this UTXO
        amount:         INTEGER NOT NULL — satoshi/wei amount
        created_height: INTEGER NOT NULL — block height when UTXO was created
        spent_height:   INTEGER — block height when UTXO was spent (NULL if unspent)

    Indexes for O(1) production queries:
        idx_utxo_owner — fast balance lookups by address
        idx_utxo_unspent — fast UTXO set scans (spent_height IS NULL)
        idx_utxo_created — fast chain reorg handling

    Returns True if table exists/created successfully, False on error.
    """
    if _UTXO_TABLE_INITIALIZED.is_set():
        return True

    with _UTXO_INIT_LOCK:
        if _UTXO_TABLE_INITIALIZED.is_set():
            return True

        import sqlite3

        try:
            conn = sqlite3.connect(str(db_path), timeout=30.0, check_same_thread=False)
            try:
                cursor = conn.cursor()

                # Create UTXO table with cathedral-grade constraints
                cursor.execute("""
                    CREATE TABLE IF NOT EXISTS utxo_set (
                        utxo_id TEXT PRIMARY KEY NOT NULL,
                        owner_address TEXT NOT NULL,
                        amount INTEGER NOT NULL CHECK(amount > 0),
                        created_height INTEGER NOT NULL,
                        spent_height INTEGER DEFAULT NULL,
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                        spent_at TIMESTAMP DEFAULT NULL,
                        CHECK (utxo_id LIKE '%:%'),
                        CHECK (LENGTH(utxo_id) >= 66)
                    )
                """)

                # Create production-grade indexes for O(1) queries
                cursor.execute("""
                    CREATE INDEX IF NOT EXISTS idx_utxo_owner 
                    ON utxo_set(owner_address, spent_height)
                """)

                cursor.execute("""
                    CREATE INDEX IF NOT EXISTS idx_utxo_unspent 
                    ON utxo_set(spent_height) WHERE spent_height IS NULL
                """)

                cursor.execute("""
                    CREATE INDEX IF NOT EXISTS idx_utxo_created 
                    ON utxo_set(created_height)
                """)

                cursor.execute("""
                    CREATE INDEX IF NOT EXISTS idx_utxo_spent 
                    ON utxo_set(spent_height) WHERE spent_height IS NOT NULL
                """)

                # Verify table structure
                cursor.execute(
                    "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='utxo_set'"
                )
                if cursor.fetchone()[0] != 1:
                    raise RuntimeError("UTXO table creation verification failed")

                conn.commit()
                logger.info("[UTXO-INIT] ✅ UTXO set table initialized with indexes")
                _UTXO_TABLE_INITIALIZED.set()
                return True

            finally:
                conn.close()

        except Exception as e:
            logger.error(f"[UTXO-INIT] ❌ Failed to initialize UTXO set: {e}")
            return False


def _query_block_by_hash(conn: sqlite3.Connection, block_hash: str) -> Optional[dict]:
    """
    Query block by hash — helper for validation.
    Returns block dict or None if not found.
    """
    try:
        cursor = conn.cursor()
        cursor.execute(
            "SELECT * FROM blocks WHERE hash = ? OR block_hash = ? LIMIT 1",
            (block_hash, block_hash),
        )
        row = cursor.fetchone()
        if row:
            # Convert row to dict
            columns = [description[0] for description in cursor.description]
            return dict(zip(columns, row))
        return None
    except Exception as e:
        logger.debug(f"[UTXO-QUERY] Block hash query failed: {e}")
        return None


def _compute_merkle_root_from_txs(transactions: List[dict]) -> str:
    """
    Compute Merkle root from transaction list.
    Returns hex string of the Merkle root.
    """
    import hashlib

    if not transactions:
        return "0" * 64

    # Get tx hashes
    tx_hashes = []
    for tx in transactions:
        tx_hash = tx.get("tx_hash") or tx.get("hash") or tx.get("txid")
        if tx_hash:
            tx_hashes.append(tx_hash)

    if not tx_hashes:
        return "0" * 64

    # Convert to bytes and compute Merkle tree
    def _hash_pair(a: str, b: str) -> str:
        """Hash two hex strings together."""
        a_bytes = bytes.fromhex(a.zfill(64))
        b_bytes = bytes.fromhex(b.zfill(64))
        combined = a_bytes + b_bytes
        return hashlib.sha256(combined).hexdigest()

    # Build tree bottom-up
    current_level = tx_hashes[:]

    while len(current_level) > 1:
        next_level = []
        for i in range(0, len(current_level), 2):
            left = current_level[i]
            if i + 1 < len(current_level):
                right = current_level[i + 1]
            else:
                right = left  # Duplicate last if odd
            next_level.append(_hash_pair(left, right))
        current_level = next_level

    return current_level[0]


def _validate_utxo_inputs(
    conn: sqlite3.Connection, transactions: List[dict], block_height: int
) -> Tuple[bool, str]:
    """
    Validate that all non-coinbase transaction inputs reference existing unspent UTXOs.

    Returns: (is_valid: bool, error_message: str)
    """
    try:
        cursor = conn.cursor()

        for tx in transactions:
            # Skip coinbase transactions (first tx in block with no inputs)
            tx_type = tx.get("tx_type", tx.get("type", "transfer"))
            if tx_type == "coinbase":
                continue

            inputs = tx.get("inputs", tx.get("vin", []))

            for inp in inputs:
                # Get UTXO reference
                prev_tx_hash = inp.get("prev_tx_hash") or inp.get("txid")
                prev_output_idx = inp.get("prev_output_index") or inp.get("vout", 0)

                if not prev_tx_hash:
                    return (
                        False,
                        f"Missing prev_tx_hash in input for tx {tx.get('tx_hash', 'unknown')}",
                    )

                utxo_id = f"{prev_tx_hash}:{prev_output_idx}"

                # Check UTXO exists and is unspent
                cursor.execute(
                    "SELECT 1 FROM utxo_set WHERE utxo_id = ? AND spent_height IS NULL LIMIT 1",
                    (utxo_id,),
                )
                if not cursor.fetchone():
                    return False, f"UTXO not found or already spent: {utxo_id[:20]}..."

        return True, ""

    except Exception as e:
        return False, f"UTXO validation error: {e}"


def _apply_utxo_updates_atomic(
    conn: sqlite3.Connection, block: dict, block_height: int
) -> Tuple[bool, str]:
    """
    Atomically apply UTXO updates for a block:
    1. Mark spent UTXOs
    2. Create new UTXOs from outputs

    Returns: (success: bool, error_message: str)
    """
    try:
        cursor = conn.cursor()
        transactions = block.get("transactions", block.get("txs", []))

        # First pass: Mark spent UTXOs
        for tx in transactions:
            tx_type = tx.get("tx_type", tx.get("type", "transfer"))
            if tx_type == "coinbase":
                continue

            inputs = tx.get("inputs", tx.get("vin", []))
            for inp in inputs:
                prev_tx_hash = inp.get("prev_tx_hash") or inp.get("txid")
                prev_output_idx = inp.get("prev_output_index") or inp.get("vout", 0)

                if prev_tx_hash:
                    utxo_id = f"{prev_tx_hash}:{prev_output_idx}"
                    cursor.execute(
                        """UPDATE utxo_set 
                           SET spent_height = ?, spent_at = CURRENT_TIMESTAMP
                           WHERE utxo_id = ? AND spent_height IS NULL""",
                        (block_height, utxo_id),
                    )

        # Second pass: Create new UTXOs from outputs
        for tx in transactions:
            tx_hash = tx.get("tx_hash") or tx.get("hash") or tx.get("txid")
            if not tx_hash:
                continue

            outputs = tx.get("outputs", tx.get("vout", []))
            for idx, output in enumerate(outputs):
                amount = output.get("amount", output.get("value", 0))
                owner = output.get("address", output.get("script_pubkey", ""))

                if amount > 0 and owner:
                    utxo_id = f"{tx_hash}:{idx}"
                    cursor.execute(
                        """INSERT INTO utxo_set
                           (utxo_id, owner_address, amount, created_height)
                           VALUES (?, ?, ?, ?)
                           ON CONFLICT(utxo_id) DO NOTHING""",
                        (utxo_id, owner, int(amount), block_height),
                    )

        return True, ""

    except Exception as e:
        return False, f"UTXO update error: {e}"


def _update_chain_state_atomic(
    conn: sqlite3.Connection,
    block_height: int,
    block_hash: str,
    miner_address: str,
    block_timestamp: int,
) -> None:
    """
    Update chain state within the atomic transaction.
    Tracks chain tip, total difficulty, and miner statistics.

    This is called within the atomic transaction so it rolls back
    if any part of the block acceptance fails.
    """
    cursor = conn.cursor()

    # Create chain_state table if not exists
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS chain_state (
            key TEXT PRIMARY KEY NOT NULL,
            value TEXT NOT NULL,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)

    # Update chain tip (SQLite 3.24+ and PostgreSQL compatible ON CONFLICT syntax)
    cursor.execute(
        """
        INSERT INTO chain_state (key, value, updated_at)
        VALUES ('chain_tip_height', ?, CURRENT_TIMESTAMP)
        ON CONFLICT(key) DO UPDATE SET value = EXCLUDED.value, updated_at = CURRENT_TIMESTAMP
    """,
        (str(block_height),),
    )

    cursor.execute(
        """
        INSERT INTO chain_state (key, value, updated_at)
        VALUES ('chain_tip_hash', ?, CURRENT_TIMESTAMP)
        ON CONFLICT(key) DO UPDATE SET value = EXCLUDED.value, updated_at = CURRENT_TIMESTAMP
    """,
        (block_hash,),
    )

    cursor.execute(
        """
        INSERT INTO chain_state (key, value, updated_at)
        VALUES ('chain_tip_timestamp', ?, CURRENT_TIMESTAMP)
        ON CONFLICT(key) DO UPDATE SET value = EXCLUDED.value, updated_at = CURRENT_TIMESTAMP
    """,
        (str(block_timestamp),),
    )

    cursor.execute(
        """
        INSERT INTO chain_state (key, value, updated_at)
        VALUES ('chain_tip_miner', ?, CURRENT_TIMESTAMP)
        ON CONFLICT(key) DO UPDATE SET value = EXCLUDED.value, updated_at = CURRENT_TIMESTAMP
    """,
        (miner_address,),
    )

    # Update total blocks accepted count
    cursor.execute("""
        INSERT INTO chain_state (key, value, updated_at)
        VALUES ('total_blocks_accepted', '1', CURRENT_TIMESTAMP)
        ON CONFLICT(key) DO UPDATE SET
            value = CAST(CAST(EXCLUDED.value AS INTEGER) + 1 AS TEXT),
            updated_at = CURRENT_TIMESTAMP
    """)

    logger.debug(
        f"[CHAIN-STATE] ✅ Updated chain tip to h={block_height}, hash={block_hash[:16]}..."
    )


