@dataclass
class HyperbolicTriangle:
    """Geodesic triangle in the {8,3} hyperbolic plane.
    Vertices are pseudoqubit IDs mapped to the Poincaré ball via
    qtcl_pq_to_ball().  The triangle_area is the angular defect (Gauss-Bonnet),
    a direct measure of how much hyperbolic curvature the chain has traversed."""

    pq0: int
    pq_curr: int
    pq_last: int
    dist_0c: float  # geodesic d(pq0, pq_curr)
    dist_cl: float  # geodesic d(pq_curr, pq_last)
    dist_0l: float  # geodesic d(pq0, pq_last)
    area: float  # angular defect = π - (α+β+γ), units: radians
    ball_pq0: tuple  # (r, θ, φ) in Poincaré ball
    ball_curr: tuple
    ball_last: tuple

    @classmethod
    def compute(cls, pq0: int, pq_curr: int, pq_last: int) -> "HyperbolicTriangle":
        """
        Compute triangle using DB pseudoqubit coordinates (mpmath mp.dps=150).

        Fetches real Poincaré disk coords for pq0, pq_curr, pq_last from the
        SQLite lattice cache populated by _ensure_pq_cache().  Uses the exact
        same geometry functions as db_builder_colab.py:
          - _hyp_distance       → geodesic side lengths
          - _hyp_triangle_area  → Gauss-Bonnet angular defect
        Falls back to fast Euclidean approximation if cache not ready.
        """
        cache_ready = _PQ_CACHE_READY.is_set()
        if cache_ready:
            try:
                x0, y0 = _pq_get_coord(pq0)
                xc, yc = _pq_get_coord(pq_curr)
                xl, yl = _pq_get_coord(pq_last)
                d0c = float(_hyp_distance(x0, y0, xc, yc))
                dcl = float(_hyp_distance(xc, yc, xl, yl))
                d0l = float(_hyp_distance(x0, y0, xl, yl))
                area = float(_hyp_triangle_area(x0, y0, xc, yc, xl, yl))
                area = max(0.0, area)
                return cls(
                    pq0=pq0,
                    pq_curr=pq_curr,
                    pq_last=pq_last,
                    dist_0c=d0c,
                    dist_cl=dcl,
                    dist_0l=d0l,
                    area=area,
                    ball_pq0=(x0, y0, 0.0),
                    ball_curr=(xc, yc, 0.0),
                    ball_last=(xl, yl, 0.0),
                )
            except Exception as exc:
                logger.debug(
                    f"[HyperbolicTriangle] DB path failed ({exc}), using fallback"
                )
        # ── Fast Euclidean approximation fallback ────────────────────────────
        import math as _m

        def _pq_r(p):
            return _m.tanh((p // 8 + 1) * 0.766 / 2)

        def _pq_theta(p):
            return 2 * _m.pi * (p % 8) / 8.0

        def _pq_phi(p):
            return _m.pi / 2.0

        def _dist(p1, p2):
            r1 = _pq_r(p1)
            t1 = _pq_theta(p1)
            ph1 = _pq_phi(p1)
            r2 = _pq_r(p2)
            t2 = _pq_theta(p2)
            ph2 = _pq_phi(p2)
            x1 = r1 * _m.sin(ph1) * _m.cos(t1)
            y1 = r1 * _m.sin(ph1) * _m.sin(t1)
            z1 = r1 * _m.cos(ph1)
            x2 = r2 * _m.sin(ph2) * _m.cos(t2)
            y2 = r2 * _m.sin(ph2) * _m.sin(t2)
            z2 = r2 * _m.cos(ph2)
            num = (x1 - x2) ** 2 + (y1 - y2) ** 2 + (z1 - z2) ** 2
            denom = (1 - r1**2) * (1 - r2**2)
            if denom < 1e-10:
                denom = 1e-10
            arg = 1.0 + 2.0 * num / denom
            return 2.0 * _m.acosh(max(1.0, arg))

        d0c = _dist(pq0, pq_curr)
        dcl = _dist(pq_curr, pq_last)
        d0l = _dist(pq0, pq_last)
        return cls(
            pq0=pq0,
            pq_curr=pq_curr,
            pq_last=pq_last,
            dist_0c=d0c,
            dist_cl=dcl,
            dist_0l=d0l,
            area=max(0.0, _m.pi / 6.0 - 0.01 * (d0c + dcl + d0l)),
            ball_pq0=(_pq_r(pq0), _pq_theta(pq0), _pq_phi(pq0)),
            ball_curr=(_pq_r(pq_curr), _pq_theta(pq_curr), _pq_phi(pq_curr)),
            ball_last=(_pq_r(pq_last), _pq_theta(pq_last), _pq_phi(pq_last)),
        )

    def as_dict(self) -> dict:
        return {
            "pq0": self.pq0,
            "pq_curr": self.pq_curr,
            "pq_last": self.pq_last,
            "hyp_dist_0c": self.dist_0c,
            "hyp_dist_cl": self.dist_cl,
            "hyp_dist_0l": self.dist_0l,
            "hyp_triangle_area": self.area,
            "ball_pq0": list(self.ball_pq0),
            "ball_curr": list(self.ball_curr),
            "ball_last": list(self.ball_last),
        }


@dataclass
class QtclOracleMeasurement:
    """Full local oracle measurement — the core gossip object.
    Built by LiveRPCOracleSnapshot.fetch_snapshot() from RPC oracle endpoint."""

    chain_height: int
    pq0: int
    pq_curr: int
    pq_last: int
    triangle: HyperbolicTriangle
    dm_re: list  # 64 floats, row-major
    dm_im: list  # 64 floats, row-major
    fidelity_to_w3: float
    coherence: float
    purity: float
    negativity_AB: float
    entropy_vn: float
    discord: float
    auth_tag_hex: str  # HMAC-SHA256 via C
    pow_seed_bytes: bytes  # SHA3-256(quorum_hash_hex + dm_re[:32])

    @property
    def dm_hex(self) -> str:
        import struct

        parts = []
        for i in range(64):
            re = self.dm_re[i]
            im = self.dm_im[i]
            parts.append(struct.pack(">dd", re, im).hex())
        return "".join(parts)

    @property
    def dm_re_bytes(self) -> bytes:
        import struct

        return struct.pack(f">{len(self.dm_re)}d", *self.dm_re)


# ═══════════════════════════════════════════════════════════════════════════════
# RPC ORCHESTRATOR: Unified polling for oracle snapshots + chain status
# ═══════════════════════════════════════════════════════════════════════════════


class LiveRPCOracleSnapshot:
    """⚛️ Real-time synchronous RPC snapshot fetcher → DM + metrics on-demand (ZERO polling)."""

    ORACLE_URL = (
        ENTROPY_SERVER_URL  # unified — set from ENTROPY_SERVER or ORACLE_URL env
    )

    def __init__(self):
        self._dm_re = [0.0] * 64
        self._dm_im = [0.0] * 64
        self._last_fetch_ts = 0.0
        self._dm_lock = threading.Lock()
        self._oracle_state = {}
        self._oracle_state_lock = threading.Lock()
        self._session = None  # Lazy-init HTTP session

        # ← SSE STREAMING LISTENER (Real-time density matrix updates from /rpc/oracle/snapshot)
        self.sse_listener = None
        self._start_sse_stream()

    def _start_sse_stream(self):
        """Initialize EventSource listener for live density matrix stream."""
        try:
            # Import EventSourceListener at runtime to avoid circular deps
            import sys

            if "sse_listener" not in sys.modules:
                # SSE listener module not available — that's OK, fall back to RPC polling
                logger.debug(
                    "[CLIENT] SSE listener module not available, using RPC polling"
                )
                return

            from sse_listener import EventSourceListener

            self.sse_listener = EventSourceListener(
                url=f"{SSE_SERVICE_URL}/rpc/oracle/snapshot",
                on_snapshot=self._handle_sse_snapshot,
                timeout=5.0,
                max_reconnect_attempts=5,
                fallback_to_rpc=True,
            )
            self.sse_listener.start()
            logger.info(
                "[CLIENT] SSE listener started for real-time density matrix updates"
            )
        except ImportError:
            logger.debug(
                "[CLIENT] SSE listener not installed, RPC polling will be used as fallback"
            )
        except Exception as e:
            logger.debug(
                f"[CLIENT] SSE listener initialization failed: {e}, falling back to RPC polling"
            )

    def _handle_sse_snapshot(self, snapshot: Dict[str, Any]):
        """Handle incoming SSE density matrix snapshot (called from listener thread)."""
        try:
            # Extract density matrix (prefer real/imag lists, fallback to hex)
            dm_real = snapshot.get("density_matrix_real")
            dm_imag = snapshot.get("density_matrix_imag")

            if (
                dm_real
                and dm_imag
                and isinstance(dm_real, list)
                and isinstance(dm_imag, list)
            ):
                with self._dm_lock:
                    self._dm_re = dm_real
                    self._dm_im = dm_imag
                    self._last_fetch_ts = time.time()

            # Update oracle state for RPC endpoints
            if snapshot:
                with self._oracle_state_lock:
                    self._oracle_state = snapshot.copy()

            # Log statistics periodically
            if self.sse_listener:
                stats = self.sse_listener.get_stats()
                if (
                    stats["total_frames"] % 50 == 0
                ):  # Log every 50 frames (~2.5 seconds)
                    logger.debug(
                        f"[SSE] frames={stats['total_frames']}, "
                        f"fps={stats['frames_per_second']:.1f}, "
                        f"latency={stats['last_frame_sec_ago'] * 1000:.1f}ms"
                    )

        except Exception as e:
            logger.debug(f"[SSE-SNAPSHOT] Handler error: {e}")

    def _get_session(self):
        """Lazy-init HTTP session for connection pooling."""
        if self._session is None:
            try:
                import requests

                self._session = requests.Session()
            except:
                self._session = False  # Mark as failed
        return self._session if self._session else None

    def fetch_snapshot(self, timeout_s=5.0) -> dict:
        """Read snapshot from SSE stream /rpc/oracle/snapshot OR fallback to RPC.

        Fetches quantum state: tries SSE stream first, falls back to RPC POST.
        Processes snapshot: parses density matrix, converts W-state if needed,
        updates oracle state cache.
        """
        _t0 = time.time()
        _snap_url = f"{SSE_SERVICE_URL}/rpc/oracle/snapshot"
        _rpc_url = f"{self.ORACLE_URL}/rpc"
        _payload = {
            "jsonrpc": "2.0",
            "method": "qtcl_getQuantumMetrics",
            "params": [],
            "id": 1,
        }
        snap = {}

        try:
            session = self._get_session()
            if not session:
                return {}

            # PRIMARY: Read from SSE stream /rpc/oracle/snapshot (with proper timeout)
            try:
                _snap_result = [None]  # Mutable container for thread result
                _snap_error = [None]

                def _read_sse():
                    try:
                        # Stream=True: read response as stream, don't load entire body
                        _r = session.get(
                            _snap_url,
                            timeout=(timeout_s / 2, timeout_s),
                            headers={"Accept": "text/event-stream"},
                            stream=True,
                        )
                        # Handle 429 Too Many Requests — server at capacity
                        if _r.status_code == 429:
                            _retry_after = int(_r.headers.get("Retry-After", "5"))
                            _snap_error[0] = (
                                f"HTTP 429 (at capacity, retry after {_retry_after}s)"
                            )
                            return
                        # Handle other non-2xx responses
                        if _r.status_code not in (200, 202):
                            _snap_error[0] = f"HTTP {_r.status_code}"
                            return
                        # Read SSE stream successfully
                        try:
                            # Read line by line from stream without loading entire response
                            for _line in _r.iter_lines(
                                decode_unicode=True, chunk_size=1024
                            ):
                                if _line.startswith("data: "):
                                    try:
                                        _envelope = json.loads(_line[6:])
                                        _snap_result[0] = _envelope.get(
                                            "result", _envelope
                                        )
                                        _r.close()  # Close immediately after getting first message
                                        return
                                    except json.JSONDecodeError:
                                        continue
                                elif _line and not _line.startswith(":"):
                                    _r.close()
                                    return
                        finally:
                            _r.close()
                    except Exception as e:
                        _snap_error[0] = e

                _sse_thread = threading.Thread(target=_read_sse, daemon=True)
                _sse_thread.start()
                _sse_thread.join(
                    timeout=timeout_s
                )  # Wait up to timeout_s for first line

                if _snap_result[0]:
                    snap = _snap_result[0]
                    logger.debug(f"[RPC-ORACLE] ✅ SSE snapshot received")
                elif _snap_error[0]:
                    logger.debug(
                        f"[RPC-ORACLE] SSE failed: {_snap_error[0]} (trying RPC)"
                    )
            except Exception as _sse_e:
                logger.debug(f"[RPC-ORACLE] SSE failed: {_sse_e} (trying RPC)")

            # FALLBACK: GET /rpc with qtcl_getQuantumMetrics
            if not snap:
                try:
                    import urllib.parse as _up

                    params_json = json.dumps(_payload.get("params", []))
                    query = _up.urlencode(
                        {
                            "method": _payload.get("method"),
                            "params": params_json,
                            "id": 1,
                        }
                    )
                    _rpc_get_url = f"{_rpc_url}?{query}"
                    _r = session.get(_rpc_get_url, timeout=timeout_s)
                    if _r.status_code in (200, 202):
                        _body = _r.json()
                        snap = _body.get("result") or {}
                        if snap and snap.get("density_matrix_hex"):
                            logger.debug(
                                f"[RPC-ORACLE] ✅ RPC fallback succeeded with 16³ DM (32 KB)"
                            )
                except Exception as _rpc_e:
                    logger.debug(f"[RPC-ORACLE] RPC fallback failed: {_rpc_e}")

            if not snap:
                return {}

            # Process snapshot: parse 16³ density tensor (native 3D format) — 2000× smaller than 64³
            dm_hex = snap.get("density_matrix_hex")
            if dm_hex:
                try:
                    bdata = bytes.fromhex(dm_hex)
                    expected_16_3_complex64 = (
                        4096 * 8
                    )  # 16³ × complex64 (8 bytes) = 32,768 bytes

                    if len(bdata) != expected_16_3_complex64:
                        logger.error(
                            f"[RPC-ORACLE] ❌ DM size mismatch: {len(bdata)} bytes, expected {expected_16_3_complex64} (16³)"
                        )
                        raise ValueError(f"Invalid tensor size: {len(bdata)} bytes")

                    # Parse 16³ format
                    dm_flat = []
                    for i in range(4096):
                        re, im = struct.unpack_from(">ff", bdata, i * 8)
                        dm_flat.append(complex(float(re), float(im)))

                    # Store 16³ tensor metadata
                    snap["_density_matrix_3d"] = {
                        "dimension": 16,
                        "shape": [16, 16, 16],
                        "elements": dm_flat,
                        "timestamp": time.time(),
                    }

                    # Keep first 16 elements for legacy compatibility
                    with self._dm_lock:
                        self._dm_re = [c.real for c in dm_flat[:16]]
                        self._dm_im = [c.imag for c in dm_flat[:16]]
                        self._last_fetch_ts = time.time()

                    logger.debug(
                        f"[RPC-ORACLE] ✅ Parsed 16³ density tensor ({len(dm_flat)} elements, 32 KB)"
                    )

                except Exception as _parse_e:
                    logger.debug(f"[RPC-ORACLE] DM parse error: {_parse_e}")

            # Update oracle state cache
            if snap:
                with self._oracle_state_lock:
                    w_state = snap.get("w_state") or {}
                    _lattice = snap.get("lattice") or {}
                    _fid_raw = (
                        w_state.get("fidelity")
                        or snap.get("w_state_fidelity")
                        or _lattice.get("fidelity")
                        or snap.get("fidelity")
                        or snap.get("client_fused_fidelity")
                        or 0.0
                    )
                    _bh_snap = int(snap.get("block_height") or snap.get("height") or 0)

                    _pur_raw = w_state.get("purity")
                    if _pur_raw is None:
                        _pur_raw = _lattice.get("purity")
                    if _pur_raw is None:
                        _pur_raw = 0.0
                    try:
                        _pur_val = float(_pur_raw)
                        if not (0.0 <= _pur_val <= 1.0):
                            _pur_val = 0.0
                    except (TypeError, ValueError):
                        _pur_val = 0.0

                    _vne_raw = (
                        w_state.get("entropy")
                        or w_state.get("von_neumann_entropy")
                        or _lattice.get("entropy")
                        or 0.0
                    )
                    try:
                        _vne_val = float(_vne_raw)
                        if not (0.0 <= _vne_val <= 10.0):
                            _vne_val = 0.0
                    except (TypeError, ValueError):
                        _vne_val = 0.0

                    _pq_curr_raw = snap.get("pq_curr") or snap.get("pq_curr_id")
                    _pq_last_raw = snap.get("pq_last") or snap.get("pq_last_id")
                    _pq_curr = (
                        int(_pq_curr_raw)
                        if _pq_curr_raw is not None
                        else (_bh_snap + 1)
                    )
                    _pq_last = (
                        int(_pq_last_raw) if _pq_last_raw is not None else _bh_snap
                    )

                    self._oracle_state = {
                        "w_state_fidelity": float(_fid_raw),
                        "coherence_l1": float(
                            w_state.get("coherence") or _lattice.get("coherence") or 0.0
                        ),
                        "von_neumann_entropy": _vne_val,
                        "purity": _pur_val,
                        "cycle": snap.get("cycle", 0),
                        "consensus": snap.get("consensus", False),
                        "mermin_test": snap.get("mermin_test", {}),
                        "block_height": _bh_snap,
                        "density_matrix_hex": snap.get("density_matrix_hex", ""),
                        "pq_curr": _pq_curr,
                        "pq_last": _pq_last,
                        "latency_ms": round((time.time() - _t0) * 1000.0, 1),
                        "pq0_oracle_fidelity": float(
                            snap.get("pq0_oracle_fidelity")
                            or (snap.get("aer_noise_state") or {}).get(
                                "pq0_oracle_fidelity"
                            )
                            or 0.0
                        ),
                        "pq0_IV_fidelity": float(
                            snap.get("pq0_IV_fidelity")
                            or (snap.get("aer_noise_state") or {}).get(
                                "pq0_IV_fidelity"
                            )
                            or 0.0
                        ),
                        "pq0_V_fidelity": float(
                            snap.get("pq0_V_fidelity")
                            or (snap.get("aer_noise_state") or {}).get("pq0_V_fidelity")
                            or 0.0
                        ),
                    }

            snap["_latency_ms"] = round((time.time() - _t0) * 1000.0, 1)
            return snap

        except Exception as e:
            logger.debug(f"[RPC-ORACLE] fetch_snapshot error: {e}")
            return {}

    def _rpc(
        self, method: str, params: list = None, timeout: int = 5, retries: int = 2
    ):
        """Generic JSON-RPC 2.0 call to server /rpc endpoint.

        Used for health checks and metrics during bootstrap.
        Returns result dict or None on failure.
        IMPORTANT: Use POST for submitBlock to avoid GET 204 empty response issues.
        """
        import urllib.parse as _up
        import urllib.request as _ur
        import socket

        # Use POST for block submission to avoid GET 204 empty response
        if method == "qtcl_submitBlock":
            post_url = f"{self.ORACLE_URL}/rpc"
            payload = {
                "jsonrpc": "2.0",
                "method": method,
                "params": params or [],
                "id": 1,
            }
            for attempt in range(retries):
                try:
                    socket.setdefaulttimeout(timeout)
                    data = json.dumps(payload).encode("utf-8")
                    req = _ur.Request(
                        post_url,
                        data=data,
                        headers={
                            "Content-Type": "application/json",
                            "Accept": "application/json",
                        },
                    )
                    with _ur.urlopen(req, timeout=timeout) as resp:
                        result = json.loads(resp.read().decode("utf-8"))
                        if "result" in result:
                            return result.get("result")
                        elif "error" in result:
                            return result
                except Exception as e:
                    logger.debug(
                        f"[RPC-ORACLE] {method} POST attempt {attempt + 1}/{retries} failed: {e}"
                    )
                    if attempt < retries - 1:
                        time.sleep(min(2**attempt, 5))
                finally:
                    socket.setdefaulttimeout(None)
            return None

        # Use GET for other methods
        params_json = json.dumps(params or [])
        query = _up.urlencode({"method": method, "params": params_json, "id": 1})
        full_url = f"{self.ORACLE_URL}/rpc?{query}"

        for attempt in range(retries):
            try:
                # Use urllib with explicit socket timeout (more reliable than requests)
                req = _ur.Request(full_url, headers={"Accept": "application/json"})
                # Set socket timeout before urlopen
                socket.setdefaulttimeout(timeout)
                with _ur.urlopen(req, timeout=timeout) as resp:
                    result = json.loads(resp.read().decode("utf-8"))
                    if "result" in result:
                        return result.get("result")
                    elif "error" in result:
                        return result
            except Exception as e:
                logger.debug(
                    f"[RPC-ORACLE] {method} attempt {attempt + 1}/{retries} failed: {e}"
                )
                if attempt < retries - 1:
                    time.sleep(min(2**attempt, 5))  # Cap backoff at 5s
            finally:
                socket.setdefaulttimeout(None)  # Reset to default
        return None

    def get_oracle_dm(self) -> tuple:
        """Return (dm_re, dm_im, age_sec) thread-safe."""
        with self._dm_lock:
            age = max(0.0, time.time() - self._last_fetch_ts)
            return (self._dm_re[:], self._dm_im[:], age)

    def get_oracle_state(self) -> dict:
        """Return current oracle state (thread-safe)."""
        with self._oracle_state_lock:
            return dict(self._oracle_state)


_LIVE_RPC_ORACLE = LiveRPCOracleSnapshot()


def _start_oracle_background_poll(interval_s: float = 15.0) -> None:
    """Soft background poll — keeps _LIVE_RPC_ORACLE cache warm.
    Uses a long interval (15s default) so it never competes with mining.
    Non-blocking: skips if oracle is slow; mining never waits for this.
    """
    import threading as _obgt, time as _obgtime

    def _poll():
        while True:
            try:
                # Only refresh if cache is stale
                _, _, _age = _LIVE_RPC_ORACLE.get_oracle_dm()
                if _age > interval_s:
                    _LIVE_RPC_ORACLE.fetch_snapshot(timeout_s=4.0)
            except Exception:
                pass
            _obgtime.sleep(interval_s)

    t = _obgt.Thread(target=_poll, daemon=True, name="OracleBackgroundPoll")
    t.start()
    return t


_ORACLE_BG_POLL = _start_oracle_background_poll()


class WStateConsensus:
    """BFT median consensus over peer W-state measurements.
    Aggregates measurements from P2P network + own measurement.
    Uses C qtcl_consensus_compute for median/DM-mean/quorum-hash.
    """

    MAX_MEASUREMENTS = 64
    MEASUREMENT_TTL = 120.0  # seconds before measurement is stale

    def __init__(self):
        self._measurements: list = []  # list of (timestamp, QtclOracleMeasurement)
        self._lock = threading.Lock()

    def ingest_peer_measurement(self, m: QtclOracleMeasurement) -> None:
        with self._lock:
            now = time.time()
            self._measurements = [
                (ts, mm)
                for ts, mm in self._measurements
                if now - ts < self.MEASUREMENT_TTL
            ][-self.MAX_MEASUREMENTS :]
            self._measurements.append((time.time(), m))

    def ingest_c_measurement_bytes(self, raw: bytes) -> None:
        """Ingest raw QtclWStateMeasurement bytes from C callback."""
        import struct as _st

        if len(raw) < 128:
            return
        try:
            ch, pq0, pq_curr, pq_last = _st.unpack_from("<IIII", raw, 16)
            w_fid, coh, pur = _st.unpack_from("<ddd", raw, 32)
            triangle = HyperbolicTriangle.compute(pq0, pq_curr, pq_last)
            m = QtclOracleMeasurement(
                chain_height=ch,
                pq0=pq0,
                pq_curr=pq_curr,
                pq_last=pq_last,
                triangle=triangle,
                dm_re=[0.0] * 64,
                dm_im=[0.0] * 64,
                fidelity_to_w3=w_fid,
                coherence=coh,
                purity=pur,
                negativity_AB=0.0,
                entropy_vn=0.0,
                discord=0.0,
                auth_tag_hex="",
                pow_seed_bytes=b"\x00" * 32,
            )
            dm_offset = 32 + 8 * 6 + 8 * 3 + 8 * 3 + 8 * 3 + 8 * 3
            if len(raw) >= dm_offset + 64 * 8 * 2:
                for i in range(64):
                    (re,) = _st.unpack_from("<d", raw, dm_offset + i * 8)
                    (im,) = _st.unpack_from("<d", raw, dm_offset + 64 * 8 + i * 8)
                    m.dm_re[i] = re
                    m.dm_im[i] = im
            self.ingest_peer_measurement(m)
        except Exception as _e:
            _EXP_LOG.debug(f"[CONSENSUS] c_bytes parse: {_e}")

    def compute(
        self,
        own_measurement: QtclOracleMeasurement,
    ) -> dict:
        """Compute BFT consensus.  Returns dict with all consensus fields."""
        import hashlib as _hl

        with self._lock:
            peer_ms = [m for ts, m in self._measurements]
        all_ms = [own_measurement] + peer_ms
        n = len(all_ms)
        fids = [m.fidelity_to_w3 for m in all_ms]
        fids.sort()
        med = fids[n // 2] if n % 2 else (fids[n // 2 - 1] + fids[n // 2]) / 2
        quorum_hash = _hl.sha3_256(
            b"".join(
                bytes.fromhex(m.auth_tag_hex)
                if m.auth_tag_hex and len(m.auth_tag_hex) == 64
                else b"\x00" * 32
                for m in all_ms
            )
        ).digest()
        pow_seed = _hl.sha3_256(b"QTCL_SEED_v2:" + quorum_hash).digest()
        return {
            "median_fidelity": med,
            "median_coherence": sum(m.coherence for m in all_ms) / n,
            "median_purity": sum(m.purity for m in all_ms) / n,
            "median_negativity": 0.0,
            "median_entropy": 0.0,
            "hyp_area_median": sum(m.triangle.area for m in all_ms) / n,
            "quorum_hash_hex": quorum_hash.hex(),
            "peer_count": n,
            "agreement_score": 1.0 - (max(fids) - min(fids)) if n > 1 else 1.0,
            "chain_height": max(m.chain_height for m in all_ms),
            "pow_seed": pow_seed,
        }


# ═══════════════════════════════════════════════════════════════════════════════
# CHAIN ADVANCE EVENT SYSTEM — Cathedral-Grade Mining Loop Interruption
# ═══════════════════════════════════════════════════════════════════════════════
# Signals mining loop to abort immediately when chain advances via P2P

_CHAIN_ADVANCE_EVENT = threading.Event()  # Signals chain advancement
_CHAIN_ADVANCE_HEIGHT = [0]  # Atomic height storage
_CHAIN_ADVANCE_LOCK = threading.Lock()  # Thread-safe synchronization


def signal_chain_advance(new_height: int) -> None:
    """Signal that chain has advanced to new_height. Thread-safe."""
    with _CHAIN_ADVANCE_LOCK:
        if new_height > _CHAIN_ADVANCE_HEIGHT[0]:
            _CHAIN_ADVANCE_HEIGHT[0] = new_height
            _CHAIN_ADVANCE_EVENT.set()
            _EXP_LOG.info(f"[CHAIN-ADVANCE] ⚡ Signaled: h={new_height}")


def check_chain_advance() -> int:
    """Check if chain advance was signaled. Returns new height or 0."""
    if _CHAIN_ADVANCE_EVENT.is_set():
        _CHAIN_ADVANCE_EVENT.clear()
        with _CHAIN_ADVANCE_LOCK:
            return _CHAIN_ADVANCE_HEIGHT[0]
    return 0


def reset_chain_advance() -> None:
    """Reset chain advance signal. Called after mining loop processes advance."""
    _CHAIN_ADVANCE_EVENT.clear()
    with _CHAIN_ADVANCE_LOCK:
        _CHAIN_ADVANCE_HEIGHT[0] = 0


class HeightMonitor:
    """
    Event-driven height monitor - watches blocks table for changes.
    When new block inserted, broadcasts height change + full block data to all peers via P2P.
    """

    def __init__(self, db_path: str, p2p_node):
        self._db_path = db_path
        self._p2p_node = p2p_node
        self._last_height = 0
        self._stop = threading.Event()
        self._check_event = threading.Event()
        self._thread = None

    def start(self) -> None:
        """Start the height monitor thread."""
        self._stop.clear()
        self._check_event.clear()
        self._thread = threading.Thread(
            target=self._watch_loop, daemon=True, name="HeightMonitor"
        )
        self._thread.start()
        _EXP_LOG.info("[HEIGHT-MONITOR] Started watching blocks table")

    def stop(self) -> None:
        """Stop the height monitor thread."""
        self._stop.set()
        self._check_event.set()
        if self._thread and self._thread.is_alive():
            self._thread.join(timeout=2.0)

    def check_now(self) -> None:
        """Trigger an immediate check (called by _rpc_submitBlock after persist)."""
        self._check_event.set()

    def _get_latest_height(self) -> int:
        """Query the current max height from blocks table."""
        try:
            import sqlite3

            conn = sqlite3.connect(str(self._db_path), timeout=5.0)
            cur = conn.execute("SELECT MAX(height) FROM blocks")
            row = cur.fetchone()
            conn.close()
            return int(row[0]) if row and row[0] else 0
        except Exception as e:
            _EXP_LOG.debug(f"[HEIGHT-MONITOR] Height query failed: {e}")
            return 0

    def _get_block_at_height(self, height: int):
        """Get full block data at specific height."""
        try:
            import sqlite3, json

            conn = sqlite3.connect(str(self._db_path), timeout=5.0)
            cur = conn.execute(
                "SELECT data FROM blocks WHERE height = ? LIMIT 1", (height,)
            )
            row = cur.fetchone()
            conn.close()
            if row and row[0]:
                return json.loads(row[0])
            return None
        except Exception as e:
            _EXP_LOG.debug(f"[HEIGHT-MONITOR] Block fetch failed: {e}")
            return None

    def _broadcast_to_peers(self, height: int, block: dict) -> None:
        """Broadcast height change + full block data to all P2P peers."""
        try:
            if not self._p2p_node:
                return
            payload = {
                "event": "height_change",
                "height": height,
                "block_hash": block.get("hash") or block.get("block_hash", ""),
                "parent_hash": block.get("parent_hash", ""),
                "timestamp": block.get("timestamp", int(time.time())),
                "miner_address": block.get("miner_address") or block.get("miner", ""),
                "difficulty": block.get("difficulty", 0),
                "nonce": block.get("nonce", 0),
                "merkle_root": block.get("merkle_root")
                or block.get("transactions_root", ""),
                "tx_count": block.get("tx_count", 0),
                "transactions": block.get("transactions") or block.get("txs", []),
                "broadcast_at": time.time(),
            }
            if hasattr(self._p2p_node, "gossip") and self._p2p_node.gossip:
                self._p2p_node.gossip.relay("height_change", payload)
                _EXP_LOG.info(
                    f"[HEIGHT-MONITOR] Broadcast height={height} to peers via gossip"
                )
            if hasattr(self._p2p_node, "broadcast_inv"):
                peers = (
                    self._p2p_node.get_peers()
                    if hasattr(self._p2p_node, "get_peers")
                    else []
                )
                if peers:
                    bhash = payload["block_hash"]
                    miner = payload["miner_address"]
                    self._p2p_node.broadcast_inv(bhash, height, miner, peers)
                    _EXP_LOG.info(
                        f"[HEIGHT-MONITOR] Broadcast height={height} to {len(peers)} peers"
                    )
            signal_chain_advance(height)
        except Exception as e:
            _EXP_LOG.debug(f"[HEIGHT-MONITOR] Broadcast failed: {e}")

    def _watch_loop(self) -> None:
        """Main watch loop - polls blocks table for changes."""
        self._last_height = self._get_latest_height()
        _EXP_LOG.info(f"[HEIGHT-MONITOR] Initial height: {self._last_height}")
        while not self._stop.is_set():
            try:
                triggered = self._check_event.wait(timeout=2.0)
                self._check_event.clear()
                if self._stop.is_set():
                    break
                current_height = self._get_latest_height()
                if current_height > self._last_height:
                    _EXP_LOG.info(
                        f"[HEIGHT-MONITOR] Height changed: {self._last_height} -> {current_height}"
                    )
                    for h in range(self._last_height + 1, current_height + 1):
                        block = self._get_block_at_height(h)
                        if block:
                            self._broadcast_to_peers(h, block)
                        else:
                            _EXP_LOG.warning(
                                f"[HEIGHT-MONITOR] Block h={h} not found in DB"
                            )
                    self._last_height = current_height
            except Exception as e:
                _EXP_LOG.debug(f"[HEIGHT-MONITOR] Watch loop error: {e}")
                import time

                time.sleep(1.0)
        _EXP_LOG.info("[HEIGHT-MONITOR] Stopped")


class QtclP2PNode:
    """Thin Python lifecycle manager over the C P2P library.
    Starts/stops the C engine, registers the cffi callback,
    routes P2P measurement events to WStateConsensus.
    Bootstrap: connects to Koyeb server /api/p2p/peer_exchange for peer list.
    """

    DEFAULT_PORT = 9091
    BOOTSTRAP_PEERS: list = []

    def __init__(
        self,
        node_id: str,
        port: int = DEFAULT_PORT,
        bootstrap_peers: list = None,
    ):
        self._node_id = node_id
        self._port = port
        self._bootstrap = bootstrap_peers or self.BOOTSTRAP_PEERS
        self._consensus: Optional[WStateConsensus] = None
        self._stop: threading.Event = threading.Event()
        self._started = False
        self._drain_thread: Optional[threading.Thread] = None
        self._rpc_client: Optional["ServerRPCClient"] = None  # B5: injected by start()
        self._height_monitor: Optional[HeightMonitor] = (
            None  # Event-driven height monitoring
        )

    def start(
        self,
        consensus: WStateConsensus,
    ) -> bool:
        global _C_P2P_CALLBACK
        self._oracle = oracle_engine
        self._consensus = consensus
        # B5: materialise _rpc_client — ServerRPCClient with Koyeb endpoint — enables _peer_exchange discovery
        if self._rpc_client is None:
            try:
                self._rpc_client = ServerRPCClient(server_url=_ORACLE_BASE_URL)
            except Exception as _rpc_init_e:
                _EXP_LOG.debug(f"[P2P] _rpc_client init failed: {_rpc_init_e}")
        for host, port in self._bootstrap:
            try:
                _EXP_LOG.info(f"[P2P] Bootstrap connect → {host}:{port}")
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P] Bootstrap {host}:{port} failed: {_e}")
        try:
            import sqlite3 as _p2p_rsq

            _p2p_rdb = (
                __import__("pathlib").Path.home() / "qtcl-miner" / "qtcl_p2p_peers.db"
            )
            if _p2p_rdb.exists():
                with _p2p_rsq.connect(str(_p2p_rdb)) as _rc:
                    _rc.row_factory = _p2p_rsq.Row
                    rows = _rc.execute(
                        """SELECT host, port FROM known_peers
                        WHERE last_seen > ? ORDER BY last_seen DESC LIMIT 32""",
                        (int(__import__("time").time()) - 86400,),
                    ).fetchall()
                for row in rows:
                    try:
                        pass
                    except Exception:
                        pass
                if rows:
                    _EXP_LOG.info(
                        f"[P2P] ↩ Reconnecting to {len(rows)} known peers from DB"
                    )
        except Exception as _pe:
            _EXP_LOG.debug(f"[P2P] peer DB reload: {_pe}")
        self._stop.clear()
        self._drain_thread = threading.Thread(
            target=self._drain_loop, daemon=True, name="P2P-Drain"
        )
        self._drain_thread.start()
        self._stop.clear()
        threading.Thread(
            target=self._peer_exchange, daemon=True, name="P2P-Discovery"
        ).start()
        self._started = True
        _EXP_LOG.info(f"[P2P] ✅ C P2P layer active  port={self._port}")
        # Start HeightMonitor for event-driven height broadcasting
        self._height_monitor = HeightMonitor(_DB_PATH, self)
        self._height_monitor.start()
        # ── Load+connect peers from SQLite DB ───────────────────────────────
        return True

    def _drain_loop(self) -> None:
        """Python thread: drain P2P event queue and route to handlers.
        Event types (mirrors qtcl_accel C layer constants):
          1 = PEER_CONNECTED
          2 = PEER_DISCONNECTED
          3 = WSTATE_RECV       — W-state measurement from peer
          4 = BLOCK_ANNOUNCE    — peer announcing a new block (height + hash)
          5 = HEIGHT_UPDATE     — peer chain tip update
        """
        import struct as _st, json as _j

        _local_tip = 0  # tracks highest chain_height seen from any peer
        while not self._stop.is_set():
            try:
                event_type, raw = _P2P_EVENT_QUEUE.get(timeout=1.0)
                if event_type == 3:  # WSTATE_RECV — peer W-state measurement
                    if self._consensus:
                        self._consensus.ingest_c_measurement_bytes(raw)
                    try:
                        import struct as _wst_st

                        if len(raw) >= 4:
                            _peer_h = _wst_st.unpack_from("<I", raw, 0)[0]
                            if _peer_h > _local_tip + 1:
                                _EXP_LOG.info(
                                    f"[P2P] 📡 Peer chain h={_peer_h} "
                                    f"(local known={_local_tip}) — tip ahead"
                                )
                                _local_tip = _peer_h
                    except Exception:
                        pass
                elif event_type == 4:  # BLOCK_ANNOUNCE — peer found a block
                    try:
                        height = 0
                        if len(raw) >= 36:
                            height = _st.unpack_from("<I", raw, 0)[0]
                            blk_hash = raw[4:36].hex()
                        elif len(raw) > 4:
                            jd = _j.loads(raw.decode("utf-8", errors="replace"))
                            height = int(
                                jd.get("height") or jd.get("block_height") or 0
                            )
                        if height > 0 and height > _local_tip:
                            _local_tip = height
                            # ── CHAIN ADVANCE SIGNAL — interrupt mining loop ──
                            signal_chain_advance(height)
                            _EXP_LOG.info(
                                f"[P2P] ⚡ Block announce h={height} "
                                f"→ Mining abort signaled, chain advance armed"
                            )
                    except Exception as _be:
                        _EXP_LOG.debug(f"[P2P] block_announce parse: {_be}")
                elif event_type == 5:  # HEIGHT_UPDATE — peer chain tip
                    try:
                        if len(raw) >= 4:
                            h = _st.unpack_from("<I", raw, 0)[0]
                            if h > _local_tip:
                                _local_tip = h
                                _EXP_LOG.debug(f"[P2P] ↑ Chain tip h={h} → C updated")
                    except Exception:
                        pass
                elif event_type == 7:  # DMPOOL_RECV — peer sent DM pool entry
                    _EXP_LOG.debug("[P2P] 🧬 DM pool entry received from peer")
                    try:
                        _dm_pool_drain_once(_DM_POOL_DB_PATH)
                    except Exception:
                        pass
                elif event_type == 8:  # CHAIN_RESET gossip received
                    payload_str = (
                        raw.decode("utf-8", errors="replace")
                        if isinstance(raw, bytes)
                        else str(raw)
                    )
                    _EXP_LOG.warning(
                        f"[P2P] ⚡ chain_reset gossip from peer: {payload_str[:80]}"
                    )
                    try:
                        import json as _pj

                        _rdata = _pj.loads(payload_str)
                        if int(_rdata.get("new_height", -1)) == 0:
                            _RESET_PERFORMED.set()
                    except Exception:
                        pass
                elif event_type == 9:  # OUROBOROS — self-measurement (500ms cadence)
                    if self._consensus and len(raw) >= 128:
                        try:
                            self._consensus.ingest_c_measurement_bytes(raw)
                        except Exception:
                            pass
                    try:
                        _dm_pool_drain_once(_DM_POOL_DB_PATH)
                    except Exception:
                        pass
                elif event_type == 10:  # BLOCK_SOLVED_SERVER — server broadcast
                    try:
                        _server_payload = json.loads(
                            raw.decode("utf-8", errors="replace")
                        )
                        _srv_height = _server_payload.get("height", 0)
                        _srv_hash = _server_payload.get("block_hash", "")
                        if _srv_height > 0:
                            # Signal immediate chain advance
                            signal_chain_advance(_srv_height)
                            # Persist to local database
                            try:
                                _local_db = LocalBlockchainDB(name="qtcl")
                                _local_db.insert_block(_srv_height, _server_payload)
                                _EXP_LOG.info(
                                    f"[P2P] 💾 Server block h={_srv_height} persisted locally"
                                )
                            except Exception as _persist_err:
                                _EXP_LOG.debug(
                                    f"[P2P] Local persistence: {_persist_err}"
                                )
                            _EXP_LOG.info(
                                f"[P2P] 🎯 BLOCK_SOLVED_SERVER h={_srv_height} "
                                f"hash={_srv_hash[:16]}… → mining abort signaled"
                            )
                    except Exception as _be:
                        _EXP_LOG.debug(f"[P2P] block_solved_server parse: {_be}")
                elif event_type == 1:  # PEER_CONNECTED
                    try:
                        import struct as _pc_st

                        if (
                            len(raw) >= 100
                        ):  # fd(4)+host(64)+port(2)+active(4)+handshake(4)+issse(4)+...
                            pass
                    except Exception:
                        pass
                    peer_data = {}
                    try:
                        _raw_host = (
                            raw[4:68].rstrip(b"\x00").decode("ascii", "replace").strip()
                            if len(raw) >= 68
                            else ""
                        )
                        _raw_port = (
                            int.from_bytes(raw[68:70], "little")
                            if len(raw) >= 70
                            else 9091
                        )
                        peer_data = {
                            "host": _raw_host,
                            "port": _raw_port if _raw_port > 0 else 9091,
                        }
                    except Exception:
                        peer_data = {}
                    _ph_key = f"{peer_data.get('host', '')}:{peer_data.get('port', 0)}"
                    _now_ns = __import__("time").time()
                    if not hasattr(self, "_logged_peers"):
                        self._logged_peers = {}
                    if (
                        _ph_key not in self._logged_peers
                        or _now_ns - self._logged_peers.get(_ph_key, 0) > 30.0
                    ):
                        self._logged_peers[_ph_key] = _now_ns
                        _nc = self.peer_count
                        if _nc <= 4:
                            _EXP_LOG.info(f"[P2P] ✅ Peer connected  connected={_nc}")
                        else:
                            _EXP_LOG.debug(f"[P2P] Peer connected  connected={_nc}")
                    # Subscribe to peer's local oracle via RPC polling for DM aggregation
                    if peer_data.get("host") and peer_data["host"] not in (
                        "",
                        "127.0.0.1",
                        "localhost",
                    ):
                        _ph = peer_data["host"]
                        _pp = int(peer_data.get("port", 9091))
                        _threading.Thread(
                            target=_subscribe_peer_oracle_rpc,
                            args=(_ph, _pp),
                            daemon=True,
                            name=f"PeerOracle-{_ph}",
                        ).start()
                elif event_type == 2:  # PEER_DISCONNECTED
                    _EXP_LOG.debug(f"[P2P] Peer disconnected  peers={self.peer_count}")
            except queue.Empty:
                continue
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P] drain_loop: {_e}")

    def _peer_exchange(self) -> None:
        """
        Priority-ordered peer discovery loop. Runs at startup then every 90s.
        Priority on each cycle:
          1. LOCAL  sqlite p2p_peers table  (freshest — zero latency)
          2. P2P    already-connected peers' known-peer gossip  (C layer)
          3. KOYEB  /api/p2p/peer_exchange + /api/peers/list  (only if local is
                    stale OR we have fewer than 2 connected peers)
        DM freshness gate: if the oracle DM age < 30s we have a live SSE source
        and local P2P peers are preferred.  If DM age > 60s the oracle is stale
        so we aggressively re-query koyeb/supabase for fresh peers.
        Every new peer is persisted back to local database immediately.
        ❤️  The more peers the more entangled the network
        """
        import json as _pj, time as _pt, sqlite3 as _psq

        _oracle_url = ENTROPY_SERVER_URL
        _connected_this_cycle: set = set()

        def _connect_peer(host, port):
            return False

        def _load_local_peers(max_age_s=7200):
            """Read p2p_peers from local sqlite database, skip already-connected."""
            try:
                _already = set()
                cutoff = int(_pt.time()) - max_age_s
                with _psq.connect(_db_path, timeout=3) as _c:
                    rows = _c.execute(
                        """
                        SELECT host, port FROM p2p_peers
                        WHERE last_seen_at > ? AND ban_score < 100
                          AND host NOT IN ('127.0.0.1','localhost','')
                        ORDER BY chain_height DESC, last_seen_at DESC
                        LIMIT 64
                    """,
                        (cutoff,),
                    ).fetchall()
                return [(r[0], r[1]) for r in rows if r[0]]
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P] local DB read: {_e}")
                return []

        def _fetch_koyeb_peers():
            """POST to koyeb peer_exchange + peers/list. Returns raw peer dicts."""
            from urllib.request import Request as _Rq, urlopen as _uo

            peers = []
            try:
                # ServerRPCClient.call() returns full envelope {jsonrpc, result, id}
                # result shape: {"peers": [...], "count": N} — never a bare list
                rpc_resp = (
                    self._rpc_client.call("qtcl_getPeers", {"limit": 50})
                    if (hasattr(self, "_rpc_client") and self._rpc_client)
                    else None
                )
                if rpc_resp and "result" in rpc_resp:
                    _r = rpc_resp["result"]
                    _peer_list = (
                        _r.get("peers", [])
                        if isinstance(_r, dict)
                        else _r
                        if isinstance(_r, list)
                        else []
                    )
                    peers += [p for p in _peer_list if isinstance(p, dict)]
            except Exception:
                pass
            return peers

        _pe_cycle = 0
        n_connected = 0  # Bug #7: was undefined
        _lo_ts = 0.0
        while not self._stop.is_set():
            try:
                _pe_cycle += 1
                _connected_this_cycle.clear()  # reset per-cycle dedup set
                # peer count via PeerManager if available, else zero
                _n_total = len(
                    getattr(self, "peer_mgr", None)
                    and getattr(self.peer_mgr, "peers", {})
                    or {}
                )
                if _n_total > n_connected:
                    n_connected = max(n_connected, _n_total // 2)
                _lo_ts = time.time()
                dm_age = _pt.time() - _lo_ts
                dm_fresh = _lo_ts > 1e9 and dm_age < 30.0 and dm_age < 86400
                need_peers = n_connected < 4  # want at least 4 peers
                dm_stale = (not dm_fresh) or dm_age > 60.0
                new_connections = 0
                # ── Priority 1: local sqlite database ──────────────────────────
                local_peers = _load_local_peers(max_age_s=7200)
                if local_peers:
                    for host, port in local_peers:
                        if _connect_peer(host, port):
                            new_connections += 1
                    _dm_age_str = (
                        f"{dm_age:.0f}s"
                        if dm_fresh or (dm_age < 86400 and _lo_ts > 1e9)
                        else "cold"
                    )
                    if local_peers:
                        _already_n = (
                            len(local_peers)
                            - new_connections
                            - (len(local_peers) - len([p for p in local_peers if p]))
                        )
                        _EXP_LOG.info(
                            f"[P2P] 🗄️  DB: {new_connections} new / {len(local_peers)} stored "
                            f"(dm_age={_dm_age_str})"
                        )
                if need_peers or dm_stale or not local_peers:
                    koyeb_peers = _fetch_koyeb_peers()
                    kc = 0
                    for p in koyeb_peers[:48]:
                        host = str(
                            p.get("host") or p.get("ip_address") or p.get("ip") or ""
                        )
                        port = int(p.get("port") or 9091)
                        if _connect_peer(host, port):
                            kc += 1
                    new_connections += kc
                    if kc:
                        _EXP_LOG.info(
                            f"[P2P] 🌐 koyeb: {kc}/{len(koyeb_peers)} new peers "
                            f"(need_peers={need_peers}, dm_stale={dm_stale})"
                        )
                else:
                    if _pe_cycle % 5 == 0:
                        try:
                            _my_ext = _MY_IP or "localhost"
                            _reg_payload = {
                                "external_addr": f"{_my_ext}:{self._port}",
                                "node_id": self._node_id,
                                "pubkey": self._node_id,
                                "chain_height": n_connected,
                            }
                            # Register peer via RPC — pass dict directly (not JSON string)
                            if hasattr(self, "_rpc_client") and self._rpc_client:
                                self._rpc_client.call(
                                    "qtcl_registerPeer", [_reg_payload]
                                )
                        except Exception:
                            pass
                    _EXP_LOG.debug(
                        f"[P2P] healthy ({n_connected} peers, DM {dm_age:.0f}s) — "
                        f"local-only cycle"
                    )
                _n_total_check = _n_total  # Bug #7: was undefined
                n_now = n_connected  # Bug #7: was undefined
                if new_connections == 0 and n_connected == 0 and _n_total_check == 0:
                    _EXP_LOG.warning("[P2P] ⚠️  no peers found — retry in 30s")
                    self._stop.wait(30)
                    continue
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P] discovery cycle: {_e}")
                n_now = n_connected  # ensure n_now is always defined after except
            if n_now == 0:
                _wait = 10  # no peers — hammer every 10s
            elif n_now < 2:
                _wait = 20  # 1 peer — try hard
            elif n_now < 4:
                _wait = 30  # getting there
            else:
                _wait = 60  # healthy — relax
            _EXP_LOG.debug(
                f"[P2P] discovery cycle {_pe_cycle}: connected={n_now} → next in {_wait}s"
            )
            self._stop.wait(_wait)

    def get_consensus_dm(self):
        """
        Pull the latest N-peer consensus density matrix from the C layer.
        Returns (dm_re_64, dm_im_64, fidelity, height) or None if not ready.
        Consensus is computed via explicit RPC polling (qtcl_p2p_trigger_consensus)
        as fidelity²-weighted arithmetic mean over P2P_DMPOOL_SZ pool entries.
        """
        return None

    def trigger_consensus(self) -> None:
        """Force immediate DM pool recompute (normally runs every 500ms)."""
        pass

    def broadcast_chain_reset(self, genesis_hash: str = "") -> None:
        """Broadcast chain-reset to all P2P peers on 9091."""
        return

    @property
    def sse_subscriber_count(self) -> int:
        """SSE subscribers removed — RPC-only consensus model."""
        return 0

    def gossip_measurement(self, m: QtclOracleMeasurement) -> int:
        """Broadcast own measurement to all C P2P peers."""
        return 0

    def stop(self) -> None:
        self._stop.set()
