def _validate_peer_host(host: str) -> Optional[str]:
    """Validate and sanitize peer host string.

    RFC-1918 private addresses are blocked by default to prevent local-network
    confusion on cloud deployments.  Set env var P2P_ALLOW_LAN=1 to permit
    RFC-1918 peers (useful when running multiple miners on the same LAN or
    inside a Docker/k8s cluster).
    """
    import re

    if not host or not isinstance(host, str):
        return None
    host = host.strip()
    if not re.match(
        r"^[a-zA-Z0-9][a-zA-Z0-9\-\.]{0,253}[a-zA-Z0-9]$|^(\d{1,3}\.){3}\d{1,3}$", host
    ):
        return None
    parts = host.split(".")
    if len(parts) != 4:
        # Hostname (not dotted-quad) — always allow
        return host
    try:
        octets = [int(p) for p in parts]
    except ValueError:
        return None
    if any(o > 255 for o in octets):
        return None
    # Loopback and unspecified — always block
    if octets[0] == 127 or octets[0] == 0:
        return None
    # RFC-1918 — block unless P2P_ALLOW_LAN=1
    _allow_lan = os.getenv("P2P_ALLOW_LAN", "0").strip() in ("1", "true", "yes")
    if not _allow_lan:
        if octets[0] == 10:
            return None
        if octets[0] == 172 and 16 <= octets[1] <= 31:
            return None
        if octets[0] == 192 and octets[1] == 168:
            return None
    return host


def _validate_port(port: Any) -> Optional[int]:
    """Validate port number."""
    try:
        p = int(port)
        if 1 <= p <= 65535:
            return p
    except (ValueError, TypeError):
        pass
    return None


def _validate_node_id(node_id: str) -> bool:
    """Validate node_id is 64 lowercase hex characters."""
    if not node_id or not isinstance(node_id, str):
        return False
    if len(node_id) != 64:
        return False
    return all(c in "0123456789abcdef" for c in node_id)


def _get_machine_salt() -> str:
    """Return stable per-machine salt used to derive node_id.
    Never changes across reboots on the same machine.

    Android/Termux: uuid.getnode() returns randomized MAC — falls through
    to build fingerprint, serial number, or Termux persistent salt file.
    ❤️  I love you.
    """
    # Priority 1: /etc/machine-id (desktop Linux, stable systemd ID)
    try:
        mid = Path("/etc/machine-id").read_text().strip()
        if mid and len(mid) >= 8:
            return mid
    except Exception:
        pass

    # Priority 2: Android build fingerprint — globally unique per device image
    try:
        import subprocess as _sp2

        _fp = (
            _sp2.check_output(
                ["getprop", "ro.build.fingerprint"], stderr=_sp2.DEVNULL, timeout=2
            )
            .decode()
            .strip()
        )
        if _fp and len(_fp) > 8:
            return hashlib.sha256(f"ANDROID_FP_SALT|{_fp}".encode()).hexdigest()
    except Exception:
        pass

    # Priority 3: Android serial number
    try:
        import subprocess as _sp3

        _ser = (
            _sp3.check_output(
                ["getprop", "ro.serialno"], stderr=_sp3.DEVNULL, timeout=2
            )
            .decode()
            .strip()
        )
        if _ser and _ser not in ("", "unknown", "0"):
            return hashlib.sha256(f"ANDROID_SN_SALT|{_ser}".encode()).hexdigest()
    except Exception:
        pass

    # Priority 4: Termux persistent salt file — created once, stable forever
    # Survives app restarts, network changes, and MAC randomization
    try:
        _prefix = os.environ.get("PREFIX", "/data/data/com.termux/files/usr")
        _salt_path = Path(_prefix) / "etc" / "qtcl_machine_salt"
        if _salt_path.exists():
            _stored = _salt_path.read_text().strip()
            if _stored and len(_stored) >= 32:
                return _stored
        # Create it once with cryptographic randomness
        import secrets as _sec4

        _new_salt = _sec4.token_hex(32)  # 64-char hex
        _salt_path.parent.mkdir(parents=True, exist_ok=True)
        _salt_path.write_text(_new_salt)
        return _new_salt
    except Exception:
        pass

    # Priority 5: uuid.getnode() — valid on desktop, unreliable on Android
    try:
        import uuid as _uuid

        mac = _uuid.getnode()
        if mac and mac != (1 << 48) - 1:
            _mac_hex = format(mac, "012x")
            # Reject Android randomized prefix
            if not _mac_hex.startswith("02"):
                return _mac_hex
    except Exception:
        pass

    # Priority 6: hostname + homedir hash
    import socket as _sk

    return hashlib.sha256(
        ((_sk.gethostname() or "") + str(Path.home())).encode()
    ).hexdigest()[:32]


def _get_mac_address() -> str:
    """Return a stable 12-char lowercase hex device fingerprint.
    Used for per-device identification behind shared NAT.

    Android/Termux: MUST NOT use /sys/class/net or uuid.getnode().
    Android 10+ randomizes the MAC reported by both sources per WiFi network,
    making them useless for stable identity — even MACs that look real
    (non-02:xx prefix) are randomized per-connection since Android 12.
    We detect Android first and short-circuit to stable sources only.
    """
    import uuid as _uuid

    # ── Detect Android/Termux immediately ─────────────────────────────────────
    _on_android = False
    try:
        _on_android = (
            Path("/system/build.prop").exists()
            or Path("/data/data/com.termux").exists()
            or bool(os.environ.get("TERMUX_VERSION"))
            or bool(os.environ.get("PREFIX", "").startswith("/data/data/com.termux"))
        )
    except Exception:
        pass

    if not _on_android:
        # ── Desktop Linux: scan real NICs via /sys/class/net ──────────────────
        def _is_real(mac: str) -> bool:
            if not mac or len(mac) != 12:
                return False
            if mac in ("000000000000", "ffffffffffff"):
                return False
            # Reject locally-administered (bit 1 of first byte set = randomized/virtual)
            if int(mac[:2], 16) & 0x02:
                return False
            return all(c in "0123456789abcdef" for c in mac)

        try:
            import glob as _glob

            for _iface in sorted(_glob.glob("/sys/class/net/*/address")):
                try:
                    _mac = Path(_iface).read_text().strip().replace(":", "").lower()
                    _skip = any(
                        k in _iface
                        for k in (
                            "docker",
                            "veth",
                            "/lo/",
                            "dummy",
                            "tun",
                            "tap",
                            "virbr",
                        )
                    )
                    if not _skip and _is_real(_mac):
                        return _mac
                except Exception:
                    continue
        except Exception:
            pass

        # Desktop fallback: uuid.getnode()
        try:
            mac = _uuid.getnode()
            _mh = format(mac, "012x")
            if mac and mac != (1 << 48) - 1 and not (int(_mh[:2], 16) & 0x02):
                return _mh
        except Exception:
            pass

        # Desktop: /etc/machine-id
        try:
            mid = Path("/etc/machine-id").read_text().strip()
            if mid and len(mid) >= 8:
                return hashlib.sha256(f"MACHINE_ID|{mid}".encode()).hexdigest()[:12]
        except Exception:
            pass

    # ── Android/Termux stable fingerprint chain ────────────────────────────────
    # Priority 1: Android build fingerprint — globally unique per device image,
    # stable across reboots, network changes, and factory resets of individual apps
    try:
        import subprocess as _sp

        _fp = (
            _sp.check_output(
                ["getprop", "ro.build.fingerprint"], stderr=_sp.DEVNULL, timeout=2
            )
            .decode()
            .strip()
        )
        if _fp and len(_fp) > 8 and _fp not in ("unknown", ""):
            return hashlib.sha256(f"ANDROID_FP|{_fp}".encode()).hexdigest()[:12]
    except Exception:
        pass

    # Priority 2: Android serial number
    try:
        import subprocess as _sp2

        _ser = (
            _sp2.check_output(
                ["getprop", "ro.serialno"], stderr=_sp2.DEVNULL, timeout=2
            )
            .decode()
            .strip()
        )
        if _ser and _ser not in ("", "unknown", "0"):
            return hashlib.sha256(f"ANDROID_SN|{_ser}".encode()).hexdigest()[:12]
    except Exception:
        pass

    # Priority 3: Termux persistent identity file — created once, stable forever.
    # Survives app restarts, network changes, WiFi↔LTE handoff, and MAC randomization.
    try:
        _prefix = os.environ.get("PREFIX", "/data/data/com.termux/files/usr")
        _termux_id_path = Path(_prefix) / "etc" / "qtcl_device_id"
        if _termux_id_path.exists():
            _tid = _termux_id_path.read_text().strip()
            if _tid and len(_tid) == 12 and all(c in "0123456789abcdef" for c in _tid):
                return _tid
        import secrets as _sec

        _new_id = _sec.token_hex(6)
        _termux_id_path.parent.mkdir(parents=True, exist_ok=True)
        _termux_id_path.write_text(_new_id)
        return _new_id
    except Exception:
        pass

    # Priority 4: /etc/machine-id (present in some Termux environments)
    try:
        mid = Path("/etc/machine-id").read_text().strip()
        if mid and len(mid) >= 8:
            return hashlib.sha256(f"MACHINE_ID|{mid}".encode()).hexdigest()[:12]
    except Exception:
        pass

    # Priority 5: hostname + home dir hash (last resort, stable per user account)
    import socket as _sk

    _hostname = _sk.gethostname() or "unknown"
    _home = str(Path.home()) if Path.home() else "/tmp"
    return hashlib.sha256(f"HOST_FALLBACK|{_hostname}|{_home}".encode()).hexdigest()[
        :12
    ]


def _get_device_id(wallet_addr: str = "") -> str:
    """Compute a stable device identity: SHA-256(wallet_addr | mac_address | domain)[:64].
    This uniquely identifies a (wallet, device) pair. Two devices with the same wallet
    behind the same NAT will get DIFFERENT device_ids, enabling server-side disambiguation."""
    mac = _get_mac_address()
    _domain = "QTCL_DEVICE_IDENTITY_v1"
    _seed = f"{wallet_addr}|{mac}|{_domain}".encode()
    return hashlib.sha256(_seed).hexdigest()


def _try_lan_broadcast(p2p_node, my_mac: str, my_node_id: str) -> None:
    """Attempt to discover same-NAT peers on the LAN by probing adjacent IPs.
    Uses the local subnet (e.g., 192.168.1.x) to try direct P2P handshake."""
    import socket as _sk2

    try:
        _lan_ip = ""
        with _sk2.socket(_sk2.AF_INET, _sk2.SOCK_DGRAM) as _s:
            _s.settimeout(2)
            _s.connect(("8.8.8.8", 80))
            _lan_ip = _s.getsockname()[0]
        if not _lan_ip or _lan_ip.startswith("127."):
            return
        if not any(
            _lan_ip.startswith(p)
            for p in (
                "192.168.",
                "10.",
                "172.16.",
                "172.17.",
                "172.18.",
                "172.19.",
                "172.20.",
                "172.21.",
                "172.22.",
                "172.23.",
                "172.24.",
                "172.25.",
                "172.26.",
                "172.27.",
                "172.28.",
                "172.29.",
                "172.30.",
                "172.31.",
            )
        ):
            return
        _parts = _lan_ip.split(".")
        _subnet = ".".join(_parts[:3])
        _last = int(_parts[3])
        _probe_range = set()
        for _delta in range(-10, 11):
            _octet = (_last + _delta) % 256
            if _octet == _last:
                continue
            _probe_range.add(f"{_subnet}.{_octet}")
        for _target_ip in _probe_range:
            try:
                _hs = json.dumps(
                    {
                        "jsonrpc": "2.0",
                        "method": "qtcl_p2p_ping",
                        "params": {"nonce": secrets.token_hex(8), "height": 0},
                        "id": 99,
                    }
                ).encode()
                _req = urllib.request.Request(
                    f"http://{_target_ip}:{_P2P_PORT}/rpc",
                    data=_hs,
                    headers={"Content-Type": "application/json"},
                )
                with urllib.request.urlopen(_req, timeout=1) as _resp:
                    _result = json.loads(_resp.read())
                    if _result.get("result"):
                        logger.info(
                            f"[LAN-DISC] Found peer at {_target_ip}:{_P2P_PORT}"
                        )
                        if not any(
                            p.host == _target_ip
                            for p in p2p_node.peer_mgr.peers.values()
                        ):
                            _new = P2PPeer(_target_ip, _P2P_PORT)
                            _new.state = PeerState.CONNECTING
                            p2p_node.peer_mgr.add_peer(_new)
            except Exception:
                pass
    except Exception:
        pass


class P2PIdentity:
    """HypΓ identity for P2P node — persisted to data/p2p_identity.json"""

    def __init__(self, pubkey_bytes: bytes, privkey_bytes: bytes, pubkey_b64: str):
        self.pubkey_bytes = pubkey_bytes
        self.privkey_bytes = privkey_bytes
        self.pubkey_b64 = pubkey_b64
        self.node_id = hashlib.sha256(pubkey_bytes).hexdigest()
        self.mac_address = ""

    @classmethod
    def load_or_create(cls, path: str = None, wallet_addr: str = "") -> "P2PIdentity":
        """Load or create identity. node_id = SHA256(wallet_addr|machine_salt|domain)
        so same wallet on two machines → two distinct, restart-stable node_ids. ❤️ I love you."""
        if path is None:
            path = str(_DATA_DIR / "p2p_identity.json")
        machine_salt = _get_machine_salt()
        mac_address = _get_mac_address()
        _domain = "QTCL_P2P_IDENTITY_v2"
        _seed = f"{wallet_addr}|{machine_salt}|{_domain}".encode()
        node_id_hex = hashlib.sha256(_seed).hexdigest()
        p = Path(path)
        if p.exists():
            try:
                data = json.loads(p.read_text())
                if (
                    data.get("wallet_addr", "") == wallet_addr
                    and data.get("machine_salt", "") == machine_salt
                    and data.get("mac_address", "") == mac_address
                    and data.get("version", "") == "v2"
                ):
                    inst = cls(
                        bytes.fromhex(data["pubkey"]),
                        bytes.fromhex(data["privkey"]),
                        data["pubkey_b64"],
                    )
                    inst.node_id = (
                        node_id_hex  # always recompute — never trust stored node_id
                    )
                    inst.mac_address = mac_address
                    return inst
                # stale v1 or mismatched wallet/machine — regenerate
            except Exception:
                pass
        pub = secrets.token_bytes(32)
        priv = secrets.token_bytes(32)
        b64 = base64.b64encode(pub).decode()
        data = {
            "pubkey": pub.hex(),
            "privkey": priv.hex(),
            "pubkey_b64": b64,
            "wallet_addr": wallet_addr,
            "machine_salt": machine_salt,
            "mac_address": mac_address,
            "version": "v2",
        }
        try:
            p.parent.mkdir(parents=True, exist_ok=True)
            p.write_text(json.dumps(data))
        except Exception:
            pass
        inst = cls(pub, priv, b64)
        inst.node_id = node_id_hex
        inst.mac_address = mac_address
        return inst


class LRUCache:
    """Thread-safe LRU cache for seen blocks/txs"""

    def __init__(self, size: int):
        self.size = size
        self.cache = {}
        self.order = []
        self.lock = threading.Lock()

    def add(self, key: str) -> None:
        with self.lock:
            if key in self.cache:
                self.order.remove(key)
            elif len(self.cache) >= self.size:
                oldest = self.order.pop(0)
                del self.cache[oldest]
            self.cache[key] = True
            self.order.append(key)

    def contains(self, key: str) -> bool:
        with self.lock:
            return key in self.cache


class SessionManager:
    """HMAC session token manager"""

    def __init__(self):
        self.sessions = {}
        self.lock = threading.Lock()

    def create(self, node_id: str, secret: bytes) -> Tuple[str, int]:
        token = secrets.token_hex(32)
        expiry = int(time.time()) + _P2P_SESSION_TTL
        with self.lock:
            self.sessions[token] = {
                "node_id": node_id,
                "expiry": expiry,
                "secret": secret,
            }
        return token, expiry

    def verify(self, token: str, node_id: str) -> bool:
        with self.lock:
            sess = self.sessions.get(token)
            if not sess:
                return False
            if time.time() > sess["expiry"]:
                del self.sessions[token]
                return False
            return sess["node_id"] == node_id

    def cleanup(self):
        with self.lock:
            now = time.time()
            expired = [t for t, s in self.sessions.items() if now > s["expiry"]]
            for t in expired:
                del self.sessions[t]


class MeshNetRateLimiter:
    """
    Advanced rate limiter for the QTCL meshnet.

    Features:
    - Per-MAC token bucket (prevents single-device flood)
    - Per-node_id token bucket (prevents identity rotation)
    - HypΓ proof-of-work challenge for new connections
    - Adaptive rate: scales down during attack, scales up during calm
    - Burst allowance for legitimate high-throughput nodes
    - Bloom-filter dedup window (rejects duplicate requests within 60s)

    Rate limits (requests per second):
        handshake          1/s per IP        New connections
        block_submit       2/s per node      Block proposals
        tx_submit          10/s per node     Transaction relay
        ping               30/s per node     Keep-alive
        inventory          5/s per node      Bloom filter exchange
        general            60/s per node     Other RPC methods
    """

    DEFAULT_RATES = {
        "handshake": 1.0,
        "block_submit": 2.0,
        "tx_submit": 10.0,
        "ping": 30.0,
        "inventory": 5.0,
        "general": 60.0,
    }

    # PoW difficulty for handshake (number of leading zero bits required)
    HANDSHAKE_POW_BITS = 16  # ~65k hashes, trivial for real peers, costly for spam

    def __init__(self):
        # Per-MAC token buckets: mac -> {method -> TokenBucket}
        self._mac_buckets = {}
        # Per-node_id token buckets: node_id -> {method -> TokenBucket}
        self._node_buckets = {}
        # Per-IP token buckets: ip -> {method -> TokenBucket}
        self._ip_buckets = {}
        # Dedup bloom filter: request_hash -> timestamp
        self._seen_requests = LRUCache(50000)
        # Adaptive rate multiplier (scales down during attacks)
        self._rate_multiplier = 1.0
        self._attack_detector = 0  # consecutive rate violations
        self._lock = threading.Lock()

    class _TokenBucket:
        """Simple token bucket rate limiter."""

        def __init__(self, rate: float, burst: int = None):
            self.rate = rate
            self.burst = burst or int(rate * 2)  # 2s of burst
            self.tokens = float(self.burst)
            self.last_refill = time.time()

        def allow(self) -> bool:
            now = time.time()
            elapsed = now - self.last_refill
            self.tokens = min(self.burst, self.tokens + elapsed * self.rate)
            self.last_refill = now
            if self.tokens >= 1.0:
                self.tokens -= 1.0
                return True
            return False

        def peek(self) -> float:
            """Check available tokens without consuming."""
            now = time.time()
            elapsed = now - self.last_refill
            return min(self.burst, self.tokens + elapsed * self.rate)

    def _get_bucket(self, buckets: dict, key: str, method: str) -> "_TokenBucket":
        """Get or create a token bucket for (key, method)."""
        if key not in buckets:
            buckets[key] = {}
        if method not in buckets[key]:
            rate = self.DEFAULT_RATES.get(method, self.DEFAULT_RATES["general"])
            rate *= self._rate_multiplier  # apply adaptive scaling
            burst = int(rate * 2)
            buckets[key][method] = self._TokenBucket(rate, burst)
        return buckets[key][method]

    def allow(
        self, method: str, ip: str = "", node_id: str = "", mac: str = ""
    ) -> tuple:
        """
        Check if a request is allowed under rate limits.

        Returns: (allowed: bool, reason: str)
        """
        # Map RPC method to rate limit category
        if method == "qtcl_p2p_handshake":
            category = "handshake"
        elif method in ("qtcl_p2p_ping", "qtcl_p2p_pong", "qtcl_dht_ping"):
            category = "ping"
        elif method in (
            "qtcl_p2p_inv",
            "qtcl_p2p_getData",
            "qtcl_p2p_getMempoolFilter",
            "qtcl_p2p_getMissingTxs",
            "qtcl_p2p_getBlocks",
        ):
            category = "inventory"
        elif method == "qtcl_p2p_pushBlock":
            category = "block_submit"
        elif method == "qtcl_p2p_pushTx":
            category = "tx_submit"
        else:
            category = "general"

        with self._lock:
            # Check dedup first (for non-ping methods)
            if category not in ("ping", "general"):
                request_key = f"{ip}:{node_id}:{method}:{int(time.time())}"
                request_hash = hashlib.sha256(request_key.encode()).hexdigest()[:16]
                if self._seen_requests.contains(request_hash):
                    return False, "duplicate_request"
                self._seen_requests.add(request_hash)

            # Check all applicable buckets
            checks = []
            if ip:
                checks.append(("ip", self._ip_buckets, ip))
            if node_id:
                checks.append(("node", self._node_buckets, node_id))
            if mac:
                checks.append(("mac", self._mac_buckets, mac))

            for bucket_type, buckets, key in checks:
                bucket = self._get_bucket(buckets, key, category)
                if not bucket.allow():
                    self._attack_detector = min(100, self._attack_detector + 1)
                    # Scale down rate during attacks
                    if self._attack_detector > 10:
                        self._rate_multiplier = max(
                            0.1, 1.0 - (self._attack_detector * 0.05)
                        )
                    return False, f"rate_limit_{bucket_type}"

            # Attack cooldown: if no violations for 60s, reset
            self._attack_detector = max(0, self._attack_detector - 1)
            if self._attack_detector == 0:
                self._rate_multiplier = min(1.0, self._rate_multiplier + 0.01)

            return True, "allowed"

    def verify_handshake_pow(self, challenge: dict, response: dict) -> bool:
        """
        Verify a handshake proof-of-work challenge.

        The connecting peer must compute SHA256(challenge_nonce + pow_nonce)
        such that the result has at least HANDSHAKE_POW_BITS leading zeros.

        This prevents automated connection floods from botnets.
        """
        nonce = response.get("pow_nonce", "")
        challenge_nonce = challenge.get("challenge_nonce", "")
        if not nonce or not challenge_nonce:
            return False
        combined = f"{challenge_nonce}{nonce}".encode()
        result = hashlib.sha256(combined).digest()
        # Count leading zero bits
        zero_bits = 0
        for byte in result:
            if byte == 0:
                zero_bits += 8
            else:
                zero_bits += (byte ^ (byte - 1)).bit_length() - 1
                break
        return zero_bits >= self.HANDSHAKE_POW_BITS

    def create_handshake_challenge(self) -> dict:
        """Create a proof-of-work challenge for a connecting peer."""
        challenge_nonce = secrets.token_hex(16)
        difficulty = self.HANDSHAKE_POW_BITS
        return {
            "challenge_nonce": challenge_nonce,
            "difficulty": difficulty,
            "timestamp": int(time.time()),
        }

    def solve_handshake_challenge(self, challenge: dict) -> dict:
        """Solve a handshake PoW challenge (returns the nonce)."""
        challenge_nonce = challenge["challenge_nonce"]
        difficulty = challenge.get("difficulty", self.HANDSHAKE_POW_BITS)
        for nonce in range(2**32):
            combined = f"{challenge_nonce}{nonce}".encode()
            result = hashlib.sha256(combined).digest()
            zero_bits = 0
            for byte in result:
                if byte == 0:
                    zero_bits += 8
                else:
                    zero_bits += (byte ^ (byte - 1)).bit_length() - 1
                    break
            if zero_bits >= difficulty:
                return {
                    "pow_nonce": str(nonce),
                    "timestamp": int(time.time()),
                }
        raise RuntimeError("PoW solve failed")

    def get_stats(self) -> dict:
        """Get rate limiter statistics."""
        with self._lock:
            return {
                "rate_multiplier": round(self._rate_multiplier, 3),
                "attack_detector": self._attack_detector,
                "mac_buckets": len(self._mac_buckets),
                "node_buckets": len(self._node_buckets),
                "ip_buckets": len(self._ip_buckets),
                "seen_cache_size": len(self._seen_requests.cache),
            }


class PeerState(Enum):
    UNKNOWN = 0
    CONNECTING = 1
    HANDSHAKE = 2
    ACTIVE = 3
    IDLE = 4
    STALE = 5
    BANNED = 6


class P2PPeer:
    """Represents a connected P2P peer"""

    def __init__(self, host: str, port: int, node_id: str = None):
        validated_host = _validate_peer_host(host) if host else None
        validated_port = _validate_port(port) if port else None
        self.host = validated_host if validated_host else "0.0.0.0"
        self.port = validated_port if validated_port else _P2P_PORT
        self.node_id = node_id if _validate_node_id(node_id) else ""
        self.external_addr = f"{self.host}:{self.port}"
        self.state = PeerState.UNKNOWN
        self.chain_height = 0
        self.last_ping_ms = 0
        self.ban_score = 0
        self.session_token = None
        self.session_expiry = 0
        self.capabilities = []
        self.mac_address = ""
        self.device_id = ""
        self.latency_ms = 0
        self.uptime_ratio = 0.0
        self.pings_sent = 0
        self.pongs_recv = 0
        self.first_seen = int(time.time())
        self.last_seen = int(time.time())


class PeerManager:
    """Manages peer connections, state machine, and discovery"""

    def __init__(self, max_peers: int = _P2P_MAX_PEERS, db=None):
        self.max_peers = max_peers
        self.max_outbound = _P2P_MAX_OUTBOUND
        self.db = db
        self.peers = {}
        self.pending = {}
        self.lock = _threading.Lock()
        self.outbound_count = 0

    def add_peer(self, peer: P2PPeer) -> None:
        with self.lock:
            if peer.mac_address:
                _old_by_mac = [
                    nid
                    for nid, p in self.peers.items()
                    if p.mac_address == peer.mac_address and nid != peer.node_id
                ]
                for _old_nid in _old_by_mac:
                    del self.peers[_old_nid]
            _is_new = peer.node_id not in self.peers
            self.peers[peer.node_id] = peer
            if _is_new:
                _EXP_LOG.info(
                    f"[PEER] 📡 New peer added: {peer.host}:{peer.port} node_id={peer.node_id[:16] if peer.node_id else 'unknown'}..."
                )
            else:
                _EXP_LOG.debug(
                    f"[PEER] Peer updated: {peer.host}:{peer.port} node_id={peer.node_id[:16] if peer.node_id else 'unknown'}..."
                )

    def get_peer(self, node_id: str) -> P2PPeer:
        return self.peers.get(node_id)

    def get_active_peers(self) -> List[P2PPeer]:
        with self.lock:
            return [p for p in self.peers.values() if p.state == PeerState.ACTIVE]

    def remove_peer(self, node_id: str) -> None:
        with self.lock:
            if node_id in self.peers:
                del self.peers[node_id]

    def increment_ban(self, node_id: str, delta: int) -> None:
        with self.lock:
            if node_id in self.peers:
                self.peers[node_id].ban_score = max(
                    0, min(65535, self.peers[node_id].ban_score + delta)
                )
                if self.peers[node_id].ban_score >= _P2P_BAN_THRESHOLD:
                    self.peers[node_id].state = PeerState.BANNED

    def tick(self) -> None:
        """Peer lifecycle tick — runs every 30s"""
        now = time.time()
        with self.lock:
            for peer in list(self.peers.values()):
                if peer.ban_score >= _P2P_BAN_THRESHOLD:
                    peer.state = PeerState.BANNED
                    continue
                if peer.state == PeerState.ACTIVE:
                    if now - peer.last_seen > 90:
                        peer.state = PeerState.IDLE
                elif peer.state == PeerState.IDLE:
                    if now - peer.last_seen > 180:
                        peer.state = PeerState.STALE
                elif peer.state == PeerState.STALE:
                    if peer.ban_score < _P2P_BAN_THRESHOLD:
                        peer.state = PeerState.CONNECTING

    def load_from_db(self, db) -> None:
        """Load known peers from SQLite"""
        if db is None:
            return
        try:
            cursor = db.execute(
                "SELECT node_id, host, port, chain_height, ban_score, last_seen_at, mac_address, device_id FROM p2p_peers ORDER BY last_seen_at DESC LIMIT 100"
            )
            for row in cursor.fetchall():
                node_id = row[0]
                if (
                    node_id
                    and len(node_id) == 64
                    and all(c in "0123456789abcdef" for c in node_id)
                ):
                    peer = P2PPeer(row[1], row[2], node_id)
                    peer.chain_height = row[3] or 0
                    peer.ban_score = row[4] or 0
                    peer.last_seen = row[5] or int(time.time())
                    peer.mac_address = row[6] or ""
                    peer.device_id = row[7] or ""
                    self.peers[node_id] = peer
        except Exception as e:
            logger.debug(f"[PeerManager] DB load failed: {e}")

    def save_to_db(self, db) -> None:
        """Persist peers to SQLite"""
        if db is None:
            return
        try:
            for peer in self.peers.values():
                if peer.state == PeerState.BANNED:
                    continue
                db.execute(
                    """
                    INSERT OR REPLACE INTO p2p_peers 
                    (node_id, host, port, chain_height, ban_score, last_seen_at, external_addr, capabilities, mac_address, device_id)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                    (
                        peer.node_id,
                        peer.host,
                        peer.port,
                        peer.chain_height,
                        peer.ban_score,
                        peer.last_seen,
                        peer.external_addr,
                        json.dumps(peer.capabilities),
                        peer.mac_address,
                        peer.device_id,
                    ),
                )
            db.commit()
        except Exception as e:
            logger.debug(f"[PeerManager] DB save failed: {e}")


class PQ0LatticeManager:
    """
    Tripartite PQ0 lattice manager — fully backed by the local SQLite hyperbolic
    geometry DB built to exact db_builder_colab.py parity (mp.dps=150, depth=5).

    Every geometry call routes through the module-level _hyp_* functions and the
    _PQ_COORD_CACHE populated by _ensure_pq_cache() at startup.  No floats are
    hand-waved; all distances are genuine Poincaré-disk geodesics from the tessellation.

    Tripartite state (mirrors server pq0_lattice table):
      • pq0_virtual         – Gauss-Bonnet curvature term from oracle triangle area
      • pq0_inverse_virtual – Möbius reflection of virtual across unit circle boundary
      • pq0_pseudoqubit     – geometric mean of oracle fidelities, mapped to [0,255]
    Consensus: all three agree within tolerance 3 (mod 256).
    """

    # {8,3} Schläfli tiling parameters — identical to db_builder
    POINCARE_RADIUS = 1.0
    HYPERBOLIC_CURVATURE = -1.0  # constant curvature K = -1
    EULER_CHARACTERISTIC = -2  # genus-2 surface triangulation
    TESSELLATION_DEPTH = 5
    PQ0_CONSENSUS_TOL = 3  # mod-256 tolerance for tripartite agreement

    def __init__(self, db=None):
        self.db = db
        self._cache: Dict[int, dict] = {}  # block_height → state dict
        self._lock = threading.RLock()

    # ── Internal: ensure PQ cache is warm (non-blocking call) ────────────────
    def _warm_cache(self) -> bool:
        """Return True iff PQ coord cache is ready."""
        return _PQ_CACHE_READY.is_set()

    # =========================================================================
    # GEOMETRY PRIMITIVES (all route through module-level _hyp_* functions)
    # =========================================================================

    def geodesic_distance(self, pq_a: int, pq_b: int) -> float:
        """True Poincaré-disk geodesic distance between two pseudoqubits."""
        try:
            xa, ya = _pq_get_coord(pq_a)
            xb, yb = _pq_get_coord(pq_b)
            return float(_hyp_distance(xa, ya, xb, yb))
        except Exception:
            return 0.0

    def triangle_area_gauss_bonnet(self, pq0: int, pq_curr: int, pq_last: int) -> float:
        """
        Gauss-Bonnet area = π − (α+β+γ) for the triangle (pq0, pq_curr, pq_last).
        Uses the exact same _hyp_triangle_area() as db_builder, which computes
        each angle via the hyperbolic law of cosines at mp.dps=150.
        """
        try:
            x0, y0 = _pq_get_coord(pq0)
            xc, yc = _pq_get_coord(pq_curr)
            xl, yl = _pq_get_coord(pq_last)
            area = _hyp_triangle_area(x0, y0, xc, yc, xl, yl)
            return max(0.0, float(area))
        except Exception:
            return 0.0

    def incenter_coord(
        self, pq0: int, pq_curr: int, pq_last: int
    ) -> Tuple[float, float]:
        """Hyperbolic incenter of the oracle triangle."""
        try:
            x0, y0 = _pq_get_coord(pq0)
            xc, yc = _pq_get_coord(pq_curr)
            xl, yl = _pq_get_coord(pq_last)
            return _hyp_incenter(x0, y0, xc, yc, xl, yl)
        except Exception:
            return (0.0, 0.0)

    def circumcenter_coord(
        self, pq0: int, pq_curr: int, pq_last: int
    ) -> Tuple[float, float]:
        """Hyperbolic circumcenter of the oracle triangle."""
        try:
            x0, y0 = _pq_get_coord(pq0)
            xc, yc = _pq_get_coord(pq_curr)
            xl, yl = _pq_get_coord(pq_last)
            return _hyp_circumcenter(x0, y0, xc, yc, xl, yl)
        except Exception:
            return (0.0, 0.0)

    def poincare_midpoint(self, pq_a: int, pq_b: int) -> Tuple[float, float]:
        """Poincaré-disk midpoint between two pseudoqubits."""
        try:
            xa, ya = _pq_get_coord(pq_a)
            xb, yb = _pq_get_coord(pq_b)
            mx, my = _hyp_poincare_midpoint(xa, ya, xb, yb)
            return float(mx), float(my)
        except Exception:
            return (0.0, 0.0)

    def conformal_factor(self, pq_id: int) -> float:
        """
        Conformal factor f = (1 − r²)/2 at pseudoqubit pq_id.
        This is the horoball scaling used by _sample_error_vector.
        """
        try:
            x, y = _pq_get_coord(pq_id)
            r2 = x * x + y * y
            return max(0.001, (1.0 - r2) / 2.0)
        except Exception:
            return 0.5

    # =========================================================================
    # PQ0 COMPUTATION — tripartite, fully geodesic
    # =========================================================================

    def compute_virtual_pq0(self, hyp_triangle_area: float) -> int:
        """
        pq0_virtual from Gauss-Bonnet curvature integral.

        Formula (exact db_builder physics):
          total_curvature = |K| × area   (K = -1)
          euler_term      = total_curvature × |χ| / (2π)   (χ = -2)
          pq0_virtual     = round(euler_term × 255) mod 256
        """
        if hyp_triangle_area <= 0.0:
            return 0
        total_curvature = abs(self.HYPERBOLIC_CURVATURE) * hyp_triangle_area
        euler_term = total_curvature * abs(self.EULER_CHARACTERISTIC) / (2.0 * math.pi)
        return int(round(euler_term * 255.0)) % 256

    def compute_inverse_virtual_pq0(
        self, pq0_virtual: int, pq0: int, pq_curr: int
    ) -> int:
        """
        pq0_inverse_virtual: Möbius reflection of pq0_virtual.

        The inversion w = 1/conj(z) in the Poincaré disk maps z → outside the
        unit circle.  We use the conformal factor ratio as the scaling:
          scale = f(pq0) / f(pq_curr)    (horoball radii ratio)
          pq0_iv = round(pq0_virtual × scale) mod 256
        """
        try:
            f0 = self.conformal_factor(pq0)
            fc = self.conformal_factor(pq_curr)
            scale = f0 / fc if fc > 1e-6 else 1.0
            return int(round(pq0_virtual * scale)) % 256
        except Exception:
            return (256 - pq0_virtual) % 256  # simple reflection fallback

    def compute_pseudoqubit_pq0(self, oracle_measurements: List[dict]) -> int:
        """
        pq0_pseudoqubit: geometric mean of oracle W-state fidelities → [0,255].

        The geometric mean respects the multiplicative structure of fidelity
        (product of survival probabilities), giving a more stable pq0 under
        Byzantine outliers than arithmetic mean.
        """
        if not oracle_measurements:
            return 0
        fids = [float(m.get("w_state_fidelity", 0) or 0) for m in oracle_measurements]
        fids = [f for f in fids if f > 0.0]
        if not fids:
            return 0
        try:
            log_sum = sum(math.log(max(f, 1e-10)) for f in fids)
            geo_mean = math.exp(log_sum / len(fids))
        except (ValueError, OverflowError):
            geo_mean = 0.0
        return int(round(geo_mean * 255.0)) % 256

    # =========================================================================
    # FULL LATTICE STATE — build + persist for a block
    # =========================================================================

    def compute_lattice_state(
        self,
        block_height: int,
        pq0: int,
        pq_curr: int,
        pq_last: int,
        oracle_measurements: List[dict],
        oracle_snapshot: Optional[dict] = None,
    ) -> dict:
        """
        Compute the complete tripartite PQ0 lattice state for a block.

        Returns a dict ready to INSERT into the local pq0_lattice table (which
        mirrors the server's pq0_lattice schema).

        All geometry uses real DB pseudoqubit coordinates at mp.dps=150.
        """
        # ── Distances ──────────────────────────────────────────────────────
        d_0c = self.geodesic_distance(pq0, pq_curr)
        d_cl = self.geodesic_distance(pq_curr, pq_last)
        d_0l = self.geodesic_distance(pq0, pq_last)

        # ── Triangle area (Gauss-Bonnet) ───────────────────────────────────
        area = self.triangle_area_gauss_bonnet(pq0, pq_curr, pq_last)

        # ── Tripartite pq0 values ──────────────────────────────────────────
        pq0_v = self.compute_virtual_pq0(area)
        pq0_iv = self.compute_inverse_virtual_pq0(pq0_v, pq0, pq_curr)
        pq0_pq = self.compute_pseudoqubit_pq0(oracle_measurements)

        # ── Special points ─────────────────────────────────────────────────
        inc_x, inc_y = self.incenter_coord(pq0, pq_curr, pq_last)
        circ_x, circ_y = self.circumcenter_coord(pq0, pq_curr, pq_last)
        mid_x, mid_y = self.poincare_midpoint(pq0, pq_curr)

        # ── Coordinates of anchors ─────────────────────────────────────────
        try:
            c0x, c0y = _pq_get_coord(pq0)
            ccx, ccy = _pq_get_coord(pq_curr)
            clx, cly = _pq_get_coord(pq_last)
        except Exception:
            c0x = c0y = ccx = ccy = clx = cly = 0.0

        # ── Oracle fidelity stats ──────────────────────────────────────────
        fids = [float(m.get("w_state_fidelity", 0) or 0) for m in oracle_measurements]
        avg_fid = sum(fids) / len(fids) if fids else 0.0

        state = {
            "block_height": block_height,
            "pq0": pq0,
            "pq_curr": pq_curr,
            "pq_last": pq_last,
            "pq0_virtual": pq0_v,
            "pq0_inverse_virtual": pq0_iv,
            "pq0_pseudoqubit": pq0_pq,
            "hyp_triangle_area": area,
            "hyp_dist_0c": d_0c,
            "hyp_dist_cl": d_cl,
            "hyp_dist_0l": d_0l,
            "incenter_x": inc_x,
            "incenter_y": inc_y,
            "circumcenter_x": circ_x,
            "circumcenter_y": circ_y,
            "midpoint_x": mid_x,
            "midpoint_y": mid_y,
            "pq0_x": c0x,
            "pq0_y": c0y,
            "pq_curr_x": ccx,
            "pq_curr_y": ccy,
            "pq_last_x": clx,
            "pq_last_y": cly,
            "avg_fidelity": avg_fid,
            "oracle_count": len(oracle_measurements),
            "cache_ready": self._warm_cache(),
            "mpmath_active": _MPMATH_OK,
            "tessellation_depth": self.TESSELLATION_DEPTH,
        }

        with self._lock:
            self._cache[block_height] = state
        return state

    def persist_lattice_state(self, state: dict) -> bool:
        """Persist computed lattice state to local SQLite pq0_lattice table."""
        if self.db is None:
            return False
        try:
            self.db.execute(
                """
                INSERT OR REPLACE INTO pq0_lattice (
                    block_height, pq0, pq_curr, pq_last,
                    pq0_virtual, pq0_inverse_virtual, pq0_pseudoqubit,
                    hyp_triangle_area, hyp_dist_0c, hyp_dist_cl, hyp_dist_0l
                ) VALUES (?,?,?,?,?,?,?,?,?,?,?)
            """,
                (
                    state["block_height"],
                    state["pq0"],
                    state["pq_curr"],
                    state["pq_last"],
                    state["pq0_virtual"],
                    state["pq0_inverse_virtual"],
                    state["pq0_pseudoqubit"],
                    state["hyp_triangle_area"],
                    state["hyp_dist_0c"],
                    state["hyp_dist_cl"],
                    state["hyp_dist_0l"],
                ),
            )
            return True
        except Exception as e:
            logger.debug(f"[PQ0LatticeManager] persist failed: {e}")
            return False

    # =========================================================================
    # QUERY / CONSENSUS helpers
    # =========================================================================

    def get_lattice_state(self, block_height: int) -> dict:
        """Return cached or DB-loaded lattice state for a block height."""
        with self._lock:
            if block_height in self._cache:
                return self._cache[block_height]
        if self.db is None:
            return {}
        try:
            cursor = self.db.execute(
                "SELECT * FROM pq0_lattice WHERE block_height = ?", (block_height,)
            )
            row = cursor.fetchone()
            if not row:
                return {}
            cols = [desc[0] for desc in cursor.description]
            state = dict(zip(cols, row))
            with self._lock:
                self._cache[block_height] = state
            return state
        except Exception:
            return {}

    def get_tripartite_consensus(self, block_height: int) -> Tuple[bool, dict]:
        """
        Check tripartite PQ0 consensus for a block.

        Three independently computed pq0 values must agree within
        PQ0_CONSENSUS_TOL (3) modulo 256 for the block geometry to be
        considered internally consistent.
        """
        state = self.get_lattice_state(block_height)
        if not state:
            return False, {"error": "no lattice state"}
        v = state.get("pq0_virtual", 0)
        iv = state.get("pq0_inverse_virtual", 0)
        pq = state.get("pq0_pseudoqubit", 0)
        tol = self.PQ0_CONSENSUS_TOL

        # Circular distance mod 256
        def _cdist(a, b):
            return min(abs(a - b), 256 - abs(a - b))

        ok = _cdist(v, pq) <= tol and _cdist(v, iv) <= tol
        detail = {
            "consensus": ok,
            "pq0_virtual": v,
            "pq0_inverse_virtual": iv,
            "pq0_pseudoqubit": pq,
            "tolerance": tol,
            "dist_v_pq": _cdist(v, pq),
            "dist_v_iv": _cdist(v, iv),
            "cache_ready": self._warm_cache(),
        }
        return ok, detail


class BlockPropagator:
    """Handles block propagation via inv/getData/pushBlock"""

    def __init__(self, router, lattice: PQ0LatticeManager = None):
        self.router = router
        self.lattice = lattice
        self.pending_blocks = {}
        self.gossip = None  # optional GossipEngine

    def set_gossip(self, gossip_engine) -> None:
        self.gossip = gossip_engine

    def broadcast_inv(
        self, block_hash: str, height: int, miner_addr: str, peers: List[P2PPeer]
    ) -> None:
        """Broadcast block inventory to all peers with per-peer DEBUG logging"""
        payload = {
            "type": "block",
            "hash": block_hash,
            "height": height,
            "miner_addr": miner_addr,
            "ttl_hops": 8,
        }
        # Gossip relay for block announcement
        if self.gossip:
            import time

            self.gossip.relay(
                "block_announce",
                {
                    "block_hash": block_hash,
                    "height": height,
                    "miner_address": miner_addr,
                    "timestamp": time.time(),
                },
            )
        _success_count = 0
        _fail_count = 0
        for peer in peers:
            try:
                _EXP_LOG.debug(
                    f"[GOSSIP] Sending qtcl_p2p_inv to {peer.host}:{peer.port} for block h={height} hash={block_hash[:16]}..."
                )
                result = self._send_rpc(peer, "qtcl_p2p_inv", payload)
                if result and not result.get("error"):
                    _success_count += 1
                    _EXP_LOG.debug(f"[GOSSIP] ✅ inv sent to {peer.host}:{peer.port}")
                else:
                    _fail_count += 1
                    _EXP_LOG.debug(
                        f"[GOSSIP] ⚠️ inv to {peer.host}:{peer.port} returned: {result}"
                    )
            except Exception as e:
                _fail_count += 1
                _EXP_LOG.debug(
                    f"[GOSSIP] ❌ inv to {peer.host}:{peer.port} failed: {e}"
                )
        _EXP_LOG.info(
            f"[GOSSIP] Block h={height} inv broadcast: {len(peers)} peers, {_success_count} ok, {_fail_count} failed"
        )

    def handle_inv(self, payload: dict, peer: P2PPeer) -> dict:
        """Handle incoming inv message with DEBUG logging"""
        block_hash = payload.get("hash")
        height = payload.get("height")
        miner_addr = payload.get("miner_addr", "unknown")
        if not block_hash:
            _EXP_LOG.debug(f"[GOSSIP] inv from {peer.host}:{peer.port} — no hash")
            return {"want": False}
        _EXP_LOG.info(
            f"[GOSSIP] 📨 inv RECEIVED from {peer.host}:{peer.port} — h={height} hash={block_hash[:16]}... miner={miner_addr[:16]}..."
        )
        return {"want": True}

    def handle_get_data(self, payload: dict, peer: P2PPeer, db) -> dict:
        """Handle getData request"""
        data_type = payload.get("type")
        data_hash = payload.get("hash")
        if not data_hash or data_type != "block":
            return {"found": False}
        try:
            cursor = db.execute(
                "SELECT * FROM blocks WHERE block_hash = ?", (data_hash,)
            )
            row = cursor.fetchone()
            if row:
                cols = [desc[0] for desc in cursor.description]
                return {"found": True, "data": dict(zip(cols, row))}
        except:
            pass
        return {"found": False}

    def handle_push_block(self, payload: dict, peer: P2PPeer, db) -> dict:
        """Handle incoming block push with comprehensive DEBUG logging"""
        block_data = payload.get("block_data")
        if not block_data:
            _EXP_LOG.debug(
                f"[GOSSIP] pushBlock from {peer.host}:{peer.port} — no block_data"
            )
            return {"accepted": False, "height": 0}
        # After receiving a block, verify HypΓ signature if present
        if "hyp_sig" in block_data or "hyp_signature" in block_data:
            try:
                # Verify the block was signed by the claimed miner
                sig_data = block_data.get("hyp_sig") or block_data.get(
                    "hyp_signature", {}
                )
                miner_pubkey = block_data.get("miner_pubkey", "")
                if sig_data and miner_pubkey:
                    import hashlib
                    import json

                    verify_data = {
                        k: v
                        for k, v in block_data.items()
                        if k
                        not in (
                            "hyp_sig",
                            "hyp_signature",
                            "signer_pubkey",
                            "signer_addr",
                        )
                    }
                    msg_bytes = json.dumps(verify_data, sort_keys=True).encode()
                    msg_hash = hashlib.sha256(msg_bytes).digest()
                    engine = HypGammaEngine()
                    if not engine.verify_signature(msg_hash, sig_data, miner_pubkey):
                        _EXP_LOG.warning(
                            f"[P2P] Block HypΓ signature invalid: block={block_data.get('block_hash', '')[:16]}"
                        )
                        return {"accepted": False, "error": "invalid_hyp_signature"}
            except Exception as e:
                _EXP_LOG.debug(f"[P2P] HypΓ sig verification error: {e}")
        try:
            height = block_data.get("height", 0)
            block_hash = block_data.get("block_hash", "")
            hyp_area = block_data.get("hyp_triangle_area", 0)
            oracle_ref = payload.get("oracle_snapshot_ref")
            _EXP_LOG.debug(
                f"[GOSSIP] pushBlock received from {peer.host}:{peer.port} — h={height} hash={block_hash[:16]}..."
            )
            if self.lattice:
                stored = self.lattice.store_lattice_state(
                    height, block_hash, hyp_area, oracle_ref, {}, {}
                )
                if stored:
                    consensus, _ = self.lattice.get_tripartite_consensus(height)
                    if not consensus:
                        _EXP_LOG.warning(
                            f"[GOSSIP] pushBlock h={height} REJECTED — PQ0 consensus failed"
                        )
                        return {"accepted": False, "error": "PQ0 consensus failed"}
                    _EXP_LOG.debug(
                        f"[GOSSIP] pushBlock h={height} PQ0 consensus passed"
                    )
            _EXP_LOG.info(
                f"[GOSSIP] ✅ pushBlock ACCEPTED h={height} from {peer.host}:{peer.port}"
            )
            return {"accepted": True, "height": height}
        except Exception as e:
            _EXP_LOG.warning(
                f"[GOSSIP] pushBlock from {peer.host}:{peer.port} error: {e}"
            )
            return {"accepted": False, "error": str(e)}

    def _send_rpc(self, peer: P2PPeer, method: str, params: dict) -> dict:
        """Send RPC to peer via GET with query parameters"""
        try:
            query_params = {
                "method": method,
                "params": json.dumps(params),
                "id": 1,
            }
            query_string = urlencode(query_params)
            url = f"http://{peer.host}:{peer.port}/rpc?{query_string}"
            req = Request(url, method="GET")
            with urlopen(req, timeout=10) as resp:
                return json.loads(resp.read())
        except:
            return {"error": "rpc failed"}


class TxRelay:
    """Handles transaction relay with mempool bloom reconciliation"""

    def __init__(self, router):
        self.router = router
        self.mempool = set()
        self.mempool_lock = threading.Lock()
        self.pending_blocks = {}
        self.gossip = None

    def set_gossip(self, gossip_engine) -> None:
        self.gossip = gossip_engine

    def add_tx(self, tx_hash: str) -> None:
        with self.mempool_lock:
            already = tx_hash in self.mempool
            self.mempool.add(tx_hash)
        # Gossip relay for transaction
        if self.gossip and not already:
            self.gossip.relay(
                "tx_relay",
                {
                    "tx_hash": tx_hash,
                    "from_addr": "",
                    "to_addr": "",
                    "amount": 0,
                },
            )

    def has_tx(self, tx_hash: str) -> bool:
        with self.mempool_lock:
            return tx_hash in self.mempool

    def generate_bloom_filter(self) -> Tuple[str, int]:
        """Generate bloom filter for mempool reconciliation using MurmurHash"""
        with self.mempool_lock:
            if not self.mempool:
                return base64.b64encode(bytes(256)).decode(), 0
            bloom = bytearray(256)
            for tx in self.mempool:
                h = int(hashlib.md5(tx.encode()).hexdigest()[:8], 16)
                for i in range(8):
                    bloom[(h + i * 17) % 256] = 1
            return base64.b64encode(bytes(bloom)).decode(), len(self.mempool)

    def check_bloom_filter(self, filter_b64: str, tx_hash: str) -> bool:
        """Check if tx might be in peer's mempool"""
        try:
            bloom = bytearray(base64.b64decode(filter_b64))
            h = int(hashlib.md5(tx_hash.encode()).hexdigest()[:8], 16)
            for i in range(8):
                if not bloom[(h + i * 17) % 256]:
                    return False
            return True
        except:
            return True

    def handle_mempool_filter(self) -> dict:
        """Handle getMempoolFilter request"""
        filter_b64, count = self.generate_bloom_filter()
        return {"filter_b64": filter_b64, "count": count}

    def handle_get_missing_txs(self, payload: dict, db) -> dict:
        """Handle getMissingTxs request"""
        hashes = payload.get("hashes", [])
        txs = []
        if db and hashes:
            try:
                placeholders = ",".join("?" * len(hashes))
                cursor = db.execute(
                    f"SELECT * FROM transactions WHERE tx_hash IN ({placeholders})",
                    hashes,
                )
                for row in cursor.fetchall():
                    cols = [desc[0] for desc in cursor.description]
                    txs.append(dict(zip(cols, row)))
            except:
                pass
        return {"txs": txs}


class SyncManager:
    """Handles chain synchronization between peers"""

    def __init__(self, peers: PeerManager, koyeb_rpc=None):
        self.peers = peers
        self.koyeb_rpc = koyeb_rpc
        self.sync_lock = threading.Lock()
        self.syncing = False

    def start_daemon(self) -> None:
        """Background sync daemon"""

        def run():
            while True:
                time.sleep(30)
                self.sync_peers()

        t = threading.Thread(target=run, daemon=True)
        t.start()

    def sync_peers(self) -> None:
        """Sync chain state with peers"""
        with self.sync_lock:
            if self.syncing:
                return
            self.syncing = True
        best_peer = None
        best_height = 0
        try:
            for peer in self.peers.get_active_peers():
                try:
                    resp = self._request_blocks(peer, 0, 1)
                    if resp and resp.get("blocks"):
                        height = resp["blocks"][0].get("height", 0)
                        if height > best_height:
                            best_height = height
                            best_peer = peer
                except:
                    pass
            if best_peer:
                resp = self._request_blocks(best_peer, 0, 500)
                if resp and "blocks" in resp:
                    logger.debug(
                        f"[Sync] Got {len(resp['blocks'])} blocks from {best_peer.host}"
                    )
        except Exception as e:
            logger.debug(f"[Sync] Sync failed: {e}")
        finally:
            self.syncing = False

    def get_height(self) -> int:
        """Get current synced chain height"""
        return 0

    def _request_blocks(self, peer: P2PPeer, from_height: int, limit: int) -> dict:
        """Request blocks from peer via GET"""
        try:
            url = f"http://{peer.host}:{peer.port}/rpc"
            params = {
                "from_height": from_height,
                "to_height": from_height + limit,
                "limit": limit,
            }
            query = urlencode(
                {"method": "qtcl_p2p_getBlocks", "params": json.dumps(params), "id": 1}
            )
            req = Request(f"{url}?{query}", method="GET")
            with urlopen(req, timeout=30) as resp:
                return json.loads(resp.read()).get("result", {})
        except:
            return {}


class ExternalAddressResolver:
    """Resolves true WAN IP via STUN (qtcl_getMyAddr) then public echo services. ❤️ I love you."""

    _RFC1918 = (
        "10.",
        "192.168.",
        "127.",
        "169.254.",
        "172.16.",
        "172.17.",
        "172.18.",
        "172.19.",
        "172.20.",
        "172.21.",
        "172.22.",
        "172.23.",
        "172.24.",
        "172.25.",
        "172.26.",
        "172.27.",
        "172.28.",
        "172.29.",
        "172.30.",
        "172.31.",
    )
    _WAN_SERVICES = [
        "https://api.ipify.org",
        "https://icanhazip.com",
        "https://checkip.amazonaws.com",
        "https://api4.my-ip.io/ip",
    ]

    @staticmethod
    def _is_public(ip: str) -> bool:
        return bool(ip) and not any(
            ip.startswith(p) for p in ExternalAddressResolver._RFC1918
        )

    @staticmethod
    def resolve() -> str:
        override_host = os.getenv("P2P_EXTERNAL_HOST")
        override_port = int(os.getenv("P2P_EXTERNAL_PORT", str(_P2P_PORT)))

        # 0) Use STUN result already obtained during _bootstrap_client_env() at startup
        #    _bootstrap_client_env() calls qtcl_getMyAddr and stores in P2P_EXTERNAL_HOST/PORT.
        #    If those are set we skip the redundant network call here.
        if override_host:
            return f"{override_host}:{override_port}"

        # Also check the raw STUN vars (set by bootstrap but may differ from P2P_EXTERNAL_HOST)
        _stun_ip = os.getenv("P2P_STUN_EXTERNAL_IP", "")
        if ExternalAddressResolver._is_public(_stun_ip):
            _stun_port = int(os.getenv("P2P_STUN_EXTERNAL_PORT", str(_P2P_PORT)))
            return f"{_stun_ip}:{_stun_port}"

        # 1) STUN via Koyeb — server reads X-Forwarded-For so client gets its real WAN IP
        #    (Only reached if _bootstrap_client_env() failed or ran before _P2P_PORT was set)
        try:
            req = Request(
                f"{ENTROPY_SERVER_URL}/rpc",
                data=json.dumps(
                    {
                        "jsonrpc": "2.0",
                        "method": "qtcl_getMyAddr",
                        "params": {},
                        "id": 1,
                    }
                ).encode(),
                headers={"Content-Type": "application/json"},
            )
            with urlopen(req, timeout=5) as resp:
                result = json.loads(resp.read()).get("result", {})
                stun_ip = result.get("ip", "")
                if ExternalAddressResolver._is_public(stun_ip):
                    return f"{stun_ip}:{override_port}"
        except Exception:
            pass
        # 2) Public WAN echo services
        for _svc in ExternalAddressResolver._WAN_SERVICES:
            try:
                req = Request(_svc, headers={"User-Agent": "QTCL-Miner/2.0"})
                with urlopen(req, timeout=4) as resp:
                    wan_ip = resp.read().decode().strip()
                    if (
                        ExternalAddressResolver._is_public(wan_ip)
                        and len(wan_ip.split(".")) == 4
                    ):
                        return f"{wan_ip}:{override_port}"
            except Exception:
                pass
        # 3) LAN fallback — at least the port is right
        try:
            import socket as _sk

            with _sk.socket(_sk.AF_INET, _sk.SOCK_DGRAM) as s:
                s.settimeout(3)
                s.connect(("8.8.8.8", 80))
                local_ip = s.getsockname()[0]
            return f"{local_ip}:{_P2P_PORT}"
        except Exception:
            return f"127.0.0.1:{_P2P_PORT}"


class DHTManager:
    """Kademlia-over-HTTP DHT for peer discovery"""

    def __init__(self, db=None):
        self.db = db
        self.node_id = None

    def find_node(self, target_id: str, count: int = 20) -> List[dict]:
        """Find closest nodes to target_id"""
        if not self.db:
            return []
        try:
            cursor = self.db.execute(
                """
                SELECT node_id, external_addr, chain_height FROM p2p_peers 
                WHERE node_id != ? ORDER BY RANDOM() LIMIT ?
            """,
                (self.node_id, count),
            )
            nodes = []
            for row in cursor.fetchall():
                dist = self._xor_distance(row[0], target_id)
                nodes.append({"node_id": row[0], "addr": row[1], "distance": dist})
            return sorted(nodes, key=lambda x: x["distance"])[:count]
        except:
            return []

    def store(self, key: str, value: str, ttl: int = 3600) -> bool:
        """Store value in DHT"""
        return True

    def find_value(self, key: str) -> dict:
        """Find value for key"""
        return {"found": False}

    def _xor_distance(self, id1: str, id2: str) -> int:
        try:
            return int(id1, 16) ^ int(id2, 16)
        except:
            return 0


class GossipEngine:
    """
    Epidemic gossip protocol for the QTCL P2P meshnet.

    Features:
    - Bloom-filter based inventory exchange (bandwidth efficient)
    - Priority queue: blocks > peer announcements > txs > metadata
    - Seen-set deduplication with LRU eviction
    - Exponential backoff fan-out (flood first, then decay)
    - HypΓ-signed message envelope support
    - Configurable relay probability (Erlay-style sparse relay)

    Message types (priority, TTL):
        block_announce     100   10 hops     High priority — flood immediately
        block_request       90    5 hops     Request for block data
        tx_relay            50    20 hops    Transaction relay (sparse)
        peer_greeting       30    3 hops     Peer introduction
        inventory_req       20    2 hops     Bloom filter exchange
        metadata            10    2 hops     Node info, chain height
    """

    MSG_PRIORITIES = {
        "block_announce": 100,
        "block_request": 90,
        "tx_relay": 50,
        "peer_greeting": 30,
        "inventory_req": 20,
        "metadata": 10,
    }

    MSG_TTLS = {
        "block_announce": 10,
        "block_request": 5,
        "tx_relay": 20,
        "peer_greeting": 3,
        "inventory_req": 2,
        "metadata": 2,
    }

    # Sparse relay probability for tx_relay (Erlay-style)
    TX_RELAY_PROB = 0.25  # relay 25% of txs to reduce redundancy

    def __init__(self, node_id: str, wallet_addr: str = ""):
        self.node_id = node_id
        self.wallet_addr = wallet_addr
        self.seen_hashes = LRUCache(100000)  # recently seen message hashes
        self.pending = {}  # msg_hash -> GossipMessage
        self.delivered = set()  # successfully delivered hashes
        self.stats = {
            "sent": 0,
            "received": 0,
            "relayed": 0,
            "duplicates_dropped": 0,
            "invalid_dropped": 0,
            "blocks_received": 0,
            "txs_received": 0,
        }
        self._relay_callbacks = {}  # msg_type -> callback(msg_hash, payload) list
        self._outbound_queue = queue.PriorityQueue(maxsize=10000)
        self._hyp_auth = None  # optional HLWEMessageAuth
        self._lock = threading.Lock()

    def set_hyp_auth(self, auth) -> None:
        """Attach HypΓ message authentication for signing/verification."""
        self._hyp_auth = auth

    def register_handler(self, msg_type: str, callback: Callable) -> None:
        """Register a callback for a specific message type."""
        if msg_type not in self._relay_callbacks:
            self._relay_callbacks[msg_type] = []
        self._relay_callbacks[msg_type].append(callback)

    def _hash_payload(self, msg_type: str, payload: dict) -> str:
        """Deterministic hash for dedup — covers content, not envelope."""
        raw = json.dumps({"type": msg_type, "data": payload}, sort_keys=True).encode()
        return hashlib.sha256(raw).hexdigest()

    def ingest(self, msg_type: str, payload: dict, sender_node_id: str = "") -> tuple:
        """
        Process an incoming gossip message.

        Returns: (accepted: bool, reason: str)
        """
        msg_hash = self._hash_payload(msg_type, payload)

        with self._lock:
            # Seen-set dedup
            if self.seen_hashes.contains(msg_hash):
                self.stats["duplicates_dropped"] += 1
                return False, "duplicate"

            self.seen_hashes.add(msg_hash)
            self.stats["received"] += 1

            # Track stats
            if msg_type == "block_announce":
                self.stats["blocks_received"] += 1
            elif msg_type == "tx_relay":
                self.stats["txs_received"] += 1

            # Update delivery set
            self.delivered.add(msg_hash)

        # Dispatch to registered handlers
        handlers = self._relay_callbacks.get(msg_type, [])
        for handler in handlers:
            try:
                handler(msg_hash, payload)
            except Exception as e:
                logger.debug(f"[GOSSIP] Handler error for {msg_type}: {e}")

        return True, "accepted"

    def relay(self, msg_type: str, payload: dict) -> str:
        """
        Initiate a new gossip broadcast.

        Returns the message hash for tracking.
        """
        msg_hash = self._hash_payload(msg_type, payload)

        if self.seen_hashes.contains(msg_hash):
            return msg_hash  # already seen

        with self._lock:
            self.seen_hashes.add(msg_hash)
            self.stats["sent"] += 1

        priority = self.MSG_PRIORITIES.get(msg_type, 10)

        # Sparse relay for transactions
        if msg_type == "tx_relay" and random.random() > self.TX_RELAY_PROB:
            return msg_hash  # skip relay (Erlay sparse)

        # Enqueue for outbound relay
        try:
            self._outbound_queue.put_nowait((-priority, msg_hash, msg_type, payload))
        except queue.Full:
            pass  # queue full — drop lowest priority

        return msg_hash

    def dequeue_outbound(self, max_items: int = 10) -> list:
        """
        Dequeue pending outbound messages, highest priority first.

        Returns list of (msg_type, payload) tuples to send.
        """
        items = []
        for _ in range(max_items):
            try:
                _, msg_hash, msg_type, payload = self._outbound_queue.get_nowait()
                items.append((msg_type, payload))
            except queue.Empty:
                break
        return items

    def create_inventory_filter(
        self, msg_type: str = "tx_relay", filter_size: int = 8192
    ) -> dict:
        """
        Create a compact bloom filter of recent items for inventory exchange.

        Peers compare filters to identify missing items efficiently.
        """
        # Simple bloom filter using bitarray simulation
        bits = bytearray(filter_size // 8)

        items = list(self.delivered)
        count = 0
        for h in items:
            # Hash to 3 bit positions
            for seed in range(3):
                h_raw = f"{h}:{seed}".encode()
                pos = (
                    int.from_bytes(hashlib.sha256(h_raw).digest()[:2], "big")
                    % filter_size
                )
                byte_idx = pos // 8
                bit_idx = pos % 8
                bits[byte_idx] |= 1 << bit_idx
                count += 1

        return {
            "msg_type": msg_type,
            "filter": bytes(bits).hex(),
            "filter_size": filter_size,
            "item_count": count,
        }

    def check_inventory_filter(self, filter_dict: dict) -> list:
        """
        Compare a peer's inventory filter against our seen-set.

        Returns list of hashes we have that the peer might not.
        """
        filter_hex = filter_dict.get("filter", "")
        filter_size = filter_dict.get("filter_size", 8192)
        if not filter_hex:
            return []

        filter_bytes = bytes.fromhex(filter_hex)
        candidates = []

        with self._lock:
            for h in list(self.delivered)[-10000:]:  # last 10k items
                match = True
                for seed in range(3):
                    h_raw = f"{h}:{seed}".encode()
                    pos = (
                        int.from_bytes(hashlib.sha256(h_raw).digest()[:2], "big")
                        % filter_size
                    )
                    byte_idx = pos // 8
                    bit_idx = pos % 8
                    if byte_idx >= len(filter_bytes) or not (
                        filter_bytes[byte_idx] & (1 << bit_idx)
                    ):
                        match = False
                        break
                if match:
                    candidates.append(h)

        return candidates

    def get_stats(self) -> dict:
        with self._lock:
            return {
                **self.stats,
                "seen_count": self.seen_hashes.size()
                if hasattr(self.seen_hashes, "size")
                else 0,
                "pending_count": self._outbound_queue.qsize(),
                "delivered_count": len(self.delivered),
            }


class PeerReputationEngine:
    """
    Multi-dimensional peer reputation scoring for the QTCL meshnet.

    Scores (0.0 - 1.0 each, weighted):
        latency        0.20   Response time (lower = higher score)
        uptime         0.25   Connection stability over time
        fidelity       0.20   W-state quantum fidelity contribution
        chain_sync     0.15   How close to our chain height
        honesty        0.10   Valid blocks/txs delivered vs invalid
        generosity     0.10   Inventory shared (blocks/txs we needed)

    Composite score = weighted sum (0.0 = banned, 1.0 = perfect)

    Ban threshold: 0.15 (auto-ban for 5 min)
    Unban: automatic after ban period, score resets to 0.5
    """

    WEIGHTS = {
        "latency": 0.20,
        "uptime": 0.25,
        "fidelity": 0.20,
        "chain_sync": 0.15,
        "honesty": 0.10,
        "generosity": 0.10,
    }

    BAN_THRESHOLD = 0.15
    BAN_DURATION_S = 300  # 5 minutes

    def __init__(self):
        self.scores = {}  # node_id -> {factor: value}
        self.composites = {}  # node_id -> float
        self.bans = {}  # node_id -> ban_until_timestamp
        self.history = {}  # node_id -> list of (timestamp, event_type, detail)
        self._lock = threading.Lock()

    def _init_peer(self, node_id: str) -> None:
        if node_id not in self.scores:
            self.scores[node_id] = {
                "latency": 0.5,
                "uptime": 0.5,
                "fidelity": 0.5,
                "chain_sync": 0.5,
                "honesty": 0.5,
                "generosity": 0.5,
            }
            self.composites[node_id] = 0.5
            self.history[node_id] = []

    def record_latency(self, node_id: str, latency_ms: float) -> None:
        """Update latency score based on ping response time."""
        with self._lock:
            self._init_peer(node_id)
            # Score: 1.0 for <50ms, 0.5 for 500ms, 0.1 for 5000ms
            if latency_ms <= 50:
                score = 1.0
            elif latency_ms <= 500:
                score = 1.0 - (latency_ms - 50) / 900
            elif latency_ms <= 5000:
                score = max(0.1, 0.5 - (latency_ms - 500) / 9000)
            else:
                score = 0.05
            # Exponential moving average
            self.scores[node_id]["latency"] = (
                0.7 * self.scores[node_id]["latency"] + 0.3 * score
            )
            self._recompute(node_id)
            self._log(node_id, "latency", f"{latency_ms:.1f}ms -> {score:.3f}")

    def record_uptime(self, node_id: str, connected_s: float) -> None:
        """Update uptime score based on connection duration."""
        with self._lock:
            self._init_peer(node_id)
            # Score increases with connection time: 0.5 at 0s, 0.8 at 60s, 1.0 at 300s
            raw = min(1.0, 0.5 + 0.5 * min(connected_s / 300.0, 1.0))
            self.scores[node_id]["uptime"] = (
                0.8 * self.scores[node_id]["uptime"] + 0.2 * raw
            )
            self._recompute(node_id)

    def record_fidelity(self, node_id: str, fidelity: float) -> None:
        """Update fidelity score — quantum state contribution quality."""
        with self._lock:
            self._init_peer(node_id)
            # fidelity is already 0.0-1.0
            self.scores[node_id]["fidelity"] = 0.7 * self.scores[node_id][
                "fidelity"
            ] + 0.3 * max(0.0, min(1.0, fidelity))
            self._recompute(node_id)

    def record_chain_sync(
        self, node_id: str, peer_height: int, our_height: int
    ) -> None:
        """Update chain sync score — peers on same chain get higher scores."""
        with self._lock:
            self._init_peer(node_id)
            diff = abs(peer_height - our_height)
            if diff == 0:
                score = 1.0
            elif diff <= 5:
                score = 0.9
            elif diff <= 20:
                score = 0.7
            elif diff <= 100:
                score = 0.4
            else:
                score = 0.1
            self.scores[node_id]["chain_sync"] = (
                0.6 * self.scores[node_id]["chain_sync"] + 0.4 * score
            )
            self._recompute(node_id)

    def record_honesty(self, node_id: str, valid: bool) -> None:
        """Record validity of a delivered block/tx — invalid = penalty."""
        with self._lock:
            self._init_peer(node_id)
            raw = 1.0 if valid else 0.0
            self.scores[node_id]["honesty"] = (
                0.9 * self.scores[node_id]["honesty"] + 0.1 * raw
            )
            if not valid:
                self._log(node_id, "honesty_fail", "delivered invalid data")
            self._recompute(node_id)

    def record_generosity(self, node_id: str, items_provided: int) -> None:
        """Record items this peer provided us (blocks, txs we needed)."""
        with self._lock:
            self._init_peer(node_id)
            raw = min(1.0, items_provided / 10.0)
            self.scores[node_id]["generosity"] = (
                0.8 * self.scores[node_id]["generosity"] + 0.2 * raw
            )
            self._recompute(node_id)

    def _recompute(self, node_id: str) -> None:
        """Recompute weighted composite score."""
        scores = self.scores.get(node_id, {})
        composite = sum(
            self.WEIGHTS.get(f, 0) * scores.get(f, 0.5) for f in self.WEIGHTS
        )
        self.composites[node_id] = composite

        # Auto-ban check
        if composite < self.BAN_THRESHOLD and node_id not in self.bans:
            self.ban(node_id, f"score {composite:.3f} < threshold {self.BAN_THRESHOLD}")

    def ban(self, node_id: str, reason: str = "") -> None:
        """Ban a peer for BAN_DURATION_S seconds."""
        with self._lock:
            self.bans[node_id] = time.time() + self.BAN_DURATION_S
            self._log(node_id, "ban", reason)

    def unban(self, node_id: str) -> None:
        """Manually unban a peer and reset score to 0.5."""
        with self._lock:
            if node_id in self.bans:
                del self.bans[node_id]
            if node_id in self.scores:
                for f in self.scores[node_id]:
                    self.scores[node_id][f] = 0.5
                self.composites[node_id] = 0.5
            self._log(node_id, "unban", "manual")

    def is_banned(self, node_id: str) -> bool:
        """Check if peer is currently banned. Auto-unban if ban expired."""
        with self._lock:
            ban_until = self.bans.get(node_id, 0)
            if ban_until and time.time() > ban_until:
                # Auto-unban: ban expired
                del self.bans[node_id]
                if node_id in self.scores:
                    for f in self.scores[node_id]:
                        self.scores[node_id][f] = 0.5
                    self.composites[node_id] = 0.5
                return False
            return ban_until > time.time()

    def get_score(self, node_id: str) -> dict:
        """Get full score breakdown for a peer."""
        with self._lock:
            self._init_peer(node_id)
            return {
                "node_id": node_id,
                "composite": self.composites.get(node_id, 0.5),
                "factors": dict(self.scores.get(node_id, {})),
                "banned": self.is_banned(node_id),
                "ban_until": self.bans.get(node_id, 0),
            }

    def get_top_peers(self, limit: int = 20) -> list:
        """Get top-scoring active (non-banned) peers."""
        with self._lock:
            active = [
                (nid, c)
                for nid, c in self.composites.items()
                if nid not in self.bans or time.time() > self.bans[nid]
            ]
            active.sort(key=lambda x: x[1], reverse=True)
            return [{"node_id": nid, "score": c} for nid, c in active[:limit]]

    def tick(self) -> None:
        """Periodic maintenance — expire bans, decay scores."""
        with self._lock:
            now = time.time()
            expired = [nid for nid, until in self.bans.items() if now > until]
            for nid in expired:
                del self.bans[nid]
                if nid in self.scores:
                    for f in self.scores[nid]:
                        self.scores[nid][f] = 0.5  # reset after ban
                    self.composites[nid] = 0.5

            # Slow decay: nudge all scores toward 0.5 (neutral)
            for nid in list(self.scores.keys()):
                for f in self.scores[nid]:
                    self.scores[nid][f] = 0.99 * self.scores[nid][f] + 0.01 * 0.5
                self._recompute(nid)

    def _log(self, node_id: str, event_type: str, detail: str) -> None:
        """Record event in peer history (keep last 100)."""
        if node_id not in self.history:
            self.history[node_id] = []
        self.history[node_id].append((time.time(), event_type, detail))
        if len(self.history[node_id]) > 100:
            self.history[node_id] = self.history[node_id][-100:]

    def get_history(self, node_id: str, limit: int = 20) -> list:
        """Get recent events for a peer."""
        with self._lock:
            h = self.history.get(node_id, [])
            return [{"ts": ts, "event": et, "detail": d} for ts, et, d in h[-limit:]]


class P2PServer(ThreadingHTTPServer):
    """RPC-only P2P server on 0.0.0.0:9091 with SO_REUSEADDR+SO_REUSEPORT.

    CRITICAL (Android/Termux): SO_REUSEADDR must be set on the socket BEFORE
    bind() is called. Python's TCPServer.__init__ creates the socket then
    immediately calls server_bind() -> socket.bind() in one shot.
    We pass bind_and_activate=False, set opts on self.socket first, then
    call server_bind() + server_activate() ourselves in the correct order.
    """

    allow_reuse_address = True

    def __init__(
        self,
        port: int,
        dispatch_fn,
        peer_mgr: PeerManager,
        lattice: PQ0LatticeManager,
        propagator: BlockPropagator,
        tx_relay: TxRelay,
        sync_mgr: SyncManager,
        dht: DHTManager,
        sessions: SessionManager,
        db=None,
    ):
        import socket as _sock

        self.port = port
        self.rate_limiter = MeshNetRateLimiter()
        handler = lambda *a, **kw: P2PRequestHandler(
            *a,
            dispatch_fn=dispatch_fn,
            peer_mgr=peer_mgr,
            lattice=lattice,
            propagator=propagator,
            tx_relay=tx_relay,
            sync_mgr=sync_mgr,
            dht=dht,
            sessions=sessions,
            db=db,
            **kw,
        )
        # bind_and_activate=False: TCPServer creates self.socket but does NOT call
        # server_bind() yet — lets us set socket options before bind().
        super().__init__(("0.0.0.0", port), handler, bind_and_activate=False)
        try:
            self.socket.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEADDR, 1)
        except OSError:
            pass
        try:
            self.socket.setsockopt(_sock.SOL_SOCKET, _sock.SO_REUSEPORT, 1)
        except OSError:
            pass
        try:
            self.server_bind()
            self.server_activate()
        except Exception:
            self.server_close()
            raise

    def server_bind(self):
        """Bind — socket opts already set pre-bind in __init__."""
        super().server_bind()

    def start_daemon(self) -> None:
        t = threading.Thread(target=self.serve_forever, daemon=True)
        t.start()
        logger.info(f"[P2P] ✅ Server listening on 0.0.0.0:{self.port}/rpc")


class P2PRequestHandler(BaseHTTPRequestHandler):
    def __init__(
        self,
        *args,
        dispatch_fn=None,
        peer_mgr=None,
        lattice=None,
        propagator=None,
        tx_relay=None,
        sync_mgr=None,
        dht=None,
        sessions=None,
        db=None,
        **kwargs,
    ):
        self.dispatch_fn = dispatch_fn
        self.peer_mgr = peer_mgr
        self.lattice = lattice
        self.propagator = propagator
        self.tx_relay = tx_relay
        self.sync_mgr = sync_mgr
        self.dht = dht
        self.sessions = sessions
        self.db = db
        super().__init__(*args, **kwargs)

    def log_message(self, format, *args):
        pass

    def do_GET(self):
        from urllib.parse import parse_qs, urlparse

        if self.path.split("?")[0] != "/rpc":
            self.send_error(404)
            return
        client_ip = self.client_address[0]
        try:
            parsed = urlparse(self.path)
            params = parse_qs(parsed.query)
            request_data = params.get("data", [params.get("body", ["{}"])[0]])[0]
            request = json.loads(request_data)
        except json.JSONDecodeError:
            self.send_error(400)
            return
        except Exception:
            self.send_error(400)
            return

        method = request.get("method", "")
        params = request.get("params", {})

        # Extract node_id and mac_address from request
        node_id = ""
        mac = ""
        if method == "qtcl_p2p_handshake":
            payload = params.get("payload", {})
            node_id = payload.get("node_id", "")
            mac = payload.get("mac_address", "")
        else:
            node_id = params.get("node_id", "")
            # mac may be present in some requests (e.g., from peer's known mac)
            mac = params.get("mac_address", "")

        # Rate limiting with MAC and node_id
        allowed, reason = self.server.rate_limiter.allow(
            method, ip=client_ip, node_id=node_id, mac=mac
        )
        if not allowed:
            self.send_error(429)
            return

        try:
            result, error = self.dispatch_fn(method, params, request, client_ip)
            response = {"jsonrpc": "2.0", "id": request.get("id")}
            if result is not None:
                response["result"] = result
            if error:
                response["error"] = error
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.end_headers()
            self.wfile.write(json.dumps(response).encode())
        except Exception as e:
            self.send_error(500)


def create_p2p_rpc_dispatch(
    peer_mgr: PeerManager,
    lattice: PQ0LatticeManager,
    propagator: BlockPropagator,
    tx_relay: TxRelay,
    sync_mgr: SyncManager,
    dht: DHTManager,
    sessions: SessionManager,
    node_id: str,
    identity: P2PIdentity,
    db=None,
    seen_blocks: LRUCache = None,
    seen_txs: LRUCache = None,
    gossip=None,
    reputation=None,
    hyp_auth=None,
) -> Callable:
    """Factory to create the complete RPC dispatch function"""

    def dispatch(
        method: str, params: dict, request: dict, client_ip: str
    ) -> Tuple[any, dict]:
        # Session verification for all methods except handshake, discovery, and mesh
        if method not in (
            "qtcl_p2p_handshake",
            "qtcl_dht_ping",
            "qtcl_p2p_ping",
            "qtcl_gossip_relay",
            "qtcl_gossip_inventory",
            "qtcl_gossip_getStats",
            "qtcl_registerPeer",
            "qtcl_peer_exchange",
            "qtcl_p2p_heightBroadcast",
        ):
            session_token = request.get("session_token") or params.get("session_token")
            req_node_id = params.get("node_id", "")
            if session_token and req_node_id:
                if not sessions.verify(session_token, req_node_id):
                    return None, {
                        "code": -32603,
                        "message": "unauthorized: invalid session",
                    }
            elif method != "qtcl_p2p_announce":
                pass  # Allow announce without session for discovery

        if method == "qtcl_p2p_handshake":
            payload = params.get("payload")
            # Bug #2 fix: tolerate BOTH payload-wrapped (new) and flat (legacy) params.
            # New clients send params={'payload': {...}}.
            # Old / hand-crafted clients send params={'node_id': ..., 'version': ...} flat.
            if not isinstance(payload, dict):
                # Attempt flat-params fallback
                if params.get("node_id") or params.get("version"):
                    payload = params  # treat whole params as payload
                else:
                    return None, {
                        "code": -32602,
                        "message": "invalid params: payload required",
                    }
            version = payload.get("version", "")
            if version != _P2P_VERSION:
                return None, {"code": -1, "message": "version mismatch"}
            node_id = payload.get("node_id", "")
            if not node_id or len(node_id) != 64:
                return None, {
                    "code": -1,
                    "message": "invalid node_id: must be 64 hex chars",
                }
            chain_height = payload.get("chain_height", 0)
            external_addr = payload.get("external_addr", "")
            _ea_port = _P2P_PORT
            if external_addr and ":" in external_addr:
                try:
                    _ea_port = int(external_addr.split(":")[-1])
                except ValueError:
                    pass
            peer = P2PPeer(client_ip, _ea_port, node_id)
            peer.chain_height = chain_height
            peer.external_addr = external_addr
            peer.capabilities = payload.get("capabilities", [])
            peer.mac_address = payload.get("mac_address", "")
            peer.device_id = payload.get("device_id", "")
            token, expiry = sessions.create(node_id, identity.pubkey_bytes)
            peer.session_token = token
            peer.session_expiry = expiry
            peer.state = PeerState.ACTIVE
            peer_mgr.add_peer(peer)
            return {
                "version": _P2P_VERSION,
                "chain_height": chain_height,
                "session_token": token,
                "session_expiry": expiry,
                "mac_address": _get_mac_address(),
                "device_id": _get_device_id(""),
            }, None

        if method == "qtcl_p2p_ping":
            nonce = params.get("nonce", "")
            height = params.get("height", 0)
            return {"nonce": nonce, "height": height}, None

        if method == "qtcl_p2p_pong":
            return {"ack": True}, None

        if method == "qtcl_p2p_announce":
            external_addr = params.get("external_addr", "")
            node_id = params.get("node_id", "")
            chain_height = params.get("chain_height", 0)
            if not _validate_node_id(node_id):
                return None, {"code": -32602, "message": "invalid node_id"}
            peer = peer_mgr.get_peer(node_id)
            if peer:
                valid_host = (
                    _validate_peer_host(external_addr.split(":")[0])
                    if external_addr
                    else None
                )
                if valid_host:
                    peer.external_addr = external_addr
                peer.chain_height = chain_height
                peer.last_seen = int(time.time())
            else:
                host_port = external_addr.split(":")
                host = (
                    _validate_peer_host(host_port[0])
                    if host_port
                    else _validate_peer_host(client_ip)
                )
                port = _validate_port(host_port[1]) if len(host_port) > 1 else _P2P_PORT
                if not host or not port:
                    return None, {"code": -32602, "message": "invalid host/port"}
                new_peer = P2PPeer(host, port, node_id)
                new_peer.chain_height = chain_height
                new_peer.last_seen = int(time.time())
                peer_mgr.add_peer(new_peer)
            return {"ack": True}, None

        if method == "qtcl_p2p_getAddr":
            max_peers = min(params.get("max", 200), 200)
            active = peer_mgr.get_active_peers()
            peers = [
                {
                    "host": p.host,
                    "port": p.port,
                    "node_id": p.node_id,
                    "last_seen": p.last_seen,
                    "chain_height": p.chain_height,
                    "score": 1.0 - (p.ban_score / 100),
                }
                for p in active[:max_peers]
            ]
            return {"peers": peers}, None

        if method == "qtcl_p2p_addr":
            peers_data = params.get("peers", [])
            if not isinstance(peers_data, list) or len(peers_data) > 100:
                return None, {"code": -32602, "message": "invalid peers list"}
            added = 0
            for p in peers_data:
                try:
                    host = _validate_peer_host(p.get("host", ""))
                    port = _validate_port(p.get("port", _P2P_PORT))
                    node_id = p.get("node_id", "")
                    if not host or not port or not _validate_node_id(node_id):
                        continue
                    peer = P2PPeer(host, port, node_id)
                    peer.chain_height = p.get("chain_height", 0)
                    peer.capabilities = p.get("capabilities", [])
                    peer_mgr.add_peer(peer)
                    added += 1
                except:
                    pass
            return {"accepted": added}, None

        if method == "qtcl_p2p_inv":
            if not propagator:
                return None, {"code": -32601, "message": "method not found"}
            block_hash = params.get("hash", "")
            height = params.get("height", 0)
            miner_addr = params.get("miner_addr", "unknown")
            _EXP_LOG.debug(
                f"[P2P-RPC] qtcl_p2p_inv from {client_ip} — h={height} hash={block_hash[:16] if block_hash else 'none'}..."
            )
            if seen_blocks and not seen_blocks.contains(block_hash):
                seen_blocks.add(block_hash)
                peer = P2PPeer(client_ip, _P2P_PORT)
                result = propagator.handle_inv(params, peer)
                _EXP_LOG.info(
                    f"[P2P-RPC] qtcl_p2p_inv handled — want={result.get('want', False)} for h={height}"
                )
                return result
            _EXP_LOG.debug(
                f"[P2P-RPC] qtcl_p2p_inv duplicate or missing hash — rejecting"
            )
            return {"want": False}, None

        if method == "qtcl_p2p_getData":
            if not propagator:
                return None, {"code": -32601, "message": "method not found"}
            return propagator.handle_get_data(params, None, db), None

        if method == "qtcl_p2p_pushBlock":
            if not propagator:
                return None, {"code": -32601, "message": "method not found"}
            _EXP_LOG.debug(f"[P2P-RPC] qtcl_p2p_pushBlock from {client_ip}")
            result = propagator.handle_push_block(params, None, db)
            _EXP_LOG.info(
                f"[P2P-RPC] qtcl_p2p_pushBlock result: accepted={result.get('accepted', False)} height={result.get('height', 0)}"
            )
            return result, None

        if method == "qtcl_p2p_pushTx":
            if not tx_relay:
                return None, {"code": -32601, "message": "method not found"}
            tx_data = params.get("tx_data", {})
            tx_hash = tx_data.get("tx_hash", "")
            if tx_hash:
                tx_relay.add_tx(tx_hash)
            return {"accepted": True, "txid": tx_hash}, None

        if method == "qtcl_p2p_getMempoolFilter":
            if not tx_relay:
                return None, {"code": -32601, "message": "method not found"}
            return tx_relay.handle_mempool_filter(), None

        if method == "qtcl_p2p_getMissingTxs":
            if not tx_relay:
                return None, {"code": -32601, "message": "method not found"}
            return tx_relay.handle_get_missing_txs(params, db), None

        if method == "qtcl_p2p_getOracleSnapshot":
            cycle_id = params.get("cycle_id")
            if db:
                try:
                    cursor = db.execute(
                        "SELECT * FROM oracle_cache WHERE cycle_id = ?", (cycle_id,)
                    )
                    row = cursor.fetchone()
                    if row:
                        return {
                            "found": True,
                            "cycle_id": row[0],
                            "snapshot": json.loads(row[1]),
                            "cached_at": row[2],
                        }, None
                except:
                    pass
            return {"found": False}, None

        if method == "qtcl_p2p_getBlocks":
            from_height = max(params.get("from_height", 0), 0)
            to_height = params.get("to_height", 500)
            limit = min(params.get("limit", 500), 500)
            blocks = []
            if db:
                try:
                    cursor = db.execute(
                        "SELECT * FROM blocks WHERE height >= ? AND height < ? LIMIT ?",
                        (from_height, max(to_height, from_height + 1), limit),
                    )
                    for row in cursor.fetchall():
                        cols = [desc[0] for desc in cursor.description]
                        blocks.append(dict(zip(cols, row)))
                except:
                    pass
            return {"blocks": blocks}, None

        if method == "qtcl_dht_findNode":
            target_id = params.get("target_id", "")
            count = min(params.get("count", 20), 100)
            if dht:
                nodes = dht.find_node(target_id, count)
                return {"nodes": nodes}, None
            return {"nodes": []}, None

        if method == "qtcl_dht_ping":
            return {"pong": True}, None

        if method == "qtcl_dht_store":
            key = params.get("key", "")
            value = params.get("value", "")
            ttl = params.get("ttl", 3600)
            if dht:
                dht.store(key, value, ttl)
            return {"stored": True}, None

        if method == "qtcl_dht_findValue":
            key = params.get("key", "")
            if dht:
                return dht.find_value(key), None
            return {"found": False}, None

        if method == "qtcl_p2p_getNetworkStats":
            active = len(peer_mgr.get_active_peers()) if peer_mgr else 0
            return {"active_peers": active, "version": _P2P_VERSION, "height": 0}, None

        # ── Mesh Peer Registration (for 1000+ miner scale) ─────────────────────
        if method == "qtcl_registerPeer":
            # Extract peer registration data - handles both dict and list params
            reg_data = params
            if isinstance(params, list) and len(params) > 0:
                reg_data = params[0]
            elif not isinstance(params, dict):
                return None, {
                    "code": -32602,
                    "message": "invalid params: expected dict or [dict]",
                }

            external_addr = reg_data.get("external_addr", "")
            peer_node_id = reg_data.get("node_id", "")
            pubkey = reg_data.get("pubkey", "")
            chain_height = reg_data.get("chain_height", 0)
            mac_address = reg_data.get("mac_address", "")
            device_id = reg_data.get("device_id", "")

            # Validate required fields
            if not peer_node_id or len(peer_node_id) != 64:
                return None, {
                    "code": -32602,
                    "message": "invalid node_id: must be 64 hex chars",
                }
            if not external_addr or ":" not in external_addr:
                return None, {
                    "code": -32602,
                    "message": "invalid external_addr: expected host:port",
                }

            # Parse host:port
            try:
                host, port_str = external_addr.rsplit(":", 1)
                port = int(port_str)
            except (ValueError, IndexError):
                return None, {"code": -32602, "message": "invalid external_addr format"}

            # Validate host
            host = _validate_peer_host(host)
            if not host:
                return None, {"code": -32602, "message": "invalid host"}

            # Create/update peer
            peer = peer_mgr.get_peer(peer_node_id)
            if peer:
                # Update existing peer
                peer.chain_height = chain_height
                peer.last_seen = int(time.time())
                if mac_address:
                    peer.mac_address = mac_address
                if device_id:
                    peer.device_id = device_id
                peer.state = PeerState.ACTIVE
                _EXP_LOG.debug(
                    f"[P2P-REGISTER] Updated peer {peer_node_id[:16]}... @ {host}:{port}"
                )
            else:
                # Create new peer
                peer = P2PPeer(host, port, peer_node_id)
                peer.chain_height = chain_height
                peer.external_addr = external_addr
                peer.mac_address = mac_address
                peer.device_id = device_id
                peer.state = PeerState.ACTIVE
                peer.first_seen = int(time.time())
                peer_mgr.add_peer(peer)
                _EXP_LOG.info(
                    f"[P2P-REGISTER] New peer registered: {peer_node_id[:16]}... @ {host}:{port} (height={chain_height})"
                )

            # Persist to DB
            if db:
                try:
                    peer_mgr.save_to_db(db)
                except Exception as _e:
                    _EXP_LOG.debug(f"[P2P-REGISTER] DB save failed: {_e}")

            return {
                "registered": True,
                "node_id": peer_node_id,
                "timestamp": int(time.time()),
                "mesh_size": len(peer_mgr.peers),
            }, None

        if method == "qtcl_peer_exchange":
            # Peer discovery endpoint - return known peers for mesh expansion
            max_peers = min(
                params.get("max", 100) if isinstance(params, dict) else 100, 200
            )
            exclude_id = (
                params.get("exclude_node_id", "") if isinstance(params, dict) else ""
            )

            # Get active peers, excluding the requester
            all_peers = peer_mgr.get_active_peers()
            peers_to_share = []

            for p in all_peers:
                if p.node_id == exclude_id:
                    continue
                if p.state != PeerState.ACTIVE:
                    continue
                peers_to_share.append(
                    {
                        "node_id": p.node_id,
                        "host": p.host,
                        "port": p.port,
                        "external_addr": p.external_addr or f"{p.host}:{p.port}",
                        "chain_height": p.chain_height,
                        "last_seen": p.last_seen,
                        "capabilities": p.capabilities,
                        "mac_address": p.mac_address,
                        "device_id": p.device_id,
                    }
                )
                if len(peers_to_share) >= max_peers:
                    break

            _EXP_LOG.debug(
                f"[P2P-EXCHANGE] Shared {len(peers_to_share)} peers with {client_ip}"
            )
            return {
                "peers": peers_to_share,
                "count": len(peers_to_share),
                "timestamp": int(time.time()),
            }, None

        if method == "qtcl_p2p_heightBroadcast":
            # Handle height change broadcast from peer
            height = params.get("height", 0)
            block_hash = params.get("block_hash", "")
            sender_node_id = params.get("node_id", "")
            miner_addr = params.get("miner_addr", "")

            if height <= 0:
                return None, {"code": -32602, "message": "invalid height"}

            # Validate sender is known peer
            sender = peer_mgr.get_peer(sender_node_id) if sender_node_id else None
            if sender_node_id and not sender:
                _EXP_LOG.debug(
                    f"[P2P-HEIGHT] Ignored broadcast from unknown peer {sender_node_id[:16]}..."
                )
                return {"acknowledged": False, "reason": "unknown_sender"}, None

            # Update sender's height
            if sender:
                sender.chain_height = height
                sender.last_seen = int(time.time())

            _EXP_LOG.info(
                f"[P2P-HEIGHT] Broadcast from {sender_node_id[:16] if sender_node_id else 'unknown'}: height={height} hash={block_hash[:16] if block_hash else 'none'}..."
            )

            # Signal chain advance if new height is ahead
            try:
                if height > 0:
                    signal_chain_advance(height)
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P-HEIGHT] Chain advance signal failed: {_e}")

            # Re-broadcast to other peers (mesh propagation) - limited to prevent spam
            if gossip and height > 0:
                try:
                    gossip.relay(
                        "height_broadcast",
                        {
                            "height": height,
                            "block_hash": block_hash,
                            "sender_node_id": sender_node_id,
                            "miner_addr": miner_addr,
                            "timestamp": time.time(),
                        },
                    )
                except Exception as _e:
                    _EXP_LOG.debug(f"[P2P-HEIGHT] Gossip relay failed: {_e}")

            return {
                "acknowledged": True,
                "local_height": height,
                "mesh_peers": len(peer_mgr.peers) if peer_mgr else 0,
            }, None

        # ── Gossip protocol RPCs ──────────────────────────────────────────────
        if method == "qtcl_gossip_relay":
            if not gossip:
                return None, {"code": -32601, "message": "gossip not available"}
            msg_type = params.get("msg_type", "")
            payload = params.get("payload", {})
            sender = params.get("sender_node_id", node_id)
            accepted, reason = gossip.ingest(msg_type, payload, sender)
            if accepted:
                gossip.relay(msg_type, payload)  # re-relay to other peers
            return {
                "accepted": accepted,
                "reason": reason,
                "stats": gossip.get_stats(),
            }, None

        if method == "qtcl_gossip_inventory":
            if not gossip:
                return None, {"code": -32601, "message": "gossip not available"}
            filter_dict = params.get("filter", {})
            msg_type = params.get("msg_type", "tx_relay")
            if filter_dict:
                # Peer sent us their filter — find what we have that they need
                missing = gossip.check_inventory_filter(filter_dict)
                return {"missing_hashes": missing[:100], "count": len(missing)}, None
            else:
                # We need to send our filter
                our_filter = gossip.create_inventory_filter(msg_type)
                return {"filter": our_filter}, None

        if method == "qtcl_gossip_getStats":
            if not gossip:
                return None, {"code": -32601, "message": "gossip not available"}
            return gossip.get_stats(), None

        # ── Reputation engine RPCs ────────────────────────────────────────────
        if method == "qtcl_reputation_getScore":
            if not reputation:
                return None, {"code": -32601, "message": "reputation not available"}
            target_id = params.get("node_id", "")
            return reputation.get_score(target_id), None

        if method == "qtcl_reputation_getTopPeers":
            if not reputation:
                return None, {"code": -32601, "message": "reputation not available"}
            limit = min(params.get("limit", 20), 100)
            return {"peers": reputation.get_top_peers(limit)}, None

        if method == "qtcl_reputation_recordLatency":
            if not reputation:
                return None, {"code": -32601, "message": "reputation not available"}
            target_id = params.get("node_id", "")
            latency = float(params.get("latency_ms", 0))
            reputation.record_latency(target_id, latency)
            return {"ok": True}, None

        return None, {"code": -32601, "message": f"method {method} not found"}

    return dispatch


class P2PNode:
    """Master P2P Node — integrates all components"""

    DEFAULT_PORT = _P2P_PORT

    def __init__(self, port: int = None, db=None, wallet_addr: str = ""):
        self.port = port or self.DEFAULT_PORT
        self.db = db
        self.wallet_addr = wallet_addr
        self.identity = P2PIdentity.load_or_create(wallet_addr=wallet_addr)
        self.node_id = self.identity.node_id
        self.mac_address = _get_mac_address()
        self.device_id = _get_device_id(wallet_addr)
        self.seen_blocks = LRUCache(10000)
        self.seen_txs = LRUCache(50000)
        self.sessions = SessionManager()
        self.peer_mgr = PeerManager(max_peers=_P2P_MAX_PEERS, db=db)
        self.lattice = PQ0LatticeManager(db=db)
        self.propagator = BlockPropagator(None, self.lattice)
        self.tx_relay = TxRelay(None)
        self.sync_mgr = SyncManager(self.peer_mgr)
        self.dht = DHTManager(db=db)
        self.dht.node_id = self.node_id
        self.external_addr = None
        self._running = False

        self.hyp_auth = HypGammaWallet()
        self.gossip = GossipEngine(self.node_id, wallet_addr)
        self.reputation = PeerReputationEngine()
        self.compact_blocks = CompactBlockSerializer()

        # If we have a wallet address, register it for HypΓ signing
        if wallet_addr:
            try:
                # Derive signing keys from P2P identity
                priv_hex = self.identity.privkey_bytes.hex()
                pub_hex = self.identity.pubkey_bytes.hex()
                self.hyp_auth.register_wallet(wallet_addr, priv_hex, pub_hex)
            except Exception:
                pass

        # Attach gossip engine to block propagator
        if hasattr(self, "propagator") and self.propagator:
            self.propagator.set_gossip(self.gossip)
        # Attach gossip engine to tx relay
        if hasattr(self, "tx_relay") and self.tx_relay:
            self.tx_relay.set_gossip(self.gossip)

    def start(self) -> None:
        if self._running:
            return
        self.external_addr = ExternalAddressResolver.resolve()
        dispatch_fn = create_p2p_rpc_dispatch(
            self.peer_mgr,
            self.lattice,
            self.propagator,
            self.tx_relay,
            self.sync_mgr,
            self.dht,
            self.sessions,
            self.node_id,
            self.identity,
            self.db,
            self.seen_blocks,
            self.seen_txs,
            gossip=self.gossip,
            reputation=self.reputation,
            hyp_auth=self.hyp_auth,
        )
        self.server = P2PServer(
            self.port,
            dispatch_fn,
            self.peer_mgr,
            self.lattice,
            self.propagator,
            self.tx_relay,
            self.sync_mgr,
            self.dht,
            self.sessions,
            self.db,
        )
        self.server.start_daemon()
        self.peer_mgr.load_from_db(self.db)
        self._running = True
        self.sync_mgr.start_daemon()
        self._start_peer_bootstrap_daemon()
        self._start_nat_group_discovery()
        self._start_peer_connector_daemon()
        self._start_peer_exchange_discovery()  # Mesh peer exchange for 1000+ scale
        logger.info(
            f"[P2P] ✅ Node started: {self.external_addr} (node_id: {self.node_id[:16]}...)"
        )
        # Register gossip handlers
        self.gossip.register_handler("block_announce", self._on_gossip_block)
        self.gossip.register_handler("tx_relay", self._on_gossip_tx)
        self.gossip.register_handler("peer_greeting", self._on_gossip_peer)
        self.gossip.register_handler("height_broadcast", self._on_gossip_height)

    def _start_peer_bootstrap_daemon(self) -> None:
        """Launch async peer bootstrap — handshake seeds, activate peers.

        Fixes applied vs original:
          • Handshake params wrapped in 'payload' key to match P2P dispatch gate
          • Backoff uses per-seed next_attempt wall-clock timestamp (not modulo hack)
          • Koyeb seeds: ENTROPY_SERVER_URL/rpc (HTTPS, no explicit port — Koyeb terminates TLS)
          • LAN peers discovered via ENV override P2P_LAN_PEERS=host:port,host:port
        """
        import threading as _t, json as _j, time as _tm
        from urllib.request import urlopen, Request
        import ssl as _ssl

        # Extra LAN seeds from env (comma-separated host:port) — for same-network miners
        _lan_seeds: dict = {}
        _lan_raw = os.getenv("P2P_LAN_PEERS", "")
        for _lp in _lan_raw.split(","):
            _lp = _lp.strip()
            if ":" in _lp:
                _lan_seeds[_lp] = {
                    "id": "",
                    "role": "lan",
                    "region": "local",
                    "verified": False,
                }

        def _bootstrap_loop():
            # next_attempt[seed_addr] = earliest wall-clock time we may retry
            _next_attempt = {
                s: 0.0
                for s in list(P2P_HARDCODED_SEEDS.keys()) + list(_lan_seeds.keys())
            }
            _backoff = {s: 2.0 for s in _next_attempt}  # exponential step (seconds)

            while self._running:
                try:
                    active_now = len(self.peer_mgr.get_active_peers())
                    if active_now < 4:
                        all_seeds = {**P2P_HARDCODED_SEEDS, **_lan_seeds}
                        for seed_addr, seed_meta in all_seeds.items():
                            if not self._running:
                                break
                            now = _tm.time()
                            if now < _next_attempt.get(seed_addr, 0.0):
                                continue  # still in backoff window

                            host_part, port_str = seed_addr.rsplit(":", 1)
                            p2p_port = int(port_str)
                            is_lan = seed_meta.get("role") == "lan"

                            existing = any(
                                p.host == host_part and p.port == p2p_port
                                for p in self.peer_mgr.peers.values()
                            )
                            if existing:
                                continue

                            try:
                                # Bug #2 fixed: wrap handshake fields in 'payload' dict
                                hs_body = _j.dumps(
                                    {
                                        "jsonrpc": "2.0",
                                        "method": "qtcl_p2p_handshake",
                                        "params": {
                                            "payload": {
                                                "version": _P2P_VERSION,
                                                "node_id": self.node_id,
                                                "port": self.port,
                                                "chain_height": 0,
                                                "external_addr": self.external_addr
                                                or "",
                                                "capabilities": [
                                                    "blocks",
                                                    "txs",
                                                    "state",
                                                ],
                                                "mac_address": _get_mac_address(),
                                                "device_id": _get_device_id(
                                                    getattr(self, "wallet_addr", "")
                                                    if hasattr(self, "wallet_addr")
                                                    else ""
                                                ),
                                            }
                                        },
                                        "id": 1,
                                    }
                                ).encode()

                                # P2P routing: Koyeb seeds → ENTROPY_SERVER_URL/rpc (HTTPS), LAN/direct peers → http://host:port/rpc
                                if is_lan:
                                    rpc_url = f"http://{host_part}:{p2p_port}/rpc"
                                    ctx = None
                                else:
                                    # Use ENTROPY_SERVER_URL (env-configurable) — Koyeb terminates TLS
                                    rpc_url = f"{ENTROPY_SERVER_URL}/rpc"
                                    ctx = (
                                        None  # ENTROPY_SERVER_URL already has https://
                                    )

                                req = Request(
                                    rpc_url,
                                    data=hs_body,
                                    headers={"Content-Type": "application/json"},
                                )
                                kwargs = {"timeout": 8}
                                if ctx:
                                    kwargs["context"] = ctx

                                with urlopen(req, **kwargs) as resp:
                                    result = _j.loads(resp.read().decode())
                                    r = result.get("result") or {}
                                    if r.get("version"):
                                        seed_id = seed_meta.get("id") or self.node_id
                                        new_peer = P2PPeer(host_part, p2p_port, seed_id)
                                        new_peer.state = PeerState.ACTIVE
                                        new_peer.external_addr = seed_addr
                                        # Store session token so subsequent RPCs pass auth gate
                                        new_peer.session_token = r.get(
                                            "session_token", ""
                                        )
                                        new_peer.session_expiry = int(
                                            r.get("session_expiry", 0)
                                        )
                                        self.peer_mgr.add_peer(new_peer)
                                        logger.info(
                                            f"[P2P] ✅ Bootstrapped seed {seed_addr}: peer ACTIVE"
                                        )
                                        _next_attempt[seed_addr] = 0.0  # reset
                                        _backoff[seed_addr] = 2.0
                                    else:
                                        raise ValueError(f"bad handshake result: {r}")

                            except Exception as e:
                                bo = _backoff.get(seed_addr, 2.0)
                                _next_attempt[seed_addr] = _tm.time() + bo
                                _backoff[seed_addr] = min(300.0, bo * 2)
                                logger.debug(
                                    f"[P2P] Bootstrap {seed_addr}: {type(e).__name__}: {e}"
                                )

                    _tm.sleep(10)

                except Exception as e:
                    logger.debug(f"[P2P] Bootstrap daemon error: {e}")
                    _tm.sleep(30)

        _t.Thread(target=_bootstrap_loop, daemon=True, name="P2P-Bootstrap").start()

    def _start_nat_group_discovery(self) -> None:
        """Periodically query the server for peers behind the same NAT (same caller_ip).
        Uses qtcl_getPeersByNatGroup to find devices with different MACs on the same WAN IP.
        Falls back to UDP broadcast on the LAN subnet for direct discovery."""
        import threading as _t2, time as _tm2
        from urllib.request import urlopen as _uo2, Request as _Rq2

        def _nat_discovery_loop():
            _last_caller_ip = ""
            _discovery_interval = 45

            while self._running:
                try:
                    _tm2.sleep(_discovery_interval)
                    if not self._running:
                        break

                    _mac = _get_mac_address()
                    _my_node_id = self.node_id

                    _caller_ip = ""
                    try:
                        _stun_body = json.dumps(
                            {
                                "jsonrpc": "2.0",
                                "method": "qtcl_getMyAddr",
                                "params": {},
                                "id": 1,
                            }
                        ).encode()
                        _stun_req = _Rq2(
                            f"{ENTROPY_SERVER_URL}/rpc",
                            data=_stun_body,
                            headers={"Content-Type": "application/json"},
                        )
                        with _uo2(_stun_req, timeout=6) as _stun_resp:
                            _stun_result = json.loads(_stun_resp.read())
                            _caller_ip = (_stun_result.get("result") or {}).get(
                                "ip", ""
                            )
                    except Exception:
                        _caller_ip = _last_caller_ip

                    if not _caller_ip:
                        continue
                    _last_caller_ip = _caller_ip

                    try:
                        _nat_body = json.dumps(
                            {
                                "jsonrpc": "2.0",
                                "method": "qtcl_getPeersByNatGroup",
                                "params": [
                                    {"caller_ip": _caller_ip, "mac_address": _mac}
                                ],
                                "id": 2,
                            }
                        ).encode()
                        _nat_req = _Rq2(
                            f"{ENTROPY_SERVER_URL}/rpc",
                            data=_nat_body,
                            headers={"Content-Type": "application/json"},
                        )
                        with _uo2(_nat_req, timeout=8) as _nat_resp:
                            _nat_result = json.loads(_nat_resp.read())
                            _nat_peers = (_nat_result.get("result") or {}).get(
                                "peers"
                            ) or []

                        if _nat_peers:
                            logger.info(
                                f"[NAT-DISC] Found {len(_nat_peers)} same-NAT peers (IP={_caller_ip})"
                            )
                            for _np in _nat_peers:
                                _np_id = _np.get("node_id", "")
                                _np_addr = _np.get("external_addr", "")
                                _np_mac = _np.get("mac_address", "")
                                if not _np_id or _np_id == _my_node_id or not _np_addr:
                                    continue
                                if _np_id in self.peer_mgr.peers:
                                    continue
                                try:
                                    _np_host = _np_addr.split(":")[0]
                                    _np_port = (
                                        int(_np_addr.split(":")[1])
                                        if ":" in _np_addr
                                        else _P2P_PORT
                                    )
                                    _new_peer = P2PPeer(_np_host, _np_port, _np_id)
                                    _new_peer.mac_address = _np_mac
                                    _new_peer.device_id = _np.get("device_id", "")
                                    _new_peer.state = PeerState.CONNECTING
                                    self.peer_mgr.add_peer(_new_peer)
                                    logger.info(
                                        f"[NAT-DISC] Queued same-NAT peer: {_np_host}:{_np_port} mac={_np_mac[:8]}..."
                                    )
                                except Exception as _npe:
                                    logger.debug(
                                        f"[NAT-DISC] Failed to add peer: {_npe}"
                                    )

                            _try_lan_broadcast(self, _mac, _my_node_id)

                    except Exception as _ne:
                        logger.debug(f"[NAT-DISC] Query failed: {_ne}")

                except Exception as _e:
                    logger.debug(f"[NAT-DISC] Loop error: {_e}")

        _t2.Thread(
            target=_nat_discovery_loop, daemon=True, name="NAT-Group-Disc"
        ).start()

    def _start_peer_connector_daemon(self) -> None:
        """Background daemon: attempt handshake with CONNECTING peers."""
        import urllib.request as _ur
        import json as _j
        import time as _tmo

        def _connector_loop():
            while self._running:
                try:
                    _tmo.sleep(10)  # pause between cycles
                    # Get all CONNECTING peers
                    with self.peer_mgr.lock:
                        _connecting = [
                            p
                            for p in self.peer_mgr.peers.values()
                            if p.state == PeerState.CONNECTING
                        ]
                    if not _connecting:
                        continue
                    # Try up to 3 peers per cycle
                    for peer in _connecting[:3]:
                        if peer.state != PeerState.CONNECTING:
                            continue
                        try:
                            _url = f"http://{peer.host}:{peer.port}/rpc"
                            _body = _j.dumps(
                                {
                                    "jsonrpc": "2.0",
                                    "method": "qtcl_p2p_handshake",
                                    "params": {
                                        "payload": {
                                            "version": _P2P_VERSION,
                                            "node_id": self.node_id,
                                            "port": self.port,
                                            "chain_height": 0,
                                            "external_addr": self.external_addr or "",
                                            "capabilities": ["blocks", "txs", "state"],
                                            "mac_address": _get_mac_address(),
                                            "device_id": _get_device_id(
                                                self.wallet_addr
                                            ),
                                        }
                                    },
                                    "id": int(_tmo.time()),
                                }
                            ).encode()
                            _req = _ur.Request(
                                _url,
                                data=_body,
                                headers={"Content-Type": "application/json"},
                            )
                            with _ur.urlopen(_req, timeout=8) as _resp:
                                _result = _j.loads(_resp.read().decode())
                                _r = _result.get("result") or {}
                                if _r.get("version"):
                                    peer.session_token = _r.get("session_token", "")
                                    peer.session_expiry = int(
                                        _r.get("session_expiry", 0)
                                    )
                                    peer.mac_address = _r.get("mac_address", "")
                                    peer.device_id = _r.get("device_id", "")
                                    peer.chain_height = _r.get(
                                        "chain_height", peer.chain_height
                                    )
                                    peer.state = PeerState.ACTIVE
                                    self.peer_mgr.save_to_db(self.db)
                                    logger.info(
                                        f"[P2P-CONN] Handshake success: {peer.host}:{peer.port} -> ACTIVE"
                                    )
                        except Exception as _e:
                            logger.debug(
                                f"[P2P-CONN] Handshake failed to {peer.host}:{peer.port}: {_e}"
                            )
                except Exception as _loop_e:
                    logger.debug(f"[P2P-CONN] Loop error: {_loop_e}")

        _t = _threading.Thread(
            target=_connector_loop, daemon=True, name="P2P-Connector"
        )
        _t.start()

    def broadcast_height_change(
        self, height: int, block_hash: str = "", miner_addr: str = ""
    ) -> dict:
        """
        Broadcast height change to all registered peers in the mesh.
        Returns broadcast statistics for monitoring.
        Scales to 1000+ miners via batched async sends.
        """
        if not self._running or not self.peer_mgr:
            return {
                "broadcast": False,
                "reason": "p2p_not_running",
                "peers_notified": 0,
            }

        if height <= 0:
            return {"broadcast": False, "reason": "invalid_height", "peers_notified": 0}

        # Get all active peers
        active_peers = self.peer_mgr.get_active_peers()
        if not active_peers:
            _EXP_LOG.debug(
                f"[P2P-BROADCAST] No active peers to notify for height {height}"
            )
            return {"broadcast": True, "peers_notified": 0, "height": height}

        # Use miner address from wallet if not provided
        if not miner_addr and self.wallet_addr:
            miner_addr = self.wallet_addr

        import json as _j
        import urllib.request as _ur

        payload = {
            "height": height,
            "block_hash": block_hash,
            "node_id": self.node_id,
            "miner_addr": miner_addr,
        }

        success_count = 0
        failed_count = 0
        skipped_count = 0

        # Batch size for 1000+ scale - process in chunks to not block
        BATCH_SIZE = 32  # Process 32 peers at a time

        def _send_to_peer(peer: P2PPeer) -> bool:
            """Send height broadcast to a single peer."""
            try:
                # Build RPC request
                body = _j.dumps(
                    {
                        "jsonrpc": "2.0",
                        "method": "qtcl_p2p_heightBroadcast",
                        "params": payload,
                        "id": 1,
                    }
                ).encode()

                url = f"http://{peer.host}:{peer.port}/rpc"
                req = _ur.Request(
                    url, data=body, headers={"Content-Type": "application/json"}
                )

                # Quick timeout for mesh responsiveness
                with _ur.urlopen(req, timeout=3) as resp:
                    result = _j.loads(resp.read().decode())
                    if result.get("result", {}).get("acknowledged"):
                        return True
                    return False
            except Exception as _e:
                _EXP_LOG.debug(
                    f"[P2P-BROADCAST] Failed to notify {peer.host}:{peer.port}: {_e}"
                )
                return False

        # Process peers in batches for scalability
        peers_to_notify = active_peers[:_P2P_MAX_PEERS]  # Respect max peers limit

        for i in range(0, len(peers_to_notify), BATCH_SIZE):
            batch = peers_to_notify[i : i + BATCH_SIZE]

            for peer in batch:
                # Skip if peer is the one who sent us this (avoid echo)
                if peer.node_id == payload.get("original_sender"):
                    skipped_count += 1
                    continue

                # Send async to not block
                try:
                    import threading as _th

                    _th.Thread(
                        target=lambda p=peer: _send_to_peer(p),
                        daemon=True,
                        name=f"HeightBroadcast-{peer.host}",
                    ).start()
                    success_count += 1
                except Exception as _e:
                    _EXP_LOG.debug(f"[P2P-BROADCAST] Thread spawn failed: {_e}")
                    failed_count += 1

        _EXP_LOG.info(
            f"[P2P-BROADCAST] Height {height} broadcast to {success_count}/{len(peers_to_notify)} peers "
            f"({failed_count} failed, {skipped_count} skipped)"
        )

        # Also relay via gossip for wider propagation
        if self.gossip:
            try:
                self.gossip.relay(
                    "height_broadcast",
                    {
                        "height": height,
                        "block_hash": block_hash,
                        "sender_node_id": self.node_id,
                        "miner_addr": miner_addr,
                        "timestamp": time.time(),
                    },
                )
            except Exception as _e:
                _EXP_LOG.debug(f"[P2P-BROADCAST] Gossip relay failed: {_e}")

        return {
            "broadcast": True,
            "height": height,
            "peers_notified": success_count,
            "peers_failed": failed_count,
            "peers_skipped": skipped_count,
            "total_active": len(active_peers),
            "mesh_size": len(self.peer_mgr.peers),
        }

    def _start_peer_exchange_discovery(self) -> None:
        """
        Background daemon: Discover new peers via peer_exchange with existing peers.
        Runs every 60s to expand the mesh. Critical for 1000+ miner scale.
        """
        import threading as _t
        import time as _tm
        import json as _j
        import urllib.request as _ur
        import random as _rnd

        def _peer_exchange_loop():
            # Wait for bootstrap to complete
            _tm.sleep(30)

            while self._running:
                try:
                    active_peers = self.peer_mgr.get_active_peers()

                    # Need at least 1 active peer to do peer exchange
                    if len(active_peers) < 1:
                        _EXP_LOG.debug(
                            "[P2P-EXCHANGE-DISC] No active peers, skipping exchange cycle"
                        )
                        _tm.sleep(60)
                        continue

                    # Pick random subset of peers to query (avoid overwhelming any single peer)
                    peers_to_query = _rnd.sample(
                        active_peers, min(3, len(active_peers))
                    )

                    new_peers_found = 0

                    for peer in peers_to_query:
                        try:
                            # Query peer for their known peers
                            body = _j.dumps(
                                {
                                    "jsonrpc": "2.0",
                                    "method": "qtcl_peer_exchange",
                                    "params": {
                                        "max": 50,
                                        "exclude_node_id": self.node_id,
                                    },
                                    "id": 1,
                                }
                            ).encode()

                            url = f"http://{peer.host}:{peer.port}/rpc"
                            req = _ur.Request(
                                url,
                                data=body,
                                headers={"Content-Type": "application/json"},
                            )

                            with _ur.urlopen(req, timeout=5) as resp:
                                result = _j.loads(resp.read().decode())
                                peer_list = result.get("result", {}).get("peers", [])

                                for p in peer_list:
                                    node_id = p.get("node_id", "")
                                    host = p.get("host", "")
                                    port = p.get("port", _P2P_PORT)

                                    # Skip if already known
                                    if (
                                        not node_id
                                        or node_id == self.node_id
                                        or node_id in self.peer_mgr.peers
                                    ):
                                        continue

                                    # Validate host
                                    host = _validate_peer_host(host)
                                    if not host:
                                        continue

                                    # Add new peer to our mesh
                                    new_peer = P2PPeer(host, port, node_id)
                                    new_peer.chain_height = p.get("chain_height", 0)
                                    new_peer.external_addr = p.get(
                                        "external_addr", f"{host}:{port}"
                                    )
                                    new_peer.mac_address = p.get("mac_address", "")
                                    new_peer.device_id = p.get("device_id", "")
                                    new_peer.capabilities = p.get("capabilities", [])
                                    new_peer.state = PeerState.CONNECTING
                                    self.peer_mgr.add_peer(new_peer)
                                    new_peers_found += 1

                        except Exception as _e:
                            _EXP_LOG.debug(
                                f"[P2P-EXCHANGE-DISC] Exchange with {peer.host}:{peer.port} failed: {_e}"
                            )

                    if new_peers_found > 0:
                        _EXP_LOG.info(
                            f"[P2P-EXCHANGE-DISC] Discovered {new_peers_found} new peers via exchange (total mesh: {len(self.peer_mgr.peers)})"
                        )

                    # Sleep before next exchange cycle (60s for scale)
                    _tm.sleep(60)

                except Exception as _loop_e:
                    _EXP_LOG.debug(f"[P2P-EXCHANGE-DISC] Loop error: {_loop_e}")
                    _tm.sleep(60)

        _t.Thread(
            target=_peer_exchange_loop, daemon=True, name="P2P-Exchange-Disc"
        ).start()

    def stop(self) -> None:
        self._running = False
        if self.server:
            self.server.shutdown()
        self.peer_mgr.save_to_db(self.db)

    def _on_gossip_block(self, msg_hash: str, payload: dict) -> None:
        """Handle incoming block announcement from gossip."""
        height = payload.get("height", 0)
        block_hash = payload.get("block_hash", "")
        miner = payload.get("miner_address", "")
        logger.info(
            f"[GOSSIP] Block announced: height={height} hash={block_hash[:16]}... miner={miner[:16]}..."
        )
        if self.propagator:
            dummy_peer = P2PPeer("0.0.0.0", 0, "")
            self.propagator.handle_inv(
                {"hash": block_hash, "height": height, "miner_addr": miner}, dummy_peer
            )

    def _on_gossip_tx(self, msg_hash: str, payload: dict) -> None:
        """Handle incoming transaction relay from gossip."""
        txid = payload.get("tx_hash", payload.get("txid", ""))
        logger.debug(f"[GOSSIP] TX relay: {txid[:16]}...")
        if self.tx_relay:
            self.tx_relay.add_tx(txid)

    def _on_gossip_peer(self, msg_hash: str, payload: dict) -> None:
        """Handle incoming peer greeting from gossip."""
        node_id = payload.get("node_id", "")
        addr = payload.get("external_addr", "")
        mac = payload.get("mac_address", "")
        if node_id and addr and node_id != self.node_id:
            if node_id not in self.peer_mgr.peers:
                parts = addr.split(":")
                host = parts[0] if parts else addr
                port = int(parts[1]) if len(parts) > 1 else _P2P_PORT
                new_peer = P2PPeer(host, port, node_id)
                new_peer.mac_address = mac
                new_peer.device_id = payload.get("device_id", "")
                new_peer.state = PeerState.CONNECTING
                self.peer_mgr.add_peer(new_peer)
                logger.info(
                    f"[GOSSIP] New peer learned: {host}:{port} mac={mac[:8]}..."
                )

    def _on_gossip_height(self, msg_hash: str, payload: dict) -> None:
        """Handle incoming height broadcast from gossip mesh."""
        height = payload.get("height", 0)
        block_hash = payload.get("block_hash", "")
        sender_node_id = payload.get("sender_node_id", "")
        miner_addr = payload.get("miner_addr", "")

        if height <= 0:
            return

        # Ignore our own broadcasts
        if sender_node_id == self.node_id:
            return

        _EXP_LOG.info(
            f"[GOSSIP-HEIGHT] Mesh broadcast from {sender_node_id[:16] if sender_node_id else 'unknown'}: "
            f"height={height} hash={block_hash[:16] if block_hash else 'none'}..."
        )

        # Update sender's height if known peer
        if sender_node_id and self.peer_mgr:
            sender = self.peer_mgr.get_peer(sender_node_id)
            if sender:
                sender.chain_height = height
                sender.last_seen = int(time.time())

        # Signal chain advance for mining coordination
        try:
            signal_chain_advance(height)
        except Exception as _e:
            _EXP_LOG.debug(f"[GOSSIP-HEIGHT] Chain advance signal failed: {_e}")


