    def _count_hyp_verified_ops(self) -> Dict[str, int]:
        """Count HypΓ-verified operations by type."""
        if self._db is None:
            return {}
        try:
            wallet_ops = self._db.execute(
                "SELECT COUNT(*) FROM wallet_operations WHERE hyp_signed=1"
            ).fetchone()[0]
            rpc_ops = self._db.execute(
                "SELECT COUNT(*) FROM rpc_operations WHERE hyp_verified=1"
            ).fetchone()[0]
            oracle_sigs = self._db.execute(
                "SELECT COUNT(*) FROM hyp_signatures WHERE verified=1"
            ).fetchone()[0]
            verified_blocks = self._db.execute(
                "SELECT COUNT(*) FROM block_verification WHERE hyp_sig_valid=1"
            ).fetchone()[0]
            return {
                "wallet_signed": wallet_ops,
                "rpc_verified": rpc_ops,
                "oracle_signatures": oracle_sigs,
                "verified_blocks": verified_blocks,
            }
        except Exception as _e:
            _EXP_LOG.debug(f"[DB-COUNT] hlwe: {_e}")
            return {}

    def _integrate_rpc_get_block(self, height: int) -> Optional[Dict]:
        """Fetch and log RPC block operation."""
        result = self.api.get_block_by_height(height)
        if result:
            result_hash = hashlib.sha256(
                json.dumps(result, sort_keys=True, default=str).encode()
            ).hexdigest()
            hyp_verified = 1 if result.get("signature") else 0
            self._log_rpc_operation(
                method="get_block",
                params=f"height={height}",
                result_hash=result_hash,
                status="success",
                hyp_verified=hyp_verified,
                block_height=height,
            )
        else:
            self._log_rpc_operation(
                method="get_block",
                params=f"height={height}",
                status="failed",
                error_msg="Block not found",
            )
        return result

    def _integrate_wallet_send(
        self, to_address: str, amount: int, private_key: str = ""
    ) -> str:
        """Send transaction and log wallet operation with HypΓ."""
        tx_data = {
            "sender": self.wallet.address,
            "recipient": to_address,
            "amount": amount,
            "nonce": int(time.time()),
        }
        tx_hash = hashlib.sha256(
            json.dumps(tx_data, sort_keys=True, default=str).encode()
        ).hexdigest()
        sig_data = (
            {"signature": "", "auth_tag": ""}
            if not private_key
            else hyp_sign_transaction(tx_data, private_key)
        )
        sig_hex = sig_data.get("signature", "")
        self._log_wallet_operation(
            wallet_addr=self.wallet.address,
            op_type="send",
            amount=amount,
            peer_addr=to_address,
            tx_hash=tx_hash,
            signature_hex=sig_hex,
        )
        return tx_hash

    def _integrate_wallet_receive(
        self, from_address: str, amount: int, tx_hash: str = ""
    ) -> bool:
        """Log wallet receive operation."""
        return self._log_wallet_operation(
            wallet_addr=self.wallet.address,
            op_type="receive",
            amount=amount,
            peer_addr=from_address,
            tx_hash=tx_hash,
        )

