# NODE RPC MESH SERVER — Full JSON-RPC 2.0 node on port 9091
# ═══════════════════════════════════════════════════════════════════════════════
# Responsibilities:
#   1. Serve every qtcl_* RPC method from local SQLite — zero dependency on main
#      server for read queries once synced.
#   2. Forward write operations (submitBlock, submitTransaction) to main server
#      AND apply locally for dual persistence.
#   3. pq0 Tripartite Entanglement Chain — every oracle snapshot cycle computes
#      the 5×5 ε_ij entanglement coefficient matrix (HMAC-SHA3-256 over quorum
#      hashes) and stores it in pq0_entanglement_log.  The local node is thus
#      cryptographically tethered to the main server's 5-oracle pq0 quorum set.
# ═══════════════════════════════════════════════════════════════════════════════


# ═══════════════════════════════════════════════════════════════════════════════════════
# EXPANSION: P2P CONSENSUS ENGINE — Byzantine fault tolerance for balance queries
# ═══════════════════════════════════════════════════════════════════════════════════════


class P2PConsensusEngine:
    """Multi-node consensus validation with Byzantine tolerance."""

    def __init__(self, tolerance_pct: float = 0.01):
        self.tolerance_pct = tolerance_pct  # 1% divergence allowed
        self.peer_cache = {}

    def consensus_balance(
        self, address: str, local_bal: int, peer_balances: list
    ) -> tuple:
        """Returns (consensus_balance, confidence_score, method)."""
        if not peer_balances:
            return local_bal, 0.5, "local_only"

        all_bals = (
            [local_bal] + peer_balances if local_bal is not None else peer_balances
        )
        if len(all_bals) < 2:
            return all_bals[0] if all_bals else 0, 0.3, "insufficient_peers"

        sorted_bals = sorted(all_bals)
        median = sorted_bals[len(sorted_bals) // 2]
        q1 = sorted_bals[len(sorted_bals) // 4]
        q3 = sorted_bals[3 * len(sorted_bals) // 4]
        iqr = q3 - q1

        outlier_thresh = max(1, int(median * 0.05))
        inlier_count = sum(1 for b in all_bals if abs(b - median) <= outlier_thresh)
        confidence = inlier_count / len(all_bals)

        if confidence >= 0.66:
            return median, confidence, "consensus_majority"
        elif local_bal is not None:
            return local_bal, confidence, "local_fallback"
        else:
            return median, confidence, "peer_median"

    def validate_balance_claim(
        self, address: str, claimed_balance: int, peer_claims: list
    ) -> bool:
        """Byzantine agreement: >66% peers must agree within tolerance."""
        if not peer_claims:
            return True

        tolerance = max(1, int(claimed_balance * 0.1))
        agreeing = sum(
            1 for pb in peer_claims if abs(pb - claimed_balance) <= tolerance
        )

        return agreeing >= len(peer_claims) * 0.66


class BalanceAuditTrail:
    """Persistent balance change audit log."""

    def __init__(self, db_conn_factory):
        self.db_conn_factory = db_conn_factory

    def log_balance_change(
        self, address: str, old_balance: int, new_balance: int, reason: str, height: int
    ) -> bool:
        """Write balance mutation to audit log."""
        try:
            conn = self.db_conn_factory()
            conn.execute(
                """
                INSERT INTO balance_audit (address, old_balance, new_balance, reason, height, timestamp)
                VALUES (?, ?, ?, ?, ?, strftime('%s','now'))
            """,
                (address, old_balance, new_balance, reason, height),
            )
            conn.commit()
            conn.close()
            return True
        except Exception as e:
            logger.error(f"[AUDIT] Balance log failed for {address[:16]}: {e}")
            return False


class RewardClaimValidator:
    """Validate miner reward claims against network consensus."""

    def __init__(self, db_conn_factory):
        self.db_conn_factory = db_conn_factory

    def verify_miner_reward(
        self, height: int, miner_addr: str, claimed_reward_base: int
    ) -> tuple:
        """Returns (is_valid, consensus_reward_base, divergence_pct)."""
        try:
            conn = self.db_conn_factory()
            row = conn.execute(
                "SELECT balance FROM wallet_addresses WHERE address=?", (miner_addr,)
            ).fetchone()
            conn.close()

            if not row:
                return False, 0, 100.0

            stored_reward = int(row[0] or 0)
            if stored_reward == 0:
                return False, 0, 100.0

            divergence = abs(claimed_reward_base - stored_reward) / stored_reward
            is_valid = divergence < 0.01

            return is_valid, stored_reward, divergence * 100.0
        except Exception as e:
            logger.error(f"[REWARD-VERIFY] Check failed h={height}: {e}")
            return False, 0, 100.0


class NodeRPCMeshServer:
    """
    Museum-grade JSON-RPC 2.0 mesh node server.

    Binds port 9091 (configurable via MESH_PORT env).
    Thread-safe: uses ThreadingHTTPServer — every connection gets its own
    worker thread from Python's threading module.
    All SQLite reads use a per-request connection to avoid cross-thread cursor
    sharing on the shared conn object.

    pq0 Tripartite Entanglement:
      On each oracle poll cycle the server fetches
        /rpc  →  qtcl_getQuantumMetrics
      from the main server and derives the entanglement coefficient matrix:
        ε_ij = HMAC-SHA3-256(quorum_hash_i ‖ quorum_hash_j, node_secret)
      This 5×5 symmetric matrix (25 × 32 bytes = 800 bytes) is stored in
      pq0_entanglement_log alongside pq0, block_height, and all oracle IDs.
      Any node that holds the same node_secret can independently verify the
      matrix — forming a quantum-analogue tripartite entanglement link between
      this client node and the 5-oracle server quorum.
    """

    MESH_VERSION = "1.0.0"
    ORACLE_COUNT = 5
    PQ0_POLL_SEC = 30.0  # oracle pq0 pull interval
    SCHEMA_VERSION = "mesh_v1_pq0_tripartite"

    def __init__(self, db_path: Path, main_server_url: str, port: int = 9091):
        self._db_path = db_path
        self._server_url = main_server_url.rstrip("/")
        self._port = port
        self._node_id = hashlib.sha256(
            (os.getenv("HOSTNAME", "") + str(port) + secrets.token_hex(8)).encode()
        ).hexdigest()[:40]
        self._node_secret = hashlib.sha3_256(
            (self._node_id + str(port)).encode()
        ).digest()
        self._stop = threading.Event()
        self._http_server: Optional[ThreadingHTTPServer] = None
        self._oracle_state: dict = {}
        self._oracle_lock = threading.Lock()
        self._pq0_epoch = 0
        self._entangle_log: list = []  # ring buffer, last 256 epochs
        logger.info(
            f"[MESH] ✅ NodeRPCMeshServer init  node={self._node_id[:16]}…  "
            f"port={self._port}  server={self._server_url}"
        )

    # ─────────────────────────────────────────────────────────────────────────
    # ─────────────────────────────────────────────────────────────────────────
    # pq0 Entanglement Engine
    # ─────────────────────────────────────────────────────────────────────────
    def _compute_epsilon_matrix(self, quorum_hashes: list) -> bytes:
        """
        Compute the 5×5 entanglement coefficient matrix.
        ε_ij = HMAC-SHA3-256(quorum_hash_i ‖ quorum_hash_j, node_secret)
        Result: 25 × 32 bytes = 800 bytes, row-major.
        Diagonal ε_ii = HMAC(h_i ‖ h_i, node_secret) — self-entanglement.
        """
        n = len(quorum_hashes)
        out = bytearray()
        for i in range(n):
            for j in range(n):
                hi = (
                    quorum_hashes[i].encode()
                    if isinstance(quorum_hashes[i], str)
                    else quorum_hashes[i]
                )
                hj = (
                    quorum_hashes[j].encode()
                    if isinstance(quorum_hashes[j], str)
                    else quorum_hashes[j]
                )
                msg = hi + hj
                epsilon = hmac.new(self._node_secret, msg, hashlib.sha3_256).digest()
                out.extend(epsilon)
        return bytes(out)

    def _tripartite_fidelity(self, epsilon_matrix: bytes) -> float:
        """
        Scalar fidelity of the tripartite link:
          F = mean(|ε_ij|) over off-diagonal elements normalised to [0,1].
        Uses the first byte of each 32-byte ε_ij coefficient as the amplitude.
        """
        n = self.ORACLE_COUNT
        total = n * n
        cell = 32  # bytes per ε_ij
        if len(epsilon_matrix) < total * cell:
            return 0.0
        off_diag_vals = []
        for i in range(n):
            for j in range(n):
                if i != j:
                    offset = (i * n + j) * cell
                    byte = epsilon_matrix[offset]
                    off_diag_vals.append(byte / 255.0)
        return sum(off_diag_vals) / len(off_diag_vals) if off_diag_vals else 0.0

    def _poll_oracle_and_entangle(self) -> None:
        """
        Background daemon: pulls oracle snapshot every PQ0_POLL_SEC seconds,
        computes ε matrix, persists to pq0_entanglement_log.
        """
        while not self._stop.is_set():
            try:
                snap = self._fetch_server_rpc("qtcl_getQuantumMetrics", [])
                if snap:
                    with self._oracle_lock:
                        self._oracle_state = snap
                    self._record_entanglement(snap)
            except Exception as _pe:
                logger.debug(f"[MESH-ENT] poll error: {_pe}")
            self._stop.wait(self.PQ0_POLL_SEC)

    def _record_entanglement(self, snap: dict) -> None:
        """Derive and persist one epoch of the pq0 tripartite entanglement log."""
        import sqlite3  # NodeRPCMeshServer scope

        try:
            block_height = int(snap.get("block_height") or snap.get("height") or 0)
            server_pq0 = int(snap.get("pq_curr") or snap.get("pq0") or block_height)
            oracle_ids = snap.get("oracle_ids") or [
                f"oracle_{i + 1}" for i in range(self.ORACLE_COUNT)
            ]
            # Build quorum hash list — use per-oracle hashes if present,
            # else derive deterministically from snapshot quorum_hash
            base_qhash = (
                snap.get("quorum_hash_hex")
                or snap.get("consensus", {}).get("quorum_hash")
                or hashlib.sha3_256(
                    json.dumps(snap, sort_keys=True, default=str).encode()
                ).hexdigest()
            )
            quorum_hashes = []
            for i in range(self.ORACLE_COUNT):
                # Oracle-specific quorum hash: HMAC(base_qhash, oracle_id_i)
                oracle_key = f"oracle_{i + 1}".encode()
                oracle_qhash = hmac.new(
                    base_qhash.encode() if isinstance(base_qhash, str) else base_qhash,
                    oracle_key,
                    hashlib.sha3_256,
                ).hexdigest()
                quorum_hashes.append(oracle_qhash)

            epsilon = self._compute_epsilon_matrix(quorum_hashes)
            fidelity = self._tripartite_fidelity(epsilon)
            consensus_score = float(
                snap.get("consensus", {}).get("agreement_score")
                or snap.get("w_state_fidelity")
                or 0.0
            )
            self._pq0_epoch += 1
            epoch = self._pq0_epoch

            # Persist to pq0_entanglement_log using correct schema
            conn = sqlite3.connect(
                str(self._db_path), timeout=10, check_same_thread=False
            )
            try:
                conn.execute(
                    """
                    INSERT INTO pq0_entanglement_log
                      (epoch, block_height, pq0, oracle_ids, entanglement_matrix_hex)
                    VALUES (?,?,?,?,?)
                """,
                    (
                        epoch,
                        block_height,
                        server_pq0,
                        ",".join(oracle_ids[: self.ORACLE_COUNT]),
                        epsilon.hex(),
                    ),
                )
                # Prune to last 10000 entries
                conn.execute("""
                    DELETE FROM pq0_entanglement_log
                    WHERE id NOT IN (
                        SELECT id FROM pq0_entanglement_log
                        ORDER BY block_height DESC LIMIT 10000
                    )
                """)
                conn.commit()
            finally:
                conn.close()

            logger.debug(
                f"[MESH-ENT] epoch={epoch}  h={block_height}  "
                f"pq0={server_pq0}  F={fidelity:.4f}"
            )
        except Exception as _e:
            _fc = getattr(self, "_ent_fail_count", 0) + 1
            self._ent_fail_count = _fc
            if _fc == 1 or _fc % 10 == 0:
                logger.warning(f"[MESH-ENT] record_entanglement failed (#{_fc}): {_e}")

    # ─────────────────────────────────────────────────────────────────────────
    # HTTP helpers
    # ─────────────────────────────────────────────────────────────────────────
    def _fetch_server_rpc(self, method: str, params: list, timeout: float = 8.0) -> Any:
        """Execute a JSON-RPC 2.0 call against the main server."""
        try:
            from urllib.parse import urlencode

            params_json = json.dumps(params)
            query = urlencode({"method": method, "params": params_json, "id": 1})
            full_url = f"{self._server_url}/rpc?{query}"
            req = Request(full_url)
            with urlopen(req, timeout=timeout) as resp:
                body = json.loads(resp.read())
            result = body.get("result")
            if result is None and "error" in body:
                logger.debug(f"[MESH-RPC] server error {method}: {body['error']}")
            return result
        except Exception as _e:
            logger.debug(f"[MESH-RPC] {method} server call failed: {_e}")
            return None

    def _db_conn(self) -> sqlite3.Connection:
        """Open a fresh per-request read connection (thread-safe)."""
        import sqlite3

        db_path = str(self._db_path)
        if not os.path.exists(db_path):
            logger.warning(f"[MESH] DB file not found: {db_path}, creating...")
        conn = sqlite3.connect(db_path, timeout=10, check_same_thread=False)
        conn.row_factory = sqlite3.Row  # Enable dict-like access: row["column"]
        # Ensure tables the mesh RPC methods depend on exist
        try:
            conn.execute(
                "CREATE TABLE IF NOT EXISTS p2p_peers ("
                " node_id TEXT,"
                " node_id_hex TEXT,"
                " host TEXT NOT NULL,"
                " port INTEGER NOT NULL DEFAULT 9091,"
                " services INTEGER DEFAULT 0,"
                " protocol_version INTEGER DEFAULT 2,"
                " chain_height INTEGER DEFAULT 0,"
                " last_fidelity REAL DEFAULT 0.0,"
                " latency_ms REAL DEFAULT 0.0,"
                " source TEXT DEFAULT 'dht',"
                " first_seen_at INTEGER DEFAULT 0,"
                " last_seen_at INTEGER DEFAULT 0,"
                " last_heartbeat_at INTEGER DEFAULT 0,"
                " external_addr TEXT,"
                " capabilities TEXT,"
                " mac_address TEXT,"
                " device_id TEXT,"
                " ban_score INTEGER DEFAULT 0,"
                " PRIMARY KEY (host, port)"
                ")"
            )
            # ALTER existing tables to add missing columns (idempotent)
            _required_cols = {
                "node_id": "TEXT",
                "node_id_hex": "TEXT",
                "services": "INTEGER DEFAULT 0",
                "protocol_version": "INTEGER DEFAULT 2",
                "chain_height": "INTEGER DEFAULT 0",
                "last_fidelity": "REAL DEFAULT 0.0",
                "latency_ms": "REAL DEFAULT 0.0",
                "source": "TEXT DEFAULT 'dht'",
                "first_seen_at": "INTEGER DEFAULT 0",
                "last_seen_at": "INTEGER DEFAULT 0",
                "last_heartbeat_at": "INTEGER DEFAULT 0",
                "external_addr": "TEXT",
                "capabilities": "TEXT",
                "mac_address": "TEXT",
                "device_id": "TEXT",
                "ban_score": "INTEGER DEFAULT 0",
            }
            try:
                existing = {
                    row[1]
                    for row in conn.execute("PRAGMA table_info(p2p_peers)").fetchall()
                }
                for col, ddl in _required_cols.items():
                    if col not in existing:
                        try:
                            conn.execute(
                                f"ALTER TABLE p2p_peers ADD COLUMN {col} {ddl}"
                            )
                        except Exception:
                            pass
            except Exception:
                pass
            conn.execute(
                "CREATE TABLE IF NOT EXISTS mesh_rpc_log ("
                " id INTEGER PRIMARY KEY AUTOINCREMENT,"
                " method TEXT,"
                " params_hash TEXT,"
                " result_ok INTEGER,"
                " latency_ms REAL,"
                " peer_addr TEXT,"
                " created_at INTEGER DEFAULT (strftime('%s','now'))"
                ")"
            )
            conn.execute(
                "CREATE TABLE IF NOT EXISTS gossip_inventory ("
                " id INTEGER PRIMARY KEY AUTOINCREMENT,"
                " event_type TEXT,"
                " channel TEXT,"
                " peer_id TEXT,"
                " payload TEXT,"
                " created_at INTEGER DEFAULT (strftime('%s','now'))"
                ")"
            )
            conn.execute(
                "CREATE TABLE IF NOT EXISTS pending_rewards ("
                " id INTEGER PRIMARY KEY AUTOINCREMENT,"
                " height INTEGER NOT NULL,"
                " reward_type TEXT NOT NULL,"
                " recipient TEXT NOT NULL,"
                " amount INTEGER NOT NULL,"
                " confirmed_at_height INTEGER DEFAULT NULL,"
                " status TEXT DEFAULT 'pending',"
                " created_at INTEGER DEFAULT (strftime('%s','now')),"
                " UNIQUE(height, reward_type, recipient)"
                ")"
            )
            conn.commit()
        except Exception:
            pass
        return conn

    # ─────────────────────────────────────────────────────────────────────────
    # RPC method implementations
    # ─────────────────────────────────────────────────────────────────────────
    def _rpc_getBlockHeight(self, params: list) -> dict:
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT MAX(height) AS h, hash FROM blocks "
                "WHERE height=(SELECT MAX(height) FROM blocks)"
            ).fetchone()
            h = int(row["h"] or 0) if row else 0
            tip = str(row["hash"] or "") if row else ""
            return {"height": h, "tip_hash": tip}
        finally:
            conn.close()

    def _rpc_getBestBlockHash(self, params: list) -> dict:
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT hash FROM blocks ORDER BY height DESC LIMIT 1"
            ).fetchone()
            return {"hash": str(row["hash"]) if row else ""}
        finally:
            conn.close()

    def _rpc_getBlock(self, params: list) -> Optional[dict]:
        height = int(params[0]) if params else 0
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT * FROM blocks WHERE height=?", (height,)
            ).fetchone()
            if not row:
                return None
            blk = dict(row)
            data = blk.get("data")
            if data:
                try:
                    blk.update(json.loads(data))
                except Exception:
                    pass
            # Attach transactions
            txs = conn.execute(
                "SELECT * FROM transactions WHERE block_height=?", (height,)
            ).fetchall()
            blk["transactions"] = [dict(t) for t in txs]
            return blk
        finally:
            conn.close()

    def _rpc_getBlockRange(self, params: list) -> dict:
        start = int(params[0]) if len(params) > 0 else 0
        end = int(params[1]) if len(params) > 1 else start + 99
        conn = self._db_conn()
        try:
            rows = conn.execute(
                "SELECT * FROM blocks WHERE height BETWEEN ? AND ? ORDER BY height ASC",
                (start, end),
            ).fetchall()
            blocks = []
            for row in rows:
                blk = dict(row)
                data = blk.get("data")
                if data:
                    try:
                        blk.update(json.loads(data))
                    except Exception:
                        pass
                txs = conn.execute(
                    "SELECT * FROM transactions WHERE block_height=?",
                    (blk["height"],),
                ).fetchall()
                blk["transactions"] = [dict(t) for t in txs]
                blocks.append(blk)
            return {"blocks": blocks, "count": len(blocks)}
        finally:
            conn.close()

    def _rpc_getChainStatus(self, params: list) -> dict:
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT MAX(height) AS h, COUNT(*) AS total FROM blocks"
            ).fetchone()
            h = int(row["h"] or 0)
            total = int(row["total"] or 0)
            tip = conn.execute(
                "SELECT hash, difficulty, w_state_fidelity FROM blocks WHERE height=?",
                (h,),
            ).fetchone()
            sync_row = conn.execute(
                "SELECT value FROM sync_state WHERE key='last_sync_ts'"
            ).fetchone()
            with self._oracle_lock:
                oracle = dict(self._oracle_state)
            return {
                "height": h,
                "total_blocks": total,
                "tip_hash": str(tip["hash"]) if tip else "",
                "difficulty": float(tip["difficulty"] or 4.0) if tip else 4.0,
                "w_state_fidelity": float(tip["w_state_fidelity"] or 0.0)
                if tip
                else 0.0,
                "last_sync_ts": int(sync_row["value"] or 0) if sync_row else 0,
                "node_id": self._node_id,
                "mesh_version": self.MESH_VERSION,
                "pq0_epoch": self._pq0_epoch,
                "oracle_fidelity": oracle.get("w_state_fidelity", 0.0),
            }
        finally:
            conn.close()

    def _rpc_getQuantumMetrics(self, params: list) -> dict:
        """Return local oracle state (last polled from main server)."""
        with self._oracle_lock:
            snap = dict(self._oracle_state)
        if not snap:
            # Cold start — pull synchronously once
            snap = self._fetch_server_rpc("qtcl_getQuantumMetrics", []) or {}
            if snap:
                with self._oracle_lock:
                    self._oracle_state = snap
        return snap

    def _rpc_getOraclePq0(self, params: list) -> dict:
        with self._oracle_lock:
            snap = dict(self._oracle_state)
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT block_height, pq0, oracle_ids, entanglement_matrix_hex "
                "FROM pq0_entanglement_log ORDER BY block_height DESC LIMIT 1"
            ).fetchone()
            latest = dict(row) if row else {}
            if latest.get("entanglement_matrix_hex"):
                latest["entanglement_matrix_hex"] = (
                    latest["entanglement_matrix_hex"][:64] + "…"
                )
            return {
                "pq0": int(snap.get("pq_curr") or 0),
                "server_pq0": int(snap.get("pq_curr") or 0),
                "oracle_count": self.ORACLE_COUNT,
                "pq0_epoch": self._pq0_epoch,
                "block_height": latest.get("block_height", 0),
                "oracle_ids": (latest.get("oracle_ids") or "").split(","),
                "node_id": self._node_id,
            }
        finally:
            conn.close()

    def _rpc_getPq0Matrix(self, params: list) -> dict:
        """Return the latest full entanglement matrix for independent verification."""
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT block_height, pq0, oracle_ids, entanglement_matrix_hex "
                "FROM pq0_entanglement_log ORDER BY block_height DESC LIMIT 1"
            ).fetchone()
            if not row:
                return {"error": "no entanglement data yet"}
            return {
                "block_height": row["block_height"],
                "pq0": row["pq0"],
                "oracle_ids": (row["oracle_ids"] or "").split(","),
                "entanglement_matrix_hex": row["entanglement_matrix_hex"] or "",
            }
        finally:
            conn.close()

    def _rpc_getConsensusSnapshot(self, params: list) -> dict:
        conn = self._db_conn()
        try:
            row = conn.execute(
                "SELECT * FROM wstate_consensus_log ORDER BY block_height DESC LIMIT 1"
            ).fetchone()
            snap = dict(row) if row else {}
            with self._oracle_lock:
                oracle = dict(self._oracle_state)
            snap["oracle_fidelity"] = oracle.get("w_state_fidelity", 0.0)
            snap["pq0_epoch"] = self._pq0_epoch
            return snap
        finally:
            conn.close()

    def _rpc_getPeers(self, params: list) -> dict:
        conn = self._db_conn()
        try:
            rows = conn.execute(
                "SELECT node_id_hex, host, port, chain_height, "
                "last_fidelity, last_seen_at FROM p2p_peers "
                "WHERE ban_score < 50 ORDER BY last_seen_at DESC LIMIT 64"
            ).fetchall()
            return {
                "peers": [dict(r) for r in rows],
                "count": len(rows),
                "node_id": self._node_id,
            }
        finally:
            conn.close()

    def _rpc_getWalletBalance(self, params: list) -> dict:
        """Balance consensus: local oracle → P2P neighbor median → Koyeb fallback."""
        import time as _time
        import urllib.request as _ur2
        import json as _jb2

        address = params[0] if params else ""
        if not address:
            return {"error": "address required"}

        _local_bal_base = None
        _local_height = 0
        try:
            conn = self._db_conn()
            try:
                row = conn.execute(
                    "SELECT balance, transaction_count, balance_at_height FROM wallet_addresses WHERE address=?",
                    (address,),
                ).fetchone()
                if row:
                    _local_bal_base = int(row["balance"] or 0)
                    _local_height = int(row["balance_at_height"] or 0)
            finally:
                conn.close()
        except Exception as _le:
            logger.debug(f"[BALANCE] Local read failed: {_le}")

        _neighbor_bals = []
        try:
            _peers_conn = self._db_conn()
            try:
                _cutoff = int(_time.time()) - 300
                _peer_rows = _peers_conn.execute(
                    "SELECT host, port FROM p2p_peers WHERE last_seen_at>? ORDER BY last_seen_at DESC LIMIT 6",
                    (_cutoff,),
                ).fetchall()
            finally:
                _peers_conn.close()

            for _pr in _peer_rows or []:
                try:
                    _purl = f"http://{_pr['host']}:{_pr['port']}/rpc"
                    _pbody = _jb2.dumps(
                        {
                            "jsonrpc": "2.0",
                            "method": "qtcl_getBalance",
                            "params": [address],
                            "id": 1,
                        }
                    ).encode()
                    _preq = _ur2.Request(
                        _purl,
                        data=_pbody,
                        headers={"Content-Type": "application/json"},
                        method="POST",
                    )
                    _presp = _jb2.loads(_ur2.urlopen(_preq, timeout=2).read())
                    _pbal = _presp.get("result", {}).get("balance_atomic")
                    if _pbal is not None:
                        _neighbor_bals.append(int(_pbal))
                except Exception:
                    pass
        except Exception as _pe:
            logger.debug(f"[BALANCE] P2P neighbor query failed: {_pe}")

        _consensus_bal_base = None
        if len(_neighbor_bals) >= 2:
            _sorted = sorted(_neighbor_bals)
            _median = _sorted[len(_sorted) // 2]
            if _local_bal_base is not None:
                _tolerance = max(1, int(_local_bal_base * 0.05))
                if abs(_median - _local_bal_base) <= _tolerance:
                    _consensus_bal_base = _median
                else:
                    logger.warning(
                        f"[BALANCE] P2P divergence {address[:20]}…: local={_local_bal_base} p2p={_median}"
                    )
                    _consensus_bal_base = _median
            else:
                _consensus_bal_base = _median
        elif _local_bal_base is not None:
            _consensus_bal_base = _local_bal_base

        if _consensus_bal_base is None:
            try:
                _koyeb_result = self._fetch_server_rpc("qtcl_getBalance", [address])
                if isinstance(_koyeb_result, dict) and "balance" in _koyeb_result:
                    _koyeb_base = int(round(float(_koyeb_result["balance"]) * 100))
                    try:
                        _wconn = self._db_conn()
                        try:
                            _wconn.execute(
                                "INSERT OR IGNORE INTO wallet_addresses (address,public_key,wallet_fingerprint,balance,address_type,balance_updated_at,balance_at_height,created_at,transaction_count) VALUES (?,?,?,0,'standard',strftime('%s','now'),0,strftime('%s','now'),0)",
                                (address, address[:64], address[:64]),
                            )
                            _wconn.execute(
                                "UPDATE wallet_addresses SET balance=?, balance_updated_at=strftime('%s','now') WHERE address=?",
                                (_koyeb_base, address),
                            )
                            _wconn.commit()
                        finally:
                            _wconn.close()
                    except Exception:
                        pass
                    _consensus_bal_base = _koyeb_base
            except Exception as _ke:
                logger.debug(f"[BALANCE] Koyeb fallback failed: {_ke}")

        _final_base = _consensus_bal_base if _consensus_bal_base is not None else 0
        return {
            "address": address,
            "balance": _final_base / 100.0,
            "balance_atomic": _final_base,
            "transaction_count": 0,
            "balance_at_height": _local_height,
            "source": (
                "p2p_consensus"
                if len(_neighbor_bals) >= 2
                else "local"
                if _local_bal_base is not None
                else "koyeb"
                if _consensus_bal_base is not None
                else "default"
            ),
            "p2p_neighbor_count": len(_neighbor_bals),
        }

    # ─────────────────────────────────────────────────────────────────────────
    # MEMPOOL / SYNC / NODE-INFO / ENTROPY / DHT / HEARTBEAT
    # ─────────────────────────────────────────────────────────────────────────
    def _rpc_getMempoolInfo(self, params: list) -> dict:
        """Return pending mempool transaction count + volume.
        Mirrors Koyeb server truth with local pending-tx buffer."""
        local_pending = 0
        local_volume = 0
        try:
            conn = self._db_conn()
            try:
                row = conn.execute(
                    "SELECT COUNT(*) AS n, COALESCE(SUM(amount),0) AS v "
                    "FROM transactions WHERE status='pending' OR status='mempool'"
                ).fetchone()
                if row:
                    local_pending = int(row["n"] or 0)
                    local_volume = int(row["v"] or 0)
            finally:
                conn.close()
        except Exception as _le:
            logger.debug(f"[MEMPOOL] local read failed: {_le}")

        server_snap = None
        try:
            server_snap = self._fetch_server_rpc("qtcl_getMempoolInfo", [])
        except Exception:
            server_snap = None

        merged_pending = local_pending
        merged_volume = local_volume
        if isinstance(server_snap, dict):
            merged_pending = max(local_pending, int(server_snap.get("pending", 0) or 0))
            merged_volume = max(
                local_volume, int(server_snap.get("volume_base", 0) or 0)
            )

        return {
            "pending": merged_pending,
            "volume_base": merged_volume,
            "volume_qtcl": merged_volume / 100.0,
            "local_pending": local_pending,
            "koyeb_pending": (server_snap or {}).get("pending", 0)
            if isinstance(server_snap, dict)
            else 0,
            "source": "dual_truth" if server_snap else "local_only",
        }

    def _rpc_getSyncStatus(self, params: list) -> dict:
        """Report local vs Koyeb chain-tip delta for sync health."""
        local_h = 0
        local_hash = ""
        try:
            conn = self._db_conn()
            try:
                r = conn.execute("SELECT MAX(height) AS h FROM blocks").fetchone()
                if r and r["h"] is not None:
                    local_h = int(r["h"])
                r2 = conn.execute(
                    "SELECT block_hash FROM blocks WHERE height=? LIMIT 1", (local_h,)
                ).fetchone()
                if r2:
                    local_hash = r2["block_hash"] or ""
            finally:
                conn.close()
        except Exception as _e:
            logger.debug(f"[SYNC] local read: {_e}")

        koyeb_h = 0
        koyeb_hash = ""
        try:
            r = self._fetch_server_rpc("qtcl_getChainStatus", [])
            if isinstance(r, dict):
                koyeb_h = int(r.get("height", r.get("chain_height", 0)) or 0)
                koyeb_hash = str(
                    r.get("best_block_hash", r.get("head_block_hash", "")) or ""
                )
        except Exception:
            pass

        delta = koyeb_h - local_h
        in_sync = (delta <= 1) and (local_hash == koyeb_hash or koyeb_hash == "")

        return {
            "local_height": local_h,
            "local_hash": local_hash,
            "koyeb_height": koyeb_h,
            "koyeb_hash": koyeb_hash,
            "delta": delta,
            "in_sync": in_sync,
            "sync_percent": round((local_h / koyeb_h * 100.0), 2)
            if koyeb_h > 0
            else 0.0,
        }

    def _rpc_nodeInfo(self, params: list) -> dict:
        """Self-describe: node identity, version, uptime, endpoints."""
        uptime = 0.0
        try:
            uptime = time.time() - getattr(self, "_start_ts", time.time())
        except Exception:
            pass
        external_wan = os.getenv("EXTERNAL_WAN", os.getenv("WAN_IP", ""))
        external_port = self._port
        return {
            "node_id": self._node_id,
            "mesh_version": self.MESH_VERSION,
            "schema_version": self.SCHEMA_VERSION,
            "uptime_sec": round(uptime, 2),
            "port": external_port,
            "external_addr": f"{external_wan}:{external_port}"
            if external_wan
            else f"0.0.0.0:{external_port}",
            "server_url": self._server_url,
            "oracle_count": self.ORACLE_COUNT,
            "pq0_epoch": self._pq0_epoch,
            "methods": sorted(list(self._METHODS.keys()))
            if hasattr(self, "_METHODS")
            else [],
        }

    def _rpc_getEntropy(self, params: list) -> dict:
        """Return a fresh 32-byte entropy nugget derived from local QRNG pool + server pq0."""
        try:
            n_bytes = int(params[0]) if params else 32
        except Exception:
            n_bytes = 32
        n_bytes = max(8, min(n_bytes, 1024))

        local_seed = os.urandom(n_bytes)
        server_nugget = None
        try:
            r = self._fetch_server_rpc("qtcl_getEntropy", [n_bytes])
            if isinstance(r, dict) and "entropy_hex" in r:
                server_nugget = bytes.fromhex(r["entropy_hex"])[:n_bytes]
        except Exception:
            pass

        if server_nugget and len(server_nugget) == n_bytes:
            merged = bytes(a ^ b for a, b in zip(local_seed, server_nugget))
            source = "xor_local_koyeb"
        else:
            merged = local_seed
            source = "local_only"

        return {
            "entropy_hex": merged.hex(),
            "bytes": len(merged),
            "source": source,
        }

    def _rpc_getDHTTable(self, params: list) -> dict:
        """Return this node's Kademlia-style peer table snapshot."""
        peers = []
        try:
            conn = self._db_conn()
            try:
                cutoff = int(time.time()) - 600
                rows = conn.execute(
                    "SELECT host, port, last_seen_at, chain_height, node_id "
                    "FROM p2p_peers WHERE last_seen_at>? "
                    "ORDER BY last_seen_at DESC LIMIT 128",
                    (cutoff,),
                ).fetchall()
                for row in rows:
                    peers.append(
                        {
                            "host": row["host"],
                            "port": int(row["port"] or 9091),
                            "node_id": row["node_id"] or "",
                            "last_seen_at": int(row["last_seen_at"] or 0),
                            "chain_height": int(row["chain_height"] or 0),
                        }
                    )
            finally:
                conn.close()
        except Exception as _e:
            logger.debug(f"[DHT] read error: {_e}")

        return {
            "node_id": self._node_id,
            "peer_count": len(peers),
            "peers": peers,
            "timestamp": int(time.time()),
        }

    def _rpc_receiveDHTTable(self, params: list) -> dict:
        """Accept another peer's DHT table and merge into p2p_peers."""
        if not params or not isinstance(params[0], dict):
            return {"accepted": 0, "error": "params[0] must be dict"}
        payload = params[0]
        incoming = payload.get("peers", []) or []
        origin = str(payload.get("node_id", ""))[:64]
        now = int(time.time())
        accepted = 0
        try:
            conn = self._db_conn()
            try:
                for p in incoming[:256]:
                    try:
                        host = str(p.get("host", ""))[:64]
                        port = int(p.get("port", 9091))
                        node_id = str(p.get("node_id", ""))[:64]
                        ch = int(p.get("chain_height", 0))
                        if not host or not port:
                            continue
                        conn.execute(
                            "INSERT OR REPLACE INTO p2p_peers "
                            "(host, port, node_id, chain_height, last_seen_at) "
                            "VALUES (?,?,?,?,?)",
                            (host, port, node_id, ch, now),
                        )
                        accepted += 1
                    except Exception:
                        continue
                conn.commit()
            finally:
                conn.close()
        except Exception as _e:
            logger.debug(f"[DHT] receive error: {_e}")
        return {"accepted": accepted, "origin": origin, "total_sent": len(incoming)}

    def _rpc_peerHeartbeat(self, params: list) -> dict:
        """Peer liveness ping — updates last_seen and returns our tip."""
        if params and isinstance(params[0], dict):
            p = params[0]
            host = str(p.get("host", ""))[:64]
            port = int(p.get("port", 9091))
            node_id = str(p.get("node_id", ""))[:64]
            ch = int(p.get("chain_height", 0))
            if host:
                try:
                    conn = self._db_conn()
                    try:
                        conn.execute(
                            "INSERT OR REPLACE INTO p2p_peers "
                            "(host, port, node_id, chain_height, last_seen_at) "
                            "VALUES (?,?,?,?,?)",
                            (host, port, node_id, ch, int(time.time())),
                        )
                        conn.commit()
                    finally:
                        conn.close()
                except Exception:
                    pass

        local_h = 0
        local_hash = ""
        try:
            conn = self._db_conn()
            try:
                r = conn.execute("SELECT MAX(height) AS h FROM blocks").fetchone()
                if r and r["h"] is not None:
                    local_h = int(r["h"])
                    r2 = conn.execute(
                        "SELECT block_hash FROM blocks WHERE height=? LIMIT 1",
                        (local_h,),
                    ).fetchone()
                    if r2:
                        local_hash = r2["block_hash"] or ""
            finally:
                conn.close()
        except Exception:
            pass

        return {
            "pong": True,
            "node_id": self._node_id,
            "chain_height": local_h,
            "best_hash": local_hash,
            "timestamp": int(time.time()),
        }

    # ─────────────────────────────────────────────────────────────────────────
    # BLOCK + TRANSACTION SUBMISSION (dual-truth: Koyeb primary + local SQLite)
    # ─────────────────────────────────────────────────────────────────────────
    def _rpc_submitBlock(self, params: list) -> dict:
        """Submit a block: dispatch to Koyeb (primary truth) then mirror into local SQLite.
        Cryptographic linkage: coinbase(miner, 7.2 QTCL) embedded IN this block.
        Treasury 0.8 QTCL is queued as pending_reward, requiring NEXT-block confirmation."""
        if not params or not isinstance(params[0], dict):
            return {"accepted": False, "error": "params[0] must be dict"}
        block = params[0]
        hdr = block.get("header", block)
        height = int(hdr.get("height", 0))
        block_hash = str(hdr.get("block_hash", hdr.get("hash", "")))
        parent_hash = str(hdr.get("parent_hash", "0" * 64))
        merkle_root = str(
            hdr.get("merkle_root", hdr.get("transactions_root", "0" * 64))
        )
        timestamp_s = int(hdr.get("timestamp", int(time.time())))
        nonce = int(hdr.get("nonce", 0))
        miner_address = str(hdr.get("miner_address", hdr.get("miner", "")))
        difficulty = int(hdr.get("difficulty", 6))
        w_entropy_hex = str(
            hdr.get("w_entropy_hash", hdr.get("oracle_w_state_hash", ""))
        )
        txs = block.get("transactions", block.get("txs", [])) or []

        if not height or not block_hash or not miner_address:
            return {
                "accepted": False,
                "error": "height/block_hash/miner_address required",
            }

        # Verify cryptographic miner coinbase presence (7.2 QTCL self-embedded)
        _miner_coinbase_found = False
        _treasury_coinbase_found = False
        for tx in txs:
            if str(tx.get("tx_type", "")).lower() == "coinbase":
                _to = tx.get("to_addr", tx.get("to_address", ""))
                _amt = float(tx.get("amount", 0))
                if _to == miner_address and abs(_amt - 7.2) < 0.01:
                    _miner_coinbase_found = True
                elif "treasury" in _to.lower() and abs(_amt - 0.8) < 0.01:
                    _treasury_coinbase_found = True

        if not _miner_coinbase_found:
            logger.warning(
                f"[SUBMIT-BLOCK] h={height} missing 7.2 QTCL miner coinbase to {miner_address[:20]}..."
            )
            return {
                "accepted": False,
                "error": "Block missing miner coinbase (7.2 QTCL)",
            }

        # === 1. Primary truth: push to Koyeb ===
        koyeb_result = None
        try:
            koyeb_result = self._fetch_server_rpc(
                "qtcl_submitBlock", [block], timeout=20.0
            )
        except Exception as _ke:
            logger.warning(f"[SUBMIT-BLOCK] Koyeb push failed: {_ke}")

        koyeb_accepted = isinstance(koyeb_result, dict) and (
            koyeb_result.get("status") == "accepted"
            or koyeb_result.get("accepted") is True
        )

        # === 2. Mirror into local SQLite (secondary truth) ===
        local_persisted = False
        try:
            conn = self._db_conn()
            try:
                conn.execute(
                    "INSERT OR IGNORE INTO blocks "
                    "(height, block_hash, parent_hash, merkle_root, timestamp, "
                    " miner_address, difficulty, nonce, oracle_w_state_hash, "
                    " transaction_count, data) "
                    "VALUES (?,?,?,?,?,?,?,?,?,?,?)",
                    (
                        height,
                        block_hash,
                        parent_hash,
                        merkle_root,
                        timestamp_s,
                        miner_address,
                        difficulty,
                        nonce,
                        w_entropy_hex[:64] if w_entropy_hex else "0" * 64,
                        len(txs),
                        json.dumps(block, default=str)[:65536],
                    ),
                )
                # Persist all transactions
                for tx in txs:
                    tx_id = str(tx.get("tx_id") or tx.get("tx_hash", ""))
                    if not tx_id:
                        continue
                    try:
                        conn.execute(
                            "INSERT OR REPLACE INTO transactions "
                            "(tx_hash, from_address, to_address, amount, tx_type, "
                            " status, height, block_hash, created_at) "
                            "VALUES (?,?,?,?,?,?,?,?,?)",
                            (
                                tx_id,
                                str(
                                    tx.get(
                                        "from_addr", tx.get("from_address", "0" * 64)
                                    )
                                ),
                                str(tx.get("to_addr", tx.get("to_address", ""))),
                                int(round(float(tx.get("amount", 0)) * 100)),
                                str(tx.get("tx_type", "transfer")),
                                "confirmed",
                                height,
                                block_hash,
                                timestamp_s,
                            ),
                        )
                    except Exception as _txe:
                        logger.debug(
                            f"[SUBMIT-BLOCK] local tx insert {tx_id[:16]}: {_txe}"
                        )

                # Credit miner 7.2 QTCL NOW (embedded in this block)
                miner_reward_base = 720
                conn.execute(
                    "INSERT INTO wallet_addresses "
                    "(address, public_key, wallet_fingerprint, balance, "
                    " address_type, balance_at_height, balance_updated_at, "
                    " created_at, transaction_count) "
                    "VALUES (?,?,?,?,?,?,strftime('%s','now'),strftime('%s','now'),1) "
                    "ON CONFLICT(address) DO UPDATE SET "
                    " balance = balance + ?, "
                    " transaction_count = transaction_count + 1, "
                    " balance_at_height = ?, "
                    " balance_updated_at = strftime('%s','now')",
                    (
                        miner_address,
                        miner_address[:64],
                        miner_address[:64],
                        miner_reward_base,
                        "miner",
                        height,
                        miner_reward_base,
                        height,
                    ),
                )

                # Treasury 0.8 QTCL → pending_rewards (requires NEXT block confirmation)
                conn.execute(
                    "CREATE TABLE IF NOT EXISTS pending_rewards ("
                    " id INTEGER PRIMARY KEY AUTOINCREMENT,"
                    " height INTEGER NOT NULL,"
                    " reward_type TEXT NOT NULL,"
                    " recipient TEXT NOT NULL,"
                    " amount INTEGER NOT NULL,"
                    " confirmed_at_height INTEGER DEFAULT NULL,"
                    " status TEXT DEFAULT 'pending',"
                    " created_at INTEGER DEFAULT (strftime('%s','now')),"
                    " UNIQUE(height, reward_type, recipient)"
                    ")"
                )
                treasury_address = (
                    "qtcl1treasury0reward0dist0address00000000000000000000001"
                )
                treasury_reward_base = 80
                try:
                    conn.execute(
                        "INSERT OR IGNORE INTO pending_rewards "
                        "(height, reward_type, recipient, amount, status) "
                        "VALUES (?, 'treasury', ?, ?, 'pending')",
                        (height, treasury_address, treasury_reward_base),
                    )
                except Exception:
                    pass

                # ← Confirm PRIOR block's pending treasury reward (height-1)
                try:
                    prev = conn.execute(
                        "SELECT id, recipient, amount FROM pending_rewards "
                        "WHERE height=? AND status='pending'",
                        (height - 1,),
                    ).fetchall()
                    for pr in prev:
                        conn.execute(
                            "INSERT INTO wallet_addresses "
                            "(address, public_key, wallet_fingerprint, balance, "
                            " address_type, balance_at_height, balance_updated_at, "
                            " created_at, transaction_count) "
                            "VALUES (?,?,?,?,?,?,strftime('%s','now'),strftime('%s','now'),1) "
                            "ON CONFLICT(address) DO UPDATE SET "
                            " balance = balance + ?, "
                            " transaction_count = transaction_count + 1, "
                            " balance_at_height = ?, "
                            " balance_updated_at = strftime('%s','now')",
                            (
                                pr["recipient"],
                                pr["recipient"][:64],
                                pr["recipient"][:64],
                                pr["amount"],
                                "treasury",
                                height,
                                pr["amount"],
                                height,
                            ),
                        )
                        conn.execute(
                            "UPDATE pending_rewards SET status='confirmed', "
                            "confirmed_at_height=? WHERE id=?",
                            (height, pr["id"]),
                        )
                        logger.info(
                            f"[SUBMIT-BLOCK] 💰 Treasury reward confirmed: h={height - 1} "
                            f"→ {pr['recipient'][:20]}... +{pr['amount'] / 100:.2f} QTCL"
                        )
                except Exception as _pre:
                    logger.debug(f"[SUBMIT-BLOCK] prev-treasury confirm: {_pre}")

                # Settle non-coinbase transactions locally
                for tx in txs:
                    if str(tx.get("tx_type", "")).lower() == "coinbase":
                        continue
                    _from = str(tx.get("from_addr", tx.get("from_address", "")))
                    _to = str(tx.get("to_addr", tx.get("to_address", "")))
                    _amt = int(round(float(tx.get("amount", 0)) * 100))
                    _fee = int(round(float(tx.get("fee", 0)) * 100))
                    if _from and _to and _amt > 0:
                        conn.execute(
                            "UPDATE wallet_addresses SET "
                            " balance = balance - ?, "
                            " transaction_count = transaction_count + 1, "
                            " balance_at_height = ? "
                            "WHERE address=? AND balance >= ?",
                            (_amt + _fee, height, _from, _amt + _fee),
                        )
                        conn.execute(
                            "INSERT INTO wallet_addresses "
                            "(address, public_key, wallet_fingerprint, balance, "
                            " address_type, balance_at_height, balance_updated_at, "
                            " created_at, transaction_count) "
                            "VALUES (?,?,?,?,?,?,strftime('%s','now'),strftime('%s','now'),1) "
                            "ON CONFLICT(address) DO UPDATE SET "
                            " balance = balance + ?, "
                            " transaction_count = transaction_count + 1, "
                            " balance_at_height = ?, "
                            " balance_updated_at = strftime('%s','now')",
                            (
                                _to,
                                _to[:64],
                                _to[:64],
                                _amt,
                                "standard",
                                height,
                                _amt,
                                height,
                            ),
                        )

                conn.commit()
                local_persisted = True
                logger.info(
                    f"[SUBMIT-BLOCK] ✅ h={height} local mirror: miner +7.20 QTCL, "
                    f"treasury 0.80 QTCL queued (confirms at h={height + 1})"
                )
            finally:
                conn.close()
        except Exception as _le:
            logger.warning(f"[SUBMIT-BLOCK] local mirror failed: {_le}")

        # === 3. P2P gossip to peers ===
        self._gossip_to_peers("qtcl_submitBlock", [block])

        return {
            "accepted": koyeb_accepted or local_persisted,
            "koyeb_accepted": koyeb_accepted,
            "local_persisted": local_persisted,
            "height": height,
            "block_hash": block_hash,
            "miner_reward_qtcl": 7.2,
            "treasury_reward_qtcl_pending": 0.8,
            "treasury_confirms_at_height": height + 1,
            "koyeb_result": koyeb_result,
        }

    def _rpc_submitTransaction(self, params: list) -> dict:
        """Submit a signed transaction to both Koyeb (primary truth) and local mempool."""
        if not params or not isinstance(params[0], dict):
            return {"accepted": False, "error": "params[0] must be dict"}
        tx = params[0]
        tx_id = str(tx.get("tx_id") or tx.get("tx_hash", ""))
        _from = str(tx.get("from_addr", tx.get("from_address", "")))
        _to = str(tx.get("to_addr", tx.get("to_address", "")))
        _amt = float(tx.get("amount", 0))

        if not tx_id or not _from or not _to or _amt <= 0:
            return {"accepted": False, "error": "tx_id/from/to/amount required"}

        # Push to Koyeb first
        koyeb_result = None
        try:
            koyeb_result = self._fetch_server_rpc(
                "qtcl_submitTransaction", [tx], timeout=10.0
            )
        except Exception as _ke:
            logger.debug(f"[SUBMIT-TX] Koyeb push: {_ke}")
        koyeb_accepted = isinstance(koyeb_result, dict) and (
            koyeb_result.get("status") in ("accepted", "pending")
            or koyeb_result.get("accepted") is True
        )

        # Local mempool mirror
        local_persisted = False
        try:
            conn = self._db_conn()
            try:
                conn.execute(
                    "INSERT OR REPLACE INTO transactions "
                    "(tx_hash, from_address, to_address, amount, tx_type, "
                    " status, created_at) "
                    "VALUES (?,?,?,?,?,?,strftime('%s','now'))",
                    (
                        tx_id,
                        _from,
                        _to,
                        int(round(_amt * 100)),
                        str(tx.get("tx_type", "transfer")),
                        "pending",
                    ),
                )
                conn.commit()
                local_persisted = True
            finally:
                conn.close()
        except Exception as _le:
            logger.debug(f"[SUBMIT-TX] local mirror: {_le}")

        # Gossip
        self._gossip_to_peers("qtcl_submitTransaction", [tx])

        return {
            "accepted": koyeb_accepted or local_persisted,
            "koyeb_accepted": koyeb_accepted,
            "local_persisted": local_persisted,
            "tx_hash": tx_id,
            "koyeb_result": koyeb_result,
        }

    # ─────────────────────────────────────────────────────────────────────────
    # P2P gossip primitive (fire-and-forget to all known peers)
    # ─────────────────────────────────────────────────────────────────────────
    def _gossip_to_peers(self, method: str, params: list, max_peers: int = 6) -> None:
        """Fire-and-forget gossip to up to `max_peers` recent peers."""

        def _do():
            import urllib.request as _ur

            try:
                conn = self._db_conn()
                try:
                    cutoff = int(time.time()) - 300
                    rows = conn.execute(
                        "SELECT host, port FROM p2p_peers "
                        "WHERE last_seen_at>? "
                        "ORDER BY last_seen_at DESC LIMIT ?",
                        (cutoff, max_peers),
                    ).fetchall()
                finally:
                    conn.close()
                body = json.dumps(
                    {"jsonrpc": "2.0", "method": method, "params": params, "id": 1}
                ).encode()
                for r in rows:
                    try:
                        url = f"http://{r['host']}:{r['port']}/rpc"
                        req = _ur.Request(
                            url,
                            data=body,
                            headers={"Content-Type": "application/json"},
                            method="POST",
                        )
                        _ur.urlopen(req, timeout=2).read()
                    except Exception:
                        pass
            except Exception:
                pass

        threading.Thread(target=_do, daemon=True, name="Gossip").start()

    # ─────────────────────────────────────────────────────────────────────────
    # BALANCE RECONCILIATION DAEMON (Koyeb ↔ Local ↔ P2P)
    # ─────────────────────────────────────────────────────────────────────────
    def _reconcile_balances_loop(self) -> None:
        """Background daemon: reconcile local wallet balances with Koyeb every 60s.
        Logs discrepancies and tags divergent wallets."""
        while not self._stop.is_set():
            try:
                conn = self._db_conn()
                try:
                    rows = conn.execute(
                        "SELECT address, balance FROM wallet_addresses "
                        "ORDER BY balance_updated_at DESC LIMIT 32"
                    ).fetchall()
                finally:
                    conn.close()
                divergences = 0
                for row in rows:
                    addr = row["address"]
                    local_bal = int(row["balance"] or 0)
                    try:
                        koyeb = self._fetch_server_rpc(
                            "qtcl_getBalance", [addr], timeout=5.0
                        )
                        if isinstance(koyeb, dict) and "balance" in koyeb:
                            kbal = int(round(float(koyeb["balance"]) * 100))
                            if abs(kbal - local_bal) > 1:
                                divergences += 1
                                logger.warning(
                                    f"[RECONCILE] {addr[:20]}... local={local_bal / 100:.2f} "
                                    f"koyeb={kbal / 100:.2f} Δ={abs(kbal - local_bal) / 100:.2f} QTCL"
                                )
                                # Koyeb is primary truth → correct local
                                try:
                                    c2 = self._db_conn()
                                    try:
                                        c2.execute(
                                            "UPDATE wallet_addresses SET "
                                            " balance=?, "
                                            " balance_updated_at=strftime('%s','now') "
                                            "WHERE address=?",
                                            (kbal, addr),
                                        )
                                        c2.commit()
                                    finally:
                                        c2.close()
                                except Exception:
                                    pass
                    except Exception:
                        pass
                if divergences > 0:
                    logger.info(
                        f"[RECONCILE] corrected {divergences} divergent wallets from Koyeb"
                    )
            except Exception as _e:
                logger.debug(f"[RECONCILE] loop error: {_e}")
            self._stop.wait(60.0)

    def _dispatch(self, body_bytes: bytes, peer_addr: str) -> Tuple[dict, int]:
        t0 = time.time()
        try:
            body = json.loads(body_bytes)
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            return (
                {
                    "jsonrpc": "2.0",
                    "error": {"code": -32700, "message": f"Parse error: {e}"},
                    "id": None,
                },
                400,
            )

        if isinstance(body, list):
            responses = [self._dispatch_one(r, peer_addr, t0) for r in body]
            return (responses, 200)
        return (self._dispatch_one(body, peer_addr, t0), 200)

    def _dispatch_one(self, req: dict, peer_addr: str, t0: float) -> dict:
        if not isinstance(req, dict):
            return {
                "jsonrpc": "2.0",
                "error": {"code": -32600, "message": "Invalid Request"},
                "id": None,
            }
        rpc_id = req.get("id")
        method = req.get("method", "")
        params = req.get("params") or []
        if req.get("jsonrpc") != "2.0":
            return {
                "jsonrpc": "2.0",
                "error": {"code": -32600, "message": "Invalid jsonrpc"},
                "id": rpc_id,
            }
        handler = self._METHODS.get(method)
        if handler is None:
            return {
                "jsonrpc": "2.0",
                "error": {"code": -32601, "message": f"Method not found: {method}"},
                "id": rpc_id,
            }
        try:
            result = handler(self, params)
            ok = True
        except Exception as exc:
            logger.error(f"[MESH-RPC] {method} error: {exc}")
            ok = False
            result = None
        latency = (time.time() - t0) * 1000.0

        # Async audit log — non-blocking
        def _log_async(m=method, p=params, ok_=ok, lat=latency, pa=peer_addr):
            try:
                import sqlite3  # NodeRPCMeshServer scope

                c = sqlite3.connect(
                    str(self._db_path), timeout=5, check_same_thread=False
                )
                c.execute(
                    "INSERT INTO mesh_rpc_log "
                    "(method, params_hash, result_ok, latency_ms, peer_addr) "
                    "VALUES (?,?,?,?,?)",
                    (
                        m,
                        hashlib.sha256(json.dumps(p, default=str).encode()).hexdigest()[
                            :16
                        ],
                        1 if ok_ else 0,
                        lat,
                        pa,
                    ),
                )
                c.commit()
                c.close()
            except Exception:
                pass

        threading.Thread(target=_log_async, daemon=True).start()
        if not ok:
            return {
                "jsonrpc": "2.0",
                "error": {"code": -32603, "message": "Internal error"},
                "id": rpc_id,
            }
        return {"jsonrpc": "2.0", "result": result, "id": rpc_id}

    # ─────────────────────────────────────────────────────────────────────────
    # HTTP request handler (inner class)
    # ─────────────────────────────────────────────────────────────────────────
    def _make_handler(self):
        mesh = self

        class _Handler(BaseHTTPRequestHandler):
            server_version = f"QTCL-Mesh/{NodeRPCMeshServer.MESH_VERSION}"
            protocol_version = "HTTP/1.1"

            def log_message(self, fmt, *args):  # silence default access log
                pass

            def _send_json(self, body: Any, status: int = 200) -> None:
                data = json.dumps(body, default=str).encode()
                self.send_response(status)
                self.send_header("Content-Type", "application/json")
                self.send_header("Content-Length", str(len(data)))
                self.send_header("Access-Control-Allow-Origin", "*")
                self.send_header("X-QTCL-Node", mesh._node_id[:16])
                self.end_headers()
                self.wfile.write(data)

            def do_OPTIONS(self):
                self.send_response(204)
                self.send_header("Access-Control-Allow-Origin", "*")
                self.send_header("Access-Control-Allow-Methods", "POST, GET, OPTIONS")
                self.send_header("Access-Control-Allow-Headers", "Content-Type")
                self.end_headers()

            def do_GET(self):
                from urllib.parse import parse_qs

                path = self.path.split("?")[0]
                peer = self.client_address[0]
                if path in ("/health", "/"):
                    self._send_json(
                        {
                            "status": "ok",
                            "node": mesh._node_id[:16],
                            "version": mesh.MESH_VERSION,
                        }
                    )
                elif path == "/rpc":
                    # GET /rpc?method=<method>&params=<json-encoded-params>
                    try:
                        query_params = parse_qs(
                            self.path.split("?", 1)[1] if "?" in self.path else ""
                        )
                        method = query_params.get("method", [""])[0]
                        params_str = query_params.get("params", ["[]"])[0]
                        params = json.loads(params_str) if params_str else []
                        # Build JSON-RPC 2.0 request body from query params
                        body = json.dumps(
                            {
                                "jsonrpc": "2.0",
                                "method": method,
                                "params": params,
                                "id": 1,
                            }
                        ).encode()
                        result, status = mesh._dispatch(body, peer)
                        self._send_json(result, status)
                    except Exception as e:
                        logger.debug(f"[MESH] GET /rpc parse error: {e}")
                        self._send_json(
                            {"error": f"Invalid GET /rpc request: {e}"}, 400
                        )
                elif path == "/rpc/chain/status":
                    self._send_json(mesh._rpc_getChainStatus([]))
                elif path == "/rpc/oracle/pq0":
                    self._send_json(mesh._rpc_getOraclePq0([]))
                elif path == "/rpc/oracle/snapshot":
                    self._send_json(mesh._rpc_getQuantumMetrics([]))
                elif path == "/api/peers/list":
                    self._send_json(mesh._rpc_getPeers([]))
                elif path == "/api/chain/tip":
                    self._send_json(mesh._rpc_getBlockHeight([]))
                elif path.startswith("/api/block/"):
                    try:
                        h = int(path.split("/")[-1])
                        blk = mesh._rpc_getBlock([h])
                        self._send_json(blk or {}, 404 if not blk else 200)
                    except ValueError:
                        self._send_json({"error": "invalid height"}, 400)
                else:
                    self._send_json({"error": "not found"}, 404)

            def do_GET(self):
                from urllib.parse import parse_qs, urlparse

                path = self.path.split("?")[0]
                peer = self.client_address[0]
                try:
                    parsed = urlparse(self.path)
                    params = parse_qs(parsed.query)
                    data_str = params.get("data", [params.get("body", ["{}"])[0]])[0]
                    body = data_str.encode("utf-8") if data_str else b"{}"
                except Exception:
                    body = b"{}"
                if path == "/rpc":
                    result, status = mesh._dispatch(body, peer)
                    self._send_json(result, status)
                elif path == "/gossip":
                    # Accept gossip ingest — parse and forward
                    try:
                        ev = json.loads(body)
                        # Non-blocking: just log it
                        threading.Thread(
                            target=mesh._ingest_gossip, args=(ev,), daemon=True
                        ).start()
                        self._send_json({"ok": True})
                    except Exception as _e:
                        self._send_json({"error": str(_e)}, 400)
                elif path in ("/api/blocks/submit", "/api/transactions"):
                    try:
                        payload = json.loads(body)
                        if path.endswith("submit"):
                            result = mesh._rpc_submitBlock([payload])
                        else:
                            result = mesh._rpc_submitTransaction([payload])
                        self._send_json(result)
                    except Exception as _e:
                        self._send_json({"error": str(_e)}, 400)
                else:
                    self._send_json({"error": "not found"}, 404)

        return _Handler

    def _ingest_gossip(self, event: dict) -> None:
        """Persist inbound gossip event to gossip_inventory."""
        try:
            import sqlite3  # NodeRPCMeshServer scope

            conn = sqlite3.connect(
                str(self._db_path), timeout=5, check_same_thread=False
            )
            conn.execute(
                "INSERT INTO gossip_inventory "
                "(event_type, channel, peer_id, payload) VALUES (?,?,?,?)",
                (
                    str(event.get("event_type", "unknown")),
                    str(event.get("channel", "p2p")),
                    str(event.get("origin", "")),
                    json.dumps(event, default=str)[:4096],
                ),
            )
            conn.commit()
            conn.close()
        except Exception as _e:
            logger.debug(f"[MESH-GOSSIP] ingest failed: {_e}")

    # ─────────────────────────────────────────────────────────────────────────
    # Lifecycle
    # ─────────────────────────────────────────────────────────────────────────
    def start(self) -> None:
        self._start_ts = time.time()
        # Oracle entanglement poller
        threading.Thread(
            target=self._poll_oracle_and_entangle,
            daemon=True,
            name="Mesh-PQ0-Entangle",
        ).start()
        # Balance reconciliation daemon (Koyeb ↔ Local ↔ P2P)
        threading.Thread(
            target=self._reconcile_balances_loop,
            daemon=True,
            name="Mesh-Reconcile",
        ).start()
        # HTTP server
        handler = self._make_handler()
        try:
            self._http_server = ThreadingHTTPServer(
                (MESH_HOST if "MESH_HOST" in dir() else "0.0.0.0", self._port),
                handler,
            )
            self._http_server.daemon_threads = True
            threading.Thread(
                target=self._http_server.serve_forever,
                daemon=True,
                name="Mesh-HTTP",
            ).start()
            logger.info(
                f"[MESH] 🌐 RPC mesh node live  "
                f"http://0.0.0.0:{self._port}/rpc  "
                f"node={self._node_id[:16]}…"
            )
        except OSError as _ose:
            logger.error(f"[MESH] ❌ Could not bind port {self._port}: {_ose}")

    def stop(self) -> None:
        self._stop.set()
        if self._http_server:
            self._http_server.shutdown()
            logger.info("[MESH] 🛑 RPC mesh node stopped")


# Register all RPC methods on the class after definition
NodeRPCMeshServer._METHODS = {
    "qtcl_getBlockHeight": NodeRPCMeshServer._rpc_getBlockHeight,
    "qtcl_getBestBlockHash": NodeRPCMeshServer._rpc_getBestBlockHash,
    "qtcl_getBlock": NodeRPCMeshServer._rpc_getBlock,
    "qtcl_getBlockRange": NodeRPCMeshServer._rpc_getBlockRange,
    "qtcl_getChainStatus": NodeRPCMeshServer._rpc_getChainStatus,
    "qtcl_getQuantumMetrics": NodeRPCMeshServer._rpc_getQuantumMetrics,
    "qtcl_getOraclePq0": NodeRPCMeshServer._rpc_getOraclePq0,
    "qtcl_getPq0Matrix": NodeRPCMeshServer._rpc_getPq0Matrix,
    "qtcl_getConsensusSnapshot": NodeRPCMeshServer._rpc_getConsensusSnapshot,
    "qtcl_getPeers": NodeRPCMeshServer._rpc_getPeers,
    "qtcl_getWalletBalance": NodeRPCMeshServer._rpc_getWalletBalance,
    "qtcl_getBalance": NodeRPCMeshServer._rpc_getWalletBalance,
    "qtcl_getMempoolInfo": NodeRPCMeshServer._rpc_getMempoolInfo,
    "qtcl_syncStatus": NodeRPCMeshServer._rpc_getSyncStatus,
    "qtcl_nodeInfo": NodeRPCMeshServer._rpc_nodeInfo,
    "qtcl_getEntropy": NodeRPCMeshServer._rpc_getEntropy,
    "qtcl_getDHTTable": NodeRPCMeshServer._rpc_getDHTTable,
    "qtcl_receiveDHTTable": NodeRPCMeshServer._rpc_receiveDHTTable,
    "qtcl_peerHeartbeat": NodeRPCMeshServer._rpc_peerHeartbeat,
    "qtcl_submitBlock": NodeRPCMeshServer._rpc_submitBlock,
    "qtcl_submitTransaction": NodeRPCMeshServer._rpc_submitTransaction,
}

_MESH_SERVER_INSTANCE: Optional["NodeRPCMeshServer"] = None
_MESH_SERVER_LOCK = threading.Lock()


def _start_mesh_rpc_node(
    db_path: Path, main_server_url: str, port: int = 9091
) -> "NodeRPCMeshServer":
    """
    Idempotent: start the RPC mesh node exactly once per process.
    Returns the running NodeRPCMeshServer instance.
    Called from main() after DB init — non-blocking daemon threads only.
    """
    global _MESH_SERVER_INSTANCE
    with _MESH_SERVER_LOCK:
        if _MESH_SERVER_INSTANCE is not None:
            return _MESH_SERVER_INSTANCE
        node = NodeRPCMeshServer(
            db_path=db_path,
            main_server_url=main_server_url,
            port=port,
        )
        node.start()
        _MESH_SERVER_INSTANCE = node
    return node


def main() -> None:  # noqa: F811
    """
    QTCL Client entrypoint.
    --node-type server|miner|oracle  → delegates to original QtclNode subclass.
    Default                          → Welcome screen (QtclClientApp).
    """
    # ✅ Initialize client-side Pyth oracle + RPC server
    # ServerRPCClient embedded in client
    # No client RPC server needed - use server RPC
    # Delegating to server RPC
    # Delegating to server RPC - no local RPC needed, flush=True)
    import argparse as _ap

    p = _ap.ArgumentParser(description="QTCL Client — W-State Entangled Blockchain")
    p.add_argument("--oracle-url", default=None)
    p.add_argument("--mine", action="store_true")
    p.add_argument("--transact", action="store_true")
    p.add_argument("--wallet", action="store_true")
    p.add_argument(
        "--oracle-audit",
        action="store_true",
        help="Oracle audit panel — live server state + full hashes",
    )
    p.add_argument(
        "--market",
        action="store_true",
        help="Market Explorer — Pyth × HypΓ oracle-signed live prices",
    )
    p.add_argument("--node-type", default=None, choices=["server", "miner", "oracle"])
    p.add_argument(
        "--node",
        action="store_true",
        help="Run as a pure QTCL relay node: P2P gossip + oracle "
        "forwarding + mesh W-state participation, no mining",
    )
    p.add_argument(
        "--log-level", default="WARNING", choices=["DEBUG", "INFO", "WARNING", "ERROR"]
    )
    args, _ = p.parse_known_args()
    _logging.basicConfig(
        level=getattr(_logging, args.log_level),
        format="[%(asctime)s] %(levelname)s  %(name)s: %(message)s",
    )
    if args.node_type:
        try:
            _cls_map = {
                "server": QtclServer,  # type: ignore[name-defined]
                "miner": QtclMiner,  # type: ignore[name-defined]
                "oracle": QtclOracle,
            }  # type: ignore[name-defined]
            node = _cls_map[args.node_type](config_path=None)
            node.start()
            node.run_forever()  # type: ignore[attr-defined]
        except KeyboardInterrupt:
            try:
                node.stop()  # type: ignore[name-defined]
            except Exception:
                pass
        return
    try:
        print("⚛️  QTCL Client initializing...", flush=True)

        # ── Ensure data directory exists (uses canonical _DATA_DIR and _DB_PATH) ─
        print(f"  ✅ Data directory ready: {_DATA_DIR}", flush=True)

        # ── Proactive schema migration: tables + columns ──────────────────────
        # Always runs create_tables() AND _ensure_blocks_schema() regardless of
        # whether the DB is brand-new or a years-old on-disk file.  Both methods
        # are idempotent — CREATE TABLE IF NOT EXISTS + ALTER TABLE ADD COLUMN
        # guarded by PRAGMA table_info.  This is the only reliable way to repair
        # an existing DB whose blocks table was created without merkle_root /
        # tx_count / synced_from_server (the root cause of IBD insert failures).
        try:
            _boot_db = LocalBlockchainDB(name="qtcl")
            # Full table creation pass (idempotent)
            _boot_db.create_tables()
            # Full column migration pass (idempotent, repairs any existing table)
            _boot_db._ensure_blocks_schema()
            # Report
            _boot_cur = _boot_db.conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name"
            )
            _boot_tables = {r[0] for r in _boot_cur.fetchall()}
            _col_cur = _boot_db.conn.execute("PRAGMA table_info(blocks)")
            _live_cols = {row[1] for row in _col_cur.fetchall()}
            # Check for columns from qtcl_db_builder.py schema
            _required_cols = {
                "block_hash",
                "parent_hash",
                "height",
                "timestamp",
                "merkle_root",
                "tx_count",
            }
            _col_missing = _required_cols - _live_cols
            if _col_missing:
                print(
                    f"  ❌ FATAL: blocks table missing critical columns: {_col_missing}",
                    flush=True,
                )
                print(
                    f"  Schema validation FAILED. Database is corrupted or incompatible.",
                    flush=True,
                )
                sys.exit(1)
            else:
                print(
                    f"  ✅ DB schema OK — {len(_boot_tables)} tables, "
                    f"all required columns present",
                    flush=True,
                )
            _boot_db.conn.close()
        except Exception as _dbe:
            print(
                f"  ⚠️  DB schema check failed: {_dbe} — will retry on first use",
                flush=True,
            )

        # ── Initialize P2P bootstrap peers (no localhost) ────────────────────
        init_p2p_bootstrap()

        url = args.oracle_url or ENTROPY_SERVER_URL
        # ── Wallet existence check (skip for oracle-audit mode) ───────────────
        from pathlib import Path as _PathLib

        _wallet_file = _PathLib.home() / "qtcl-miner" / "data" / "wallet.json"
        _is_oracle_audit = getattr(args, "oracle_audit", False)
        if not _wallet_file.exists() and not _is_oracle_audit:
            print()
            print("  ┌──────────────────────────────────────────────────────────┐")
            print("  │  🔑  Wallet Setup                                        │")
            print("  │                                                          │")
            print("  │  No wallet file found.                                   │")
            print("  │  Create a new QTCL wallet? (Required for all modes)      │")
            print("  └──────────────────────────────────────────────────────────┘")
            # Suppress logging during input to prevent prompt injection
            import contextlib

            _orig_level = logger.level
            try:
                logger.setLevel(logging.CRITICAL)
                _create_wallet_ans = input("  Create wallet? [Y/n]: ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                _create_wallet_ans = "y"
            finally:
                logger.setLevel(_orig_level)

            if _create_wallet_ans != "n":
                print()
                try:
                    _new_pw = _silent_getpass("  New wallet password: ").strip()
                    _new_pw2 = _silent_getpass("  Confirm password   : ").strip()
                    if _new_pw != _new_pw2:
                        print("  ❌ Passwords don't match — using defaults")
                        _new_pw = "default_qtcl_password"
                    elif not _new_pw:
                        print("  ⚠  Empty password — using defaults")
                        _new_pw = "default_qtcl_password"

                    _tmp_create_wallet = HypGammaWallet()
                    _new_addr = _tmp_create_wallet.create(_new_pw)
                    print(f"  ✅ Wallet created: {_new_addr}")
                    _new_pw = "0" * len(_new_pw)
                except (EOFError, KeyboardInterrupt):
                    print("  ⚠  Wallet creation skipped — continuing as guest")
                except Exception as _cwe:
                    print(f"  ❌ Wallet creation error: {_cwe} — continuing as guest")
        # ── Oracle mode prompt (skip for --oracle-audit) ──────────────────────
        oracle_context = None
        if _is_oracle_audit:
            print(
                "  👻 Oracle-audit mode: skipping wallet prompts (read-only panel)",
                flush=True,
            )
        else:
            print()
            print("  ┌──────────────────────────────────────────────────────────┐")
            print("  │  🔮  Oracle Signing Mode  (optional)                     │")
            print("  │                                                          │")
            print("  │  Run as a registered signing oracle?                     │")
            print("  │  Your price attestations will be HypΓ-signed and         │")
            print("  │  cryptographically bound to your QTCL wallet address.    │")
            print("  │  This requires your wallet password.                     │")
            print("  │                                                          │")
            print("  │  Skip (N) = mine/transact normally, anonymous signing.   │")
            print("  └──────────────────────────────────────────────────────────┘")
            # Suppress logging during input to prevent prompt injection
            import contextlib

            _orig_level = logger.level
            try:
                logger.setLevel(logging.CRITICAL)
                _oracle_ans = input("  Register as oracle? [y/N]: ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                _oracle_ans = "n"
            finally:
                logger.setLevel(_orig_level)
            if _oracle_ans == "y":
                print()
                _tmp_wallet = HypGammaWallet()
                try:
                    _pw_oi = _silent_getpass("  Wallet password: ")
                    if _tmp_wallet.load(_pw_oi):
                        oracle_context = {
                            "wallet_addr": _tmp_wallet.address,
                            "wallet_priv": _tmp_wallet.private_key,
                            "wallet_pub": _tmp_wallet.public_key,
                        }
                        print(f"  ✅ Oracle bound to wallet: {_tmp_wallet.address}")
                        _pw_oi = "0" * len(_pw_oi)
                        del _pw_oi
                    else:
                        print("  ❌ Wallet load failed — running anonymous oracle")
                except (EOFError, KeyboardInterrupt):
                    print("  ⚠  Skipped — running anonymous oracle")
                except Exception as _oe:
                    print(f"  ❌ Wallet error ({_oe}) — running anonymous oracle")
            else:
                print("  👻 Running anonymous oracle (no wallet binding)")
        print()
        app = QtclClientApp(oracle_url=url, oracle_context=oracle_context)
        # (Moved here after interactive prompts to prevent log injection during password input)
        import sqlite3 as _rpc_sq3

        try:
            _rpc_db = _rpc_sq3.connect(
                str(_DB_PATH), timeout=5.0, check_same_thread=False
            )
            _rpc_client = ServerRPCClient(db_connection=_rpc_db)
            logger.info(
                f"[RPC] ✅ Dual-mode RPC initialized (HTTP + P2P gossip fallback)"
            )
            # Make available globally for mining/oracle modes
            globals()["_SERVER_RPC"] = _rpc_client
        except Exception as _rpc_err:
            logger.warning(f"[RPC] ⚠️  Could not initialize dual-mode RPC: {_rpc_err}")

        # ── RPC Mesh Node (port 9091) — skip for oracle-audit ─────────────────
        # Full JSON-RPC 2.0 node serving local SQLite mirror of the main Lattice.
        # pq0 tripartite entanglement chain links this node to the 5-oracle quorum.
        if not _is_oracle_audit:
            try:
                _mesh_port = int(_os.environ.get("MESH_PORT", "9091"))
                _mesh_srv = _start_mesh_rpc_node(
                    db_path=_DB_PATH,
                    main_server_url=_os.environ.get(
                        "ENTROPY_SERVER", "https://qtcl-blockchain.koyeb.app"
                    ),
                    port=_mesh_port,
                )
                globals()["_MESH_SERVER"] = _mesh_srv
                logger.info(
                    f"[MESH] ✅ RPC mesh node started on port {_mesh_port} — "
                    f"pq0 tripartite entanglement active"
                )
            except Exception as _mesh_err:
                logger.warning(f"[MESH] ⚠️  Mesh node startup failed: {_mesh_err}")
        else:
            logger.info(
                "[ORACLE-AUDIT] Skipping mesh node (port 9091 reserved for P2P)"
            )

        # ── SSE Stream Receivers ─────────────────────────────────────────────
        # Start background threads to receive real-time density and block streams
        _sse_density_handlers: List[Callable[[dict], None]] = []
        _sse_block_handlers: List[Callable[[dict], None]] = []

        def _default_density_handler(data: dict) -> None:
            """Default handler for density stream - stores to global for reference."""
            dm_hex = data.get("density_tensor_hex", "") or data.get(
                "density_matrix_hex", ""
            )
            ts = data.get("timestamp_ns", 0) or data.get("timestamp", 0)
            if dm_hex:
                logger.debug(f"[SSE-RECV] Density snapshot received (ts={ts})")
            # Store in global for other components to access
            globals()["_LATEST_DENSITY_SNAPSHOT"] = data

        def _default_block_handler(data: dict) -> None:
            """Default handler for block stream - logs new blocks."""
            height = data.get("height", 0) or data.get("block_height", 0)
            block_hash = data.get("hash", "") or data.get("block_hash", "")
            if height:
                logger.info(
                    f"[SSE-RECV] New block received: height={height}, hash={block_hash[:16]}..."
                )
            # Store in global for other components to access
            globals()["_LATEST_BLOCK_EVENT"] = data

        # Register default handlers
        _sse_density_handlers.append(_default_density_handler)
        _sse_block_handlers.append(_default_block_handler)

        # Start SSE streams (only in non-audit modes to avoid cluttering logs)
        if not _is_oracle_audit:
            try:
                _density_thread = connect_density_stream(url, _default_density_handler)
                globals()["_SSE_DENSITY_THREAD"] = _density_thread
            except Exception as _sse_err:
                logger.debug(f"[SSE] Density stream init failed: {_sse_err}")

            try:
                _block_thread = connect_block_stream(url, _default_block_handler)
                globals()["_SSE_BLOCK_THREAD"] = _block_thread
            except Exception as _sse_err:
                logger.debug(f"[SSE] Block stream init failed: {_sse_err}")

        # Make handler registration available globally
        globals()["_SSE_DENSITY_HANDLERS"] = _sse_density_handlers
        globals()["_SSE_BLOCK_HANDLERS"] = _sse_block_handlers

        def register_density_handler(handler: Callable[[dict], None]) -> None:
            """Register an additional handler for density stream events."""
            _sse_density_handlers.append(handler)

        def register_block_handler(handler: Callable[[dict], None]) -> None:
            """Register an additional handler for block stream events."""
            _sse_block_handlers.append(handler)

        globals()["register_density_handler"] = register_density_handler
        globals()["register_block_handler"] = register_block_handler

        print("✅ Ready for input", flush=True)
    except Exception as e:
        print(f"❌ Initialization error: {e}")
        return
    if args.mine:
        app.run_mine_mode()
    elif args.transact:
        app.run_transact_mode()
    elif args.wallet:
        app.run_wallet_mode()
    elif getattr(args, "market", False):
        app.run_market_explorer()
    elif getattr(args, "oracle_audit", False):
        app.run_oracle_mode()
    elif getattr(args, "node", False):
        app.run_node_mode()
    else:
        app.run()


if __name__ == "__main__":
    main()
